export const SPOTS = [
  {name:"Champion Malasadas",tier:"A",lat:21.3937,lng:-157.744,category:"bakery",subcategory:"malasada-shop",tagline:"Kailua's neighborhood malasada spot — lighter and less greasy than the famous ones, with perfect sugar coating.",area:"Kailua",price:"$",mustOrder:["plain malasada","haupia filled","custard filled"],parking:"Free lot at shopping center",talkStory:"While Leonard's gets all the fame, Windward side locals swear by Champion Malasadas in Kailua. The malasadas here are lighter and less greasy, with a perfect sugar coating. The haupia-filled and custard-filled versions are excellent. Located in a small shopping center, it's a true neighborhood spot where you'll see locals grabbing a box on the way home. Freshest in the morning.",cashOnly:false,kamaaina:null},
  {name:"Nisshodo Candy Store",tier:"S",lat:21.326,lng:-157.865,category:"bakery",subcategory:"mochi-shop",tagline:"Handmade Japanese mochi and manju since the 1920s — hidden in an industrial warehouse, sold out by noon.",area:"Kalihi",price:"$",mustOrder:["chichi dango","mochi","manju"],parking:"Free lot on Dillingham Blvd",talkStory:"Hidden in an industrial warehouse on Dillingham Boulevard, Nisshodo has been making traditional Japanese mochi and manju by hand since the 1920s. The chichi dango (soft, chewy rice flour confection dusted in potato starch) is the signature — locals buy it by the box for family gatherings. Everything is made fresh daily in small batches. Arrive between 7-9am for the freshest selection; popular items sell out after noon. Closed Sundays.",cashOnly:true,kamaaina:null},
  {name:"Pipeline Bakeshop & Creamery",tier:"A",lat:21.28,lng:-157.781,category:"bakery",subcategory:"malasada-shop",tagline:"Kaimuki's cult-favorite bakery — the 'Malamode' (malasada + ice cream) and Cake Bombs are modern Hawaii classics.",area:"Kaimuki",price:"$",mustOrder:["Malamode (ube or haupia)","Cake Bombs","fresh malasadas"],parking:"Street parking on Waialae Ave",talkStory:"A Kaimuki bakery with a cult following for its freshly made malasadas and the signature Malamode — a malasada split open and filled with house-made ice cream in flavors like ube, haupia, and Kona coffee. The Cake Bombs (miniature layered cakes) are another local obsession. Arrive early because popular items sell out by midday. This is the modern evolution of Hawaii's malasada tradition.",cashOnly:false,kamaaina:null},
  {name:"Via Gelato",tier:"B",lat:21.2725,lng:-157.809,category:"bakery",subcategory:"gelato",tagline:"Hawaii's best gelato — Italian technique with local flavors like haupia, ube, and lilikoi in a Kapahulu neighborhood shop.",area:"Kapahulu / Diamond Head",price:"$",mustOrder:["haupia gelato","ube gelato","lilikoi sorbetto"],parking:"Street parking on Kapahulu Ave",talkStory:"This small Kapahulu gelato shop uses authentic Italian technique with local Hawaiian ingredients to create some of the best frozen treats on the island. The haupia (coconut pudding) and ube flavors are incredible, and the lilikoi sorbetto is refreshingly tart. Everything is made in-house daily. Locals bring their kids after dinner at nearby restaurants. The flavor selection rotates, so there's always something new to try.",cashOnly:false,kamaaina:null},
  {name:"Ala Moana Beach Park",tier:"A",lat:21.2886,lng:-157.8453,category:"beach",subcategory:"kid-friendly",tagline:"The locals' beach in the heart of Honolulu — Magic Island Lagoon is toddler paradise.",area:"Honolulu",price:"Free",parking:"Large free parking lot (fills weekends by 10am)",hours:"Open daily, 4:00 AM – 10:00 PM",bestTime:"Weekday mornings for space; sunset at Magic Island for golden light",kidFriendly:true,talkStory:"Magic Island east end has calm, shallow water perfect for toddlers. Shaded picnic areas fill fast on weekends — claim one early. Combine with a walk to the Ala Moana Bowls surf break viewpoint on the peninsula tip.",kamaaina:null},
  {name:"Bellows Beach",tier:"A",lat:21.3566,lng:-157.7096,category:"beach",subcategory:"hidden",tagline:"On a military base, open weekends only — the trade-off is some of the most untouched white sand on the island.",area:"Waimanalo",price:"Free",parking:"Free lot inside the base gate",hours:"Fri noon – Sun midnight only",bestTime:"Saturday morning for the full day; arrive by 9am for best spot",kidFriendly:true,talkStory:"BBQ grills and camping with permit — one of the best beach camping spots on Oahu. Gentle shore break great for beginner bodyboarding. The ironwood tree line gives natural shade. Combine with a Waimanalo shave ice run on the way out.",kamaaina:null},
  {name:"Diamond Head Beach",tier:"B",lat:21.2555,lng:-157.8055,category:"beach",subcategory:"bodyboard",tagline:"A hidden stretch below the lighthouse cliffs that locals use for bodyboarding, tidepooling, and escaping the Waikiki scene.",area:"East Honolulu",price:"Free",parking:"Street parking along Diamond Head Rd near the lighthouse; walk down the cliffside trail",hours:"Open daily, sunrise to sunset",bestTime:"South swell season (summer) for surf; morning for tidepools",kidFriendly:false,talkStory:"Getting here requires a short but steep walk down from the road — which is exactly why it stays uncrowded. The bodyboarding here is legit during south swells. There are cool tide pools along the rocky edges at low tide. Not a sandy lounge-around beach; more of an adventure spot. Combine with the Diamond Head hike for a full morning. Bring water shoes — the entry is rocky.",kamaaina:null},
  {name:"Ehukai Beach (Banzai Pipeline)",tier:"A",lat:21.6653,lng:-158.0473,category:"beach",subcategory:"surfing",tagline:"Pipeline is the most famous wave on Earth — watching from the sand puts you closer to the action than any surf comp broadcast.",area:"North Shore",price:"Free",parking:"Tiny lot at Ehukai Beach Park or street parking on Ke Nui Rd; come early in winter",hours:"Open daily, sunrise to sunset",bestTime:"Dec–Feb for massive Pipeline surf; summer is calm enough for swimming",kidFriendly:false,talkStory:"In winter you can sit on the sand and feel the ground shake when the big sets break — it's that close. Pipeline breaks over a shallow reef, so this is watch-only for 99% of people. During the Pipe Masters in December, the beach is packed but the energy is unreal. In summer, the same spot becomes a mellow beach. The access path is between houses off Ke Nui Rd — look for the blue sign.",kamaaina:null},
  {name:"Electric Beach (Kahe Point)",tier:"B",lat:21.3547,lng:-158.1311,category:"beach",subcategory:"snorkeling",tagline:"Warm water from the power plant outflow attracts spinner dolphins, sea turtles, and tropical fish in ridiculous abundance.",area:"West Side",price:"Free",parking:"Small gravel lot right off Farrington Hwy; comes and goes quickly",hours:"Open daily, sunrise to sunset",bestTime:"Early morning for dolphins and calm water; weekdays to avoid crowds",kidFriendly:false,talkStory:"The power plant next door pumps warm water into the ocean, creating this wild ecosystem right off shore. Spinner dolphins cruise through here regularly — you can see them from shore. Snorkeling is best on the left side near the outflow pipe. Currents can be strong so this isn't for beginners. Bring your own gear; there are no rentals nearby. One of the most unique ocean experiences on Oahu.",kamaaina:null},
  {name:"Ewa Beach",tier:"C",lat:21.3132,lng:-158.0076,category:"beach",subcategory:"kid-friendly",tagline:"A mellow neighborhood beach where local families set up camp all weekend — no tourists, no fuss.",area:"Ewa",price:"Free",parking:"Street parking in the Ewa Beach neighborhood; free but limited",hours:"Open daily, sunrise to sunset",bestTime:"Morning for calm water; weekdays for peace and quiet",kidFriendly:true,talkStory:"This is the definition of a neighborhood beach — families with canopies, coolers of food, and kids running around all day. The water is shallow and calm, which is why the keiki love it. Not the prettiest sand on the island, but the vibe is authentic local lifestyle. Hit up the nearby L&L or Rainbow Drive-In for a plate lunch after. If you're staying in the Ko Olina area, this is a quick side trip.",kamaaina:null},
  {name:"Fort DeRussy Beach Park",tier:"B",lat:21.2822,lng:-157.8365,category:"beach",subcategory:"swimming",tagline:"Waikiki's widest, least-crowded beach — BBQ grills, calm water, and actual space to put your towel down.",area:"Waikiki",price:"Free",parking:"Paid lot off Kalia Rd ($4/hr); street parking on Saratoga Rd if you're lucky",hours:"5am–10pm daily",bestTime:"Weekday mornings for a near-private beach experience; weekends for BBQ vibes",kidFriendly:true,talkStory:"Fort DeRussy is the beach locals send you to when you say you want to go to Waikiki but hate crowds. It's a 71-acre military park that's almost entirely open to the public. The beach here is wider than the main Waikiki strip and the water is just as calm. There are BBQ grills and picnic tables in the park — one of the only spots in Waikiki where you can actually grill. The U.S. Army Museum inside the old battery is free and worth a quick walk-through. Workout stations along the path if you're that type. The Hale Koa Hotel next door is military-only, but the beach and park are for everyone.",kamaaina:null},
  {name:"Haleiwa Beach Park",tier:"B",lat:21.5963,lng:-158.1052,category:"beach",subcategory:"kid-friendly",tagline:"A laid-back local park where families picnic, keiki play in calm water, and the North Shore vibe is at its most relaxed.",area:"North Shore",price:"Free",parking:"Large free lot right at the park — rarely fills up",hours:"Open daily, 6:00 AM – 10:00 PM",bestTime:"Year-round; calmer in summer but the protected harbor side stays mellow even in winter",kidFriendly:true,talkStory:"This is the beach locals actually bring their families to on the North Shore — no crowds, big shade trees, and the water near the harbor is protected and calm. Restrooms, showers, and a big grassy area for the kids to run around. Walk to Haleiwa town for Matsumoto's shave ice or Aoki's for poke after. Way more chill than the famous surf beaches up the road.",kamaaina:null},
  {name:"Hanauma Bay",tier:"S",lat:21.269,lng:-157.6937,category:"beach",subcategory:"snorkeling",tagline:"A protected marine sanctuary inside a volcanic crater — the snorkeling is like swimming in an aquarium.",area:"East Honolulu",price:"$25 non-resident, $5 kama'aina; closed Mondays and Tuesdays",parking:"$3 parking; lot fills by 9 AM, arrive early or take the shuttle",hours:"Wed–Sun, 6:45 AM – 4:00 PM (gates close at 1:30 PM for last entry)",bestTime:"Arrive at 6:30 AM for first entry; Wed or Thu for fewest crowds",kidFriendly:true,talkStory:"You have to watch a short conservation video before entering, which honestly is worth it — it helps you understand what you're swimming with. The inner reef is shallow and calm, perfect for first-time snorkelers and kids. Bring your own gear to skip the overpriced rental line. Go early and leave by 11 AM before the afternoon crowds and wind pick up. The fish here are so used to people they'll swim right up to you.",kamaaina:"$5 entry for Hawaii residents with valid ID"},
  {name:"Kahana Bay",tier:"B",lat:21.5493,lng:-157.8782,category:"beach",subcategory:"hidden",tagline:"A quiet crescent of sand tucked into a lush valley — the kind of spot most tourists drive right past.",area:"Windward",price:"Free",parking:"Small lot off Kamehameha Hwy with additional roadside parking",hours:"Open daily, 7:00 AM – 6:45 PM",bestTime:"Weekday mornings for near-total solitude; spring and summer for calmer water",kidFriendly:true,talkStory:"This is one of the most underrated beaches on the island. The bay is shallow and protected, the mountains wrap around you, and there's hardly anyone here on weekdays. It connects to the Kahana Valley hiking trail if you want to stretch your legs. Locals fish here in the evenings — it's that kind of mellow spot. No frills, just pure windward beauty.",kamaaina:null},
  {name:"Kailua Beach Park",tier:"S",lat:21.3976,lng:-157.7271,category:"beach",subcategory:"swimming",tagline:"The beach Honolulu locals make the drive for — powder-white sand, gentle clear water, views of the Mokes.",area:"Kailua",price:"Free",parking:"3 free lots — arrive before 9am on weekends",hours:"Open daily, 5:00 AM – 10:00 PM",bestTime:"Arrive before 9am weekends; weekday mornings are uncrowded",kidFriendly:true,talkStory:"Rent kayaks to paddle to the Mokulua Islands (Na Mokulua) — land on Moku Nui's hidden beach. The section near Kalama Beach Park is less crowded than the main park. Wind picks up after noon most days, great for kite sports but choppy for swimming.",kamaaina:null},
  {name:"Kalama Beach Park",tier:"B",lat:21.3975,lng:-157.7381,category:"beach",subcategory:"kid-friendly",tagline:"Kailua's neighborhood beach park — where locals actually go while tourists crowd Kailua Beach down the road.",area:"Kailua",price:"Free",parking:"Free lot on N Kalaheo Ave; easier to find a spot than Kailua Beach Park",hours:"Open daily, sunrise to sunset",bestTime:"Morning for SUP and kayaking; afternoon for the breeze and kite-watching",kidFriendly:true,talkStory:"This is the locals' alternative to Kailua Beach — same gorgeous water, way fewer people. The park has a big grassy area, picnic tables, and is a prime spot for kiteboarding and windsurfing, so even if you're not in the water there's a show. Buzz's Steakhouse is a two-minute walk for a legendary lanai lunch. The water is shallow and sandy — great for keiki.",kamaaina:null},
  {name:"Kawela Bay",tier:"B",lat:21.697,lng:-157.9965,category:"beach",subcategory:"hidden",tagline:"A secluded crescent bay past Turtle Bay Resort that feels like you stepped into a postcard from old Hawaii.",area:"North Shore",price:"Free",parking:"Park at the public access lot near Turtle Bay Resort; 10-minute walk along the shoreline trail",hours:"Open daily, sunrise to sunset",bestTime:"Mornings for calm water; summer for swimming, winter for dramatic scenery",kidFriendly:true,talkStory:"Most people turn around at Turtle Bay Resort and never discover Kawela Bay just past it. The walk along the coastal trail is beautiful, and when you arrive you'll likely have the beach nearly to yourself. The bay is protected by a reef so the water stays relatively calm. Ironwood trees provide shade right on the sand. This was a filming location for LOST and several movies — you'll see why.",kamaaina:null},
  {name:"Ko Olina Lagoon 4",tier:"B",lat:21.3283,lng:-158.122,category:"beach",subcategory:"kid-friendly",tagline:"Calm as a bathtub year-round — the best lagoon for families with babies and toddlers.",area:"Ko Olina",price:"Free",parking:"Most public parking of the 4 lagoons — free lot",hours:"Open 24 hours (public beach access)",bestTime:"Arrive by 8am weekends to guarantee parking; weekdays are easy",kidFriendly:true,talkStory:"Lagoon 4 is the least crowded of the four — resort guests cluster at Lagoons 1-3. Bring your own snorkel gear; turtles sometimes swim into the lagoons. All four lagoons are public (ignore any resort signage suggesting otherwise). Combine with dinner at Monkeypod Kitchen nearby.",kamaaina:null},
  {name:"Kualoa Beach Park",tier:"A",lat:21.5137,lng:-157.8378,category:"beach",subcategory:"kid-friendly",tagline:"Chinaman's Hat sits right offshore, the Ko'olau mountains tower behind you — this might be the most scenic beach on the island.",area:"Windward",price:"Free",parking:"Large free lot right at the park",hours:"Open daily, 7:00 AM – 8:00 PM",bestTime:"Morning for best light on the mountains; weekdays to avoid crowds",kidFriendly:true,talkStory:"The view here is unreal — Mokolii (Chinaman's Hat) island is right there and you can actually kayak or wade to it at low tide if you're adventurous. The water is shallow and calm, perfect for little ones. This is right next to Kualoa Ranch so you can combo a beach day with an ATV tour or movie site visit. Bring a tent or pop-up — not a lot of natural shade near the water.",kamaaina:null},
  {name:"Kuilima Cove",tier:"B",lat:21.7075,lng:-157.992,category:"beach",subcategory:"snorkeling",tagline:"A tiny protected cove at Turtle Bay with beginner-friendly snorkeling and green sea turtles just offshore.",area:"North Shore",price:"Free",parking:"Use the Turtle Bay Resort public beach access parking; free but can fill on weekends",hours:"Open daily, sunrise to sunset",bestTime:"Morning for clearest water and turtle sightings; summer for calmest conditions",kidFriendly:true,talkStory:"This little cove is protected by rocks on both sides, so it stays calm when the rest of the North Shore is pounding. Perfect for kids and beginner snorkelers — you'll see reef fish and very likely turtles. It's right next to Turtle Bay Resort but it's a public beach, so don't let the resort vibe intimidate you. Small beach so it can feel crowded with just a few families. Grab fish tacos at the resort's Surfer, The Bar after.",kamaaina:null},
  {name:"Laniakea Beach",tier:"A",lat:21.5783,lng:-158.1067,category:"beach",subcategory:"wildlife",tagline:"Known as Turtle Beach — where Hawaiian green sea turtles haul out on the sand right in front of you.",area:"North Shore",price:"Free",parking:"Small roadside lot on Kamehameha Hwy; very limited, watch for traffic pulling in",hours:"Open daily, sunrise to sunset",bestTime:"Late morning to early afternoon for best turtle sightings; calmer summer months for swimming",kidFriendly:true,talkStory:"Volunteers are usually there to make sure people keep the required 10-ft distance from the honu. Turtles are almost always on the beach — I've never been and not seen at least a few. The swimming isn't the main draw here, it's about the turtle experience. Quick stop on the way to or from Haleiwa town — grab lunch at Haleiwa Joe's after.",kamaaina:null},
  {name:"Lanikai Beach",tier:"S",lat:21.3901,lng:-157.7134,category:"beach",subcategory:"swimming",tagline:"Consistently ranked among the world's most beautiful — turquoise water so clear it looks fake.",area:"Kailua",price:"Free",parking:"No public lot — park at Kailua Beach Park and walk 10 min",hours:"Open 24 hours (public beach access via neighborhood paths)",bestTime:"Early morning for calm water and fewer people; sunrise is spectacular",kidFriendly:true,talkStory:"Access via narrow blue beach-access signs along Mokulua Dr — easy to miss. No restrooms, no lifeguards, no shade — bring everything you need. The Lanikai Pillbox hike trailhead is steps away; do the hike first at sunrise, then reward yourself with a swim.",kamaaina:null},
  {name:"Makaha Beach",tier:"B",lat:21.4734,lng:-158.2181,category:"beach",subcategory:"surfing",tagline:"World-class surf history and world-class sunsets — the Waianae coast's crown jewel.",area:"Makaha",price:"Free",parking:"Free parking lot",hours:"Open daily, 7:00 AM – 8:00 PM",bestTime:"Summer for calm swimming and snorkeling; winter for big wave watching (stay out of water); sunset year-round",kidFriendly:false,talkStory:"Be respectful — this is a very local beach and the community takes pride in it. Summer months bring crystal-clear water and turtles. Don't leave valuables in car. Combine with a drive to Yokohama Bay or Ka'ena Point.",kamaaina:null},
  {name:"Makapu'u Beach",tier:"A",lat:21.3161,lng:-157.6645,category:"beach",subcategory:"bodyboard",tagline:"A natural amphitheater channeling perfect shore break — bodyboard legends cut their teeth here.",area:"Makapu'u",price:"Free",parking:"Free lot off Kalanianaole Hwy",hours:"Open daily, sunrise to sunset",bestTime:"Oct–Apr for best east swell; mornings for lighter wind",kidFriendly:false,talkStory:"NOT for beginners — powerful shore break causes more spinal injuries than any beach on Oahu. Watch from the sand first to gauge conditions. Bring fins (no board rental here). Combine with the Makapu'u Lighthouse Trail right next door for a hike + bodyboard day.",kamaaina:null},
  {name:"Makua Beach",tier:"B",lat:21.524,lng:-158.2332,category:"beach",subcategory:"hidden",tagline:"The last beach before the road ends — remote, wild, and stunningly beautiful with spinner dolphins offshore.",area:"West Side",price:"Free",parking:"Roadside parking along Farrington Hwy; limited spaces",hours:"Open daily, sunrise to sunset; road beyond Makua is gated",bestTime:"Summer mornings for calm water and dolphin sightings; avoid after heavy rain",kidFriendly:false,talkStory:"This is about as remote as it gets on Oahu without hiking. The beach sits in a dramatic valley with steep cliffs and spinner dolphins are regularly spotted in the bay. Swimming is only safe in calm summer conditions — winter currents are dangerous. The area has deep cultural significance to Native Hawaiians, so treat it with extra respect. Don't leave any valuables in your car.",kamaaina:null},
  {name:"Malaekahana Beach",tier:"A",lat:21.5703,lng:-157.9245,category:"beach",subcategory:"hidden",tagline:"A mile of empty gold sand with a tiny island you can walk to at low tide — North Shore's best-kept secret.",area:"Laie",price:"Free",parking:"Free state park lot off Kamehameha Hwy",hours:"Open daily, 7:00 AM – 7:45 PM (gates locked at closing)",bestTime:"Low tide to walk to Goat Island (Mokuauia); check tide charts before going",kidFriendly:true,talkStory:"Wade to Goat Island (Mokuauia) at low tide — wear reef shoes, the crossing is rocky. The island has its own tiny beach on the far side. Camping available with state permit. One of the least crowded beaches on Oahu even on weekends.",kamaaina:null},
  {name:"Nanakuli Beach Park",tier:"C",lat:21.3897,lng:-158.1542,category:"beach",subcategory:"sunset",tagline:"A wide sandy beach on the Waianae coast with some of the most fiery sunsets you'll see on the island.",area:"West Side",price:"Free",parking:"Free lot at the park",hours:"Open daily, 6:00 AM – 10:00 PM",bestTime:"Late afternoon for golden light and sunsets; summer for calmer swimming",kidFriendly:true,talkStory:"Nanakuli is a local community beach — not on any tourist radar, which is part of the appeal. The sunsets from this stretch of coast are insane because you're facing due west with nothing between you and the horizon. In summer the water is gentle enough for the kids; winter can bring big surf. Be mindful that this is a tight-knit neighborhood — show respect and aloha and you'll get it back tenfold.",kamaaina:null},
  {name:"Pokai Bay",tier:"B",lat:21.4335,lng:-158.1896,category:"beach",subcategory:"kid-friendly",tagline:"The calmest water on the west side thanks to a protective breakwater — a true locals' family beach.",area:"West Side",price:"Free",parking:"Free lot at Pokai Bay Beach Park",hours:"Open daily, 6:00 AM – 10:00 PM",bestTime:"Year-round; the breakwater keeps the bay calm even when other west side beaches are rough",kidFriendly:true,talkStory:"The breakwater here makes this the safest swimming on the west side — the water inside is basically a pool. This is a real community beach; you'll see local families camping, fishing, and hanging out all weekend. The ancient Ku'ilioloa Heiau (temple) sits on the point and is worth a respectful visit. Not a tourist beach at all, so be respectful of the neighborhood vibe.",kamaaina:null},
  {name:"Punalu'u Beach",tier:"C",lat:21.5698,lng:-157.8925,category:"beach",subcategory:"hidden",tagline:"A skinny ribbon of sand along the windward coast that locals use for quick dips and fishing — no crowds, ever.",area:"Windward",price:"Free",parking:"Roadside pulloffs along Kamehameha Hwy",hours:"Open daily, sunrise to sunset",bestTime:"Summer mornings; water can be murky after rain",kidFriendly:false,talkStory:"Not to be confused with the Big Island's black sand Punalu'u — this is Oahu's quiet windward version. It's a narrow beach popular with local fishermen and the occasional paddler. Not a destination beach, but if you're driving the windward coast and want a quick, uncrowded stop to dip your feet, this is it. The scenery along this stretch of highway is worth the drive alone.",kamaaina:null},
  {name:"Sandy Beach",tier:"A",lat:21.2857,lng:-157.6727,category:"beach",subcategory:"bodyboard",tagline:"Oahu's most notorious shore break — where locals prove themselves and lifeguards stay busy.",area:"Hawaii Kai",price:"Free",parking:"Free lot along Kalanianaole Hwy",hours:"Open daily, sunrise to sunset",bestTime:"Best at 2–4 ft swell for bodyboarding; any day for watching from the sand",kidFriendly:false,talkStory:"NOT for beginners — Sandy's sends more people to the ER than any beach on the island. Even on calm days the shore break is deceptive. Great spectator beach though. The grassy hill above is a top-tier kite-flying and hang-gliding spot. Combine with a drive along the scenic Hwy 72 loop.",kamaaina:null},
  {name:"Shark's Cove",tier:"A",lat:21.6529,lng:-158.0637,category:"beach",subcategory:"snorkeling",tagline:"The best shore snorkeling on Oahu — a rocky cove teeming with sea turtles, reef fish, and tide pool life.",area:"North Shore",price:"Free",parking:"Gravel lot across Kamehameha Hwy; fills by 10 AM on weekends",hours:"Open daily, sunrise to sunset",bestTime:"Summer (May–Sept) when the water is calm and visibility is 50+ ft; never enter in winter swells",kidFriendly:false,talkStory:"Despite the name, no sharks — just incredible snorkeling. The right side has tide pools worth exploring, and the left side drops into deeper water with lava tubes for more advanced snorkelers. Entry over sharp rocks can be tricky — reef shoes are essential. Not ideal for small children due to rocky entry, strong currents on the outer edge, and no sandy beach. Combine with a shave ice run to Ted's Bakery just up the road.",kamaaina:null},
  {name:"Sunset Beach",tier:"A",lat:21.6785,lng:-158.1017,category:"beach",subcategory:"surfing",tagline:"The crown jewel of the Seven Mile Miracle — where the world's best surfers come to prove themselves every winter.",area:"North Shore",price:"Free",parking:"Street parking along Kamehameha Hwy fills fast in winter; arrive before 9 AM",hours:"Open daily, sunrise to sunset",bestTime:"Summer for swimming and sunsets; winter (Nov–Feb) for watching world-class surf competitions",kidFriendly:false,talkStory:"In summer this beach is a completely different animal — flat, wide, and perfect for families. Winter is when it earns its reputation with 15–30 ft faces. The Vans Triple Crown runs here in Nov–Dec and it's free to watch from the sand. Grab a plate lunch from a food truck on Kam Hwy and post up. Don't swim when waves are overhead — the currents here are no joke.",kamaaina:null},
  {name:"Waikiki Beach",tier:"S",lat:21.2765,lng:-157.8272,category:"beach",subcategory:"swimming",tagline:"Yes, it's touristy — but the surf break is gentle, the people-watching is elite, and the sunset with Diamond Head is undeniable.",area:"Waikiki",price:"Free",parking:"Use the Waikiki Shell lot ($5) or park at Kapiolani Park; street parking is near impossible",hours:"Open 24 hours",bestTime:"Early morning for calm water and space; sunset for the iconic view",kidFriendly:true,talkStory:"Locals love to hate on Waikiki, but real talk — the beginner surf break at Canoes is where half of us learned to surf. The trick is going early before the longboard rental crowd hits the water. Walk down toward the Duke statue for the classic section, or go the opposite direction toward the Natatorium for fewer people. Grab musubi from ABC Store and call it a picnic. It's a cliche for a reason.",kamaaina:null},
  {name:"Waimanalo Beach",tier:"A",lat:21.3319,lng:-157.6942,category:"beach",subcategory:"swimming",tagline:"The longest white sand beach on Oahu — nearly 4 miles backed by the Ko'olau mountains.",area:"Waimanalo",price:"Free",parking:"Free lot at Waimanalo Beach Park",hours:"Open daily, 7:00 AM – 8:00 PM",bestTime:"Morning for calm water; any day — rarely crowded",kidFriendly:true,talkStory:"Great bodyboarding on small days too. The Ko'olau mountain backdrop makes this the most photogenic beach on the island — bring a camera. Don't leave valuables in car. Keneke's nearby has the best plate lunch in Waimanalo.",kamaaina:null},
  {name:"Waimea Bay",tier:"S",lat:21.6423,lng:-158.0656,category:"beach",subcategory:"swimming",tagline:"Birthplace of big wave surfing in winter, glass-calm swimming hole in summer — two completely different worlds.",area:"North Shore",price:"Free",parking:"Parking fills by 10am — arrive early or use Haleiwa shuttle",hours:"Open daily, 7:00 AM – 7:45 PM",bestTime:"Summer for calm swimming and Jump Rock; winter for watching 30+ ft waves (do NOT swim)",kidFriendly:false,talkStory:"Jump Rock is the big flat rock on the left side — locals line up to leap off in summer. In winter the bay transforms completely with massive waves; even wading is deadly. Check surf report before going in any season. Across the street is Waimea Valley for a waterfall hike combo day.",kamaaina:null},
  {name:"White Plains Beach",tier:"B",lat:21.3221,lng:-158.0407,category:"beach",subcategory:"surfing",tagline:"A former military beach now open to the public — wide sand, consistent beginner waves, and no Waikiki crowds.",area:"Ewa",price:"Free",parking:"Large free lot; ample parking even on weekends",hours:"Open daily, sunrise to sunset",bestTime:"Morning for glassy surf conditions; year-round for consistent small waves",kidFriendly:true,talkStory:"This used to be restricted to military personnel but is now fully open — and it's one of the best beginner surf spots on the island. The waves are small and consistent, the beach is wide, and there's actual parking. Board rentals are available right at the beach. Way less hectic than learning at Waikiki. The water is clean, the sand is soft, and it never feels crowded. A seriously underrated spot.",kamaaina:null},
  {name:"Yokohama Bay",tier:"B",lat:21.5582,lng:-158.2448,category:"beach",subcategory:"sunset",tagline:"The end of the road on the west side — wild, empty, and painted in fire every evening.",area:"Makaha",price:"Free",parking:"Free lot at end of Farrington Hwy",hours:"Open daily, 7:00 AM – 7:45 PM (gates locked at closing)",bestTime:"Sunset year-round; summer for swimming (winter has dangerous surf)",kidFriendly:false,talkStory:"Zero shade — bring water, sunscreen, and a hat. Swimming in summer only; winter surf is powerful and there are no lifeguards. Ka'ena Point Trail starts here for a spectacular coastal hike to Oahu's westernmost tip. Dolphins sometimes visible offshore in the morning.",kamaaina:null},
  {name:"Ars Cafe",tier:"B",lat:21.266,lng:-157.8105,category:"coffee",subcategory:"cafe",tagline:"Art gallery meets gelato shop meets espresso bar — a charming post-Diamond Head pit stop with homemade Italian gelato.",area:"Kapahulu / Diamond Head",price:"$$",mustOrder:["Homemade gelato — rotating tropical flavors like lilikoi and haupia","Espresso or cappuccino","Affogato — espresso poured over gelato"],parking:"Street parking on Monsarrat Ave. Can be tight on weekends",talkStory:"Tucked on Monsarrat Ave near the base of Diamond Head, Ars Cafe is a tiny Italian-style cafe that doubles as an art gallery. The homemade gelato is the star — made fresh daily with tropical flavors you won't find on the mainland. The espresso is solid and the affogato (espresso over gelato) is the perfect post-hike reward. The space is small and charming with rotating art on the walls. Great combined with Diamond Head sunrise hike or a walk through Kapiolani Park.",cashOnly:false,kamaaina:null},
  {name:"Arvo Cafe",tier:"A",lat:21.2978,lng:-157.8601,category:"coffee",subcategory:"cafe",tagline:"Aussie-inspired at SALT Kakaako — the ube bread alone is worth the trip.",area:"Kakaako",price:"$$",mustOrder:["ube (purple yam) toast","flat white","cold brew"],parking:"SALT has street parking and a lot behind the complex",talkStory:"Arvo means 'afternoon' in Australian slang. Jess built this into one of the most Instagrammed cafes in Hawaii — the pink/coral interior is designed for it. Go right at 8am opening on weekdays. The pastry case sells out early. Walk around SALT afterward — great murals, boutiques, and Moku Kitchen is in the same complex.",cashOnly:false,kamaaina:null},
  {name:"Bean About Town",tier:"B",lat:21.279,lng:-157.784,category:"coffee",subcategory:"specialty-coffee",tagline:"A semi-hidden Kaimuki coffee spot using beans from top mainland roasters — no-fuss, quality-focused neighborhood vibes.",area:"Kaimuki",price:"$",mustOrder:["espresso","pour-over"],parking:"Street parking on 12th Ave",talkStory:"A semi-hidden coffee spot in Kaimuki that uses beans from top roasters like Sightglass and Verve. The small footprint and neighborhood vibe mean mostly locals come here. The espresso drinks are carefully crafted and the pastry selection, while small, is curated. It's the kind of no-fuss, quality-focused coffee shop that makes a neighborhood feel alive. Weekday mornings for the quietest experience.",cashOnly:false,kamaaina:null},
  {name:"Beet Box Cafe",tier:"B",lat:21.3947,lng:-157.7447,category:"coffee",subcategory:"cafe",tagline:"Plant-powered cafe in Kailua with the best oat milk lattes and acai bowls on the Windward side.",area:"Kailua",price:"$$",mustOrder:["golden turmeric latte — anti-inflammatory and delicious","acai bowl with local honey and granola"],parking:"Small lot in front; additional parking on Hahani St",talkStory:"Beet Box started as a health food spot but their coffee game is legit. Everything is plant-based or plant-forward, and they use local produce whenever possible. The turmeric latte is not your basic mainland version — they actually make it well. Great if you're into clean eating or just want something different from the usual coffee shop menu. Kailua moms swear by this place.",cashOnly:false,kamaaina:null},
  {name:"Brew & Foam",tier:"B",lat:21.573,lng:-158.127,category:"coffee",subcategory:"specialty-coffee",tagline:"Hidden in a Waialua shopping center away from tourist Haleiwa — serious baristas and one of the best matcha lattes on the island.",area:"North Shore",price:"$",mustOrder:["matcha latte","espresso"],parking:"Free lot at shopping center",talkStory:"Tucked in a low-key shopping center in Waialua, well away from tourist Haleiwa. The baristas take their craft seriously, and the matcha latte is one of the best on the island. Locals from the North Shore come here specifically because it's not in Haleiwa — no tourist traffic, no lines, just good coffee. Morning, any day of the week.",cashOnly:false,kamaaina:null},
  {name:"ChadLou's Coffee",tier:"A",lat:21.397,lng:-157.7387,category:"coffee",subcategory:"roaster",tagline:"Kailua's most serious roastery — artisan small-batch with cult-following seasonal lattes.",area:"Kailua",price:"$$",mustOrder:["seasonal latte","single-origin pour-over","house roast bag ($14–18)"],parking:"Street parking on Hoolai or in the nearby municipal lot",talkStory:"Chad is a certified Q Grader (the sommelier equivalent for coffee) and sources beans directly from Hawaiian farms. They supply beans to several restaurants around the island. Buy a bag of their house roast to take home — it's some of the best roasted-in-Hawaii coffee you'll find. Ask what single-origin they're pouring that week.",cashOnly:false,kamaaina:null},
  {name:"Coffee Gallery",tier:"S",lat:21.5943,lng:-158.1045,category:"coffee",subcategory:"roaster",tagline:"North Shore roastery with Oahu, Maui, and Kona beans — the real locals' coffee stop in Haleiwa.",area:"Haleiwa",price:"$",mustOrder:["Waialua estate coffee","bag of Waialua beans ($12–16)","iced mocha"],parking:"Parking in the North Shore Marketplace lot — easy",talkStory:"They've been a Haleiwa fixture for years and the staff knows every regular by name and order. They roast beans from multiple Hawaiian estates: Waialua (grown right here on Oahu's North Shore), Maui, Kona, and Kauai. The Waialua estate is on the Dole Plantation side of the North Shore. Grab a bag of Waialua beans as a souvenir — it's genuinely local and most visitors don't know Oahu grows coffee. The Waialua estate coffee is the move — you're literally drinking coffee grown 10 miles from where you're sitting. Good pastry case too. Great first stop before a North Shore beach day.",cashOnly:false,kamaaina:null},
  {name:"Green World Coffee Farm",tier:"A",lat:21.521,lng:-158.013,category:"coffee",subcategory:"farm-cafe",tagline:"A working 7-acre coffee farm on a former pineapple plantation — free self-guided tours and freshly roasted Waialua coffee.",area:"Wahiawa / Central",price:"$",mustOrder:["Waialua estate coffee","homemade banana bread"],parking:"Free lot on the farm",talkStory:"A 7-acre working coffee farm on a former pineapple plantation in Central Oahu. Free self-guided tours let you walk among the coffee trees and learn about the bean-to-cup process. The cafe serves freshly roasted Waialua coffee and homemade baked goods at prices far below any Waikiki coffee shop. Locals stop here on the way to or from the North Shore for a genuinely good, genuinely local cup of coffee.",cashOnly:false,kamaaina:null},
  {name:"Haleiwa Bowls",tier:"B",lat:21.5762,lng:-158.1024,category:"coffee",subcategory:"cafe",tagline:"North Shore's go-to for acai bowls and espresso drinks in the heart of Haleiwa town.",area:"North Shore (Haleiwa)",price:"$$",mustOrder:["iced honey latte — pairs perfectly with an acai bowl","cold brew — strong enough for a post-surf revival"],parking:"Free lot behind Haleiwa town shops on Kamehameha Hwy",talkStory:"Haleiwa Bowls nails that North Shore surfer-health-conscious combo. The acai bowls are some of the best on the island, and the espresso drinks are better than you'd expect from a bowl shop. It's right in Haleiwa town so you can walk to Matsumoto's for shave ice after. Come early before the day-trippers from town arrive — by 10am the line gets long.",cashOnly:false,kamaaina:null},
  {name:"Honolulu Coffee Experience Center",tier:"A",lat:21.286,lng:-157.8368,category:"coffee",subcategory:"roaster",tagline:"Their flagship roastery lets you taste the full range of Hawaiian coffee under one roof.",area:"Ward Village",price:"$$$",mustOrder:["Kona peaberry pour-over — the good stuff","coffee flight — taste multiple Hawaiian estates side by side"],parking:"Ward Village parking structure, free with validation",talkStory:"This is Honolulu Coffee's mothership — not the same as their little airport kiosks. They roast on-site and you can watch the whole process. The coffee flights are the move if you want to learn the difference between Kona, Waialua, and Ka'u. Yeah it's pricier, but you're drinking 100% Hawaiian single-estate beans. Worth it once.",cashOnly:false,kamaaina:null},
  {name:"Island Brew Coffeehouse",tier:"B",lat:21.2887,lng:-157.8447,category:"coffee",subcategory:"cafe",tagline:"Hawaii-grown coffee in an open-air lanai setting right on the Ala Moana waterfront.",area:"Ala Moana",price:"$$",mustOrder:["Hawaiian honey latte — local honey and Waialua coffee","cold brew on nitro — smooth and creamy"],parking:"Ala Moana Center parking garage, free for 4 hours",talkStory:"This is the spot when you want good Hawaii-grown coffee without the Waikiki markup. They source from multiple Hawaiian farms and rotate seasonally. The outdoor lanai has views of Ala Moana Beach Park — grab a seat outside if the trade winds are blowing. Way less hectic than the food court upstairs.",cashOnly:false,kamaaina:null},
  {name:"Island Vintage Coffee",tier:"A",lat:21.2842,lng:-157.837,category:"coffee",subcategory:"cafe",tagline:"100% Kona coffee, acai bowls the size of your head, and the best iced latte in Waikiki — tourist-friendly but genuinely good.",area:"Waikiki (Royal Hawaiian Center)",price:"$$",mustOrder:["Mauna Kea Iced Coffee — Kona coffee, coconut gelato, black lava sea salt","Acai Bowl — massive, loaded with granola and fresh fruit","100% Kona drip coffee"],parking:"Royal Hawaiian Center validated parking or street meters on Kalakaua Ave",talkStory:"Yes, it's in a Waikiki mall, and yes, tourists pack it — but the coffee is genuinely excellent. They use 100% Hawaiian-grown beans (not blends) and roast in small batches. The Mauna Kea Iced Coffee with a scoop of coconut gelato and black lava sea salt is iconic. Their acai bowls are also some of the best on the island — huge portions. Multiple locations across Oahu (Ko Olina, Ala Moana) but the Royal Hawaiian Center original has the most energy. Expect a line at peak hours.",cashOnly:false,kamaaina:null},
  {name:"Kai Coffee Hawaii",tier:"A",lat:21.2783,lng:-157.8272,category:"coffee",subcategory:"cafe",tagline:"A legit local roaster hiding in plain sight on the edge of Waikiki.",area:"Waikiki",price:"$$",mustOrder:["Waialua single-origin drip — clean and bright","macadamia nut latte — tastes like Hawaii"],parking:"Street parking on Monsarrat Ave or park at Kapiolani Park and walk",talkStory:"Kai roasts their own beans and actually cares about the cup, which is rare for a Waikiki-adjacent spot. The Monsarrat Avenue location is near Diamond Head so you can fuel up before or after the hike. They sell bags of their roasts too — makes a way better souvenir than ABC Store Kona coffee. Chill neighborhood vibe, not touristy at all.",cashOnly:false,kamaaina:null},
  {name:"Kona Coffee Purveyors",tier:"S",lat:21.2794,lng:-157.8307,category:"coffee",subcategory:"roaster",tagline:"100% Kona paired with SF's b.Patisserie pastries — the best coffee in Waikiki, full stop.",area:"Waikiki",price:"$$",mustOrder:["100% Kona pour-over ($8–10)","iced Kona latte","b.Patisserie pastries"],parking:"Validated parking at International Market Place garage (3 hrs free with purchase)",talkStory:"Brandon personally visits every farm he sources from. They partnered with Belinda Leong of b.Patisserie (James Beard-nominated SF bakery) for the pastry program. Go before 9am to beat the Waikiki brunch crowd. Ask the baristas which estate the current pour-over comes from. The upstairs location means most tourists walk right past it.",cashOnly:false,kamaaina:null},
  {name:"Manifest",tier:"A",lat:21.311,lng:-157.861,category:"coffee",subcategory:"cafe-bar",tagline:"Chinatown coffee shop by day, cocktail bar by night — a creative hub with gallery vibes and excellent espresso.",area:"Chinatown / Downtown",price:"$$",mustOrder:["espresso","latte","evening cocktail"],parking:"Street parking; paid lots on Maunakea St",talkStory:"By day, Manifest is a serene Chinatown coffee shop with excellent espresso and a quiet, artistic atmosphere. By night, it transforms into a cocktail bar with local DJs and a creative crowd. The space is filled with provocative art and has a lofty, gallery-like feel. Locals love the duality — come for coffee and work in the afternoon, return for cocktails and socializing at night. Friday and Saturday nights are the most lively.",cashOnly:false,kamaaina:null},
  {name:"Moke's Bread & Breakfast",tier:"C",lat:21.3958,lng:-157.7466,category:"coffee",subcategory:"cafe",tagline:"Famous for lilikoi pancakes, but the coffee is no afterthought here.",area:"Kailua",price:"$$",mustOrder:["house coffee with lilikoi pancakes — the full experience","iced coffee — strong, you'll need it for the wait"],parking:"Street parking on Kailua Rd or public lot on Hahani St",talkStory:"Yeah, Moke's is known for breakfast, but they brew solid coffee and you're gonna be here anyway for those lilikoi pancakes. The line can be 30-45 minutes on weekends — come at 7am or accept your fate. Named after the family dog. The vibe is pure local breakfast spot energy. If the Kailua location is packed, they have one in Honolulu too.",cashOnly:false,kamaaina:null},
  {name:"Morning Brew",tier:"A",lat:21.3938,lng:-157.7356,category:"coffee",subcategory:"cafe",tagline:"Kailua's beloved bohemian coffeehouse — strong wifi, all-day breakfast, 100% Hawaiian-roasted coffee.",area:"Kailua",price:"$",mustOrder:["honey macadamia nut latte","cold brew","acai bowl"],parking:"Parking in the Kailua Shopping Center lot — free and usually easy",talkStory:"This is where Kailua moms, surfers, and remote workers all converge. Weekend mornings are packed with post-beach regulars. Jim is often around and loves talking coffee sourcing. Pair with a Kailua Beach morning — park at the lot, grab coffee first, then walk to the beach (10 min). Good WiFi and plenty of outlets — one of the best remote work spots on the Windward side.",cashOnly:false,kamaaina:null},
  {name:"Morning Glass Coffee",tier:"A",lat:21.2877,lng:-157.8213,category:"coffee",subcategory:"cafe",tagline:"Manoa's beloved neighborhood cafe where UH professors and surfers share the same lanai.",area:"Manoa",price:"$$",mustOrder:["honey lavender latte — floral and smooth","acai bowl — thick, not watered down"],parking:"Small lot behind the building; street parking on East Manoa Rd",talkStory:"Morning Glass is the kind of place where you see the same regulars every day — it's Manoa's living room. The upstairs lanai is magic on a rainy Manoa morning (and it rains a lot up here). They do solid food too, the breakfast menu is legit. If you're heading to Manoa Falls, stop here first. Way better than anything near the trailhead.",cashOnly:false,kamaaina:null},
  {name:"Seven Brothers",tier:"B",lat:21.6413,lng:-158.0628,category:"coffee",subcategory:"cafe",tagline:"Samoan family-run cafe in Kahuku serving hearty food and solid coffee near the shrimp trucks.",area:"North Shore (Kahuku)",price:"$",mustOrder:["iced mocha — thick and sweet, fuels the drive home","any plate lunch with a drip coffee — full local experience"],parking:"Free lot in Kahuku town center",talkStory:"Seven Brothers is named because there are literally seven brothers running it. It's a Samoan family operation and the portions are massive. The coffee is simple but good — you're here for the full vibe. Right in Kahuku town near the famous shrimp trucks. If you're doing a North Shore loop, this is a legit stop for both food and caffeine. Aloha spirit is strong here.",cashOnly:false,kamaaina:null},
  {name:"Surfers Coffee",tier:"B",lat:21.5038,lng:-158.0239,category:"coffee",subcategory:"cafe",tagline:"Non-profit coffee shop run by Surfing The Nations — great espresso with an even better mission.",area:"Wahiawa",price:"$",mustOrder:["espresso","drip coffee","mocha"],parking:"Free parking lot",talkStory:"Surfing The Nations has done humanitarian work across the Pacific — tsunami relief, youth outreach in underserved communities, surf therapy programs. Every cup you buy funds something real. The vibe is warm and community-oriented. This is the perfect pit stop if you're driving between Honolulu and the North Shore — Wahiawa is dead center. Fill up on caffeine before hitting the beaches.",cashOnly:false,kamaaina:null},
  {name:"Waialua Estate Coffee & Chocolate",tier:"A",lat:21.5744,lng:-158.1303,category:"coffee",subcategory:"roaster",tagline:"Farm-to-cup coffee grown and roasted right here on the North Shore — this is the real Hawaii coffee experience.",area:"North Shore (Waialua)",price:"$$",mustOrder:["Waialua single-origin drip — grown literally across the road","chocolate-covered coffee beans — made on-site from estate cacao"],parking:"Free lot at the old Waialua Sugar Mill complex",talkStory:"This is one of the few places on Oahu where the coffee is actually grown, roasted, and served in the same ahupuaa. The old Waialua Sugar Mill has been converted into a collection of local shops, and the coffee operation here uses land that was once sugarcane fields. They grow cacao too, so the chocolate-covered beans are a double-local combo. Ask about the harvest — they're usually happy to talk story about the farming process.",cashOnly:false,kamaaina:null},
  {name:"ARTS at Marks Garage",tier:"B",lat:21.313,lng:-157.8625,category:"cultural",subcategory:"gallery",tagline:"Honolulu's community arts hub — rotating exhibitions, makers' markets, and the heartbeat of Chinatown's First Friday scene.",area:"Chinatown / Downtown",price:"Free",parking:"Street parking; walk from downtown",hours:"Tue-Sat 11am-6pm; late on First Fridays",bestTime:"First Friday of every month for the art walk; regular gallery hours during the week",kidFriendly:true,talkStory:"Honolulu's community arts hub rotates exhibitions across painting, photography, sculpture, and mixed media, and hosts film screenings, makers' markets, and performance art. The space supports local and emerging artists and feels genuinely grassroots. First Friday nights here are electric — the gallery opens late, the streets fill with people, and art spills onto the sidewalk. This is the heartbeat of Honolulu's creative scene.",kamaaina:null},
  {name:"Battleship Missouri Memorial",tier:"A",lat:21.3639,lng:-157.9517,category:"cultural",subcategory:"historic",tagline:"Stand on the exact deck where WWII ended — the Mighty Mo pairs perfectly with the Arizona Memorial across the harbor.",area:"Pearl Harbor",price:"$$",parking:"Use the Pearl Harbor Visitor Center lot ($7/day). Shuttle bus takes you to Ford Island",hours:"Daily 8am–4pm. Closed Thanksgiving, Christmas, New Year's Day",bestTime:"Morning — do the Arizona Memorial first (free, timed tickets), then shuttle to the Missouri. Plan 1.5–2 hours aboard",kidFriendly:true,talkStory:"The USS Missouri is where General Douglas MacArthur accepted Japan's formal surrender on September 2, 1945, ending WWII. You can stand on the exact spot on the surrender deck — marked with a bronze plaque. The ship is massive (887 feet long) and you can explore multiple decks, crew quarters, the bridge, and massive 16-inch gun turrets. Look for the dent in the hull from a kamikaze strike. Combined with the Arizona Memorial, it bookends the Pacific War — the Arizona marks the beginning, the Missouri the end. Budget $35/adult for general admission; guided tours cost more but are worth it.",kamaaina:"Kamaaina/military rates available with valid ID"},
  {name:"Byodo-In Temple",tier:"S",lat:21.4252,lng:-157.8257,category:"cultural",subcategory:"temple",tagline:"A full-scale replica of a 900-year-old Kyoto temple tucked against the Ko'olau cliffs — ring the 3-ton bell for blessings.",area:"Kaneohe",price:"$",parking:"Free parking at the entrance",hours:"Daily 8:30am–4:30pm. Last entry 4:15pm",bestTime:"Early morning for misty mountain backdrop and fewer crowds — golden hour light is stunning for photos",kidFriendly:true,talkStory:"Built in 1968 to honor 100 years of Japanese immigration to Hawaii. Ring the sacred bon-sho bell before entering — tradition says it brings happiness and long life. Inside sits a 9-foot golden Lotus Buddha. Buy $1 fish food at the gift shop to feed the koi (some are over 100 years old) — don't bring outside food, it makes them sick. Wild peacocks roam the grounds but can be feisty during mating season. The temple sits in the Valley of the Temples Memorial Park, a multi-faith cemetery at the base of the Ko'olau mountains. Allow 1-2 hours. Was a filming location for Lost.",kamaaina:"Kamaaina rate: $4 adults, $3 seniors, $2 kids (vs $7/$6/$4 general) with Hawaii ID. No cash — card/contactless only"},
  {name:"Chinatown Cultural Plaza",tier:"B",lat:21.313,lng:-157.862,category:"cultural",subcategory:"cultural-center",tagline:"Traditional herbalists, dim sum restaurants, and Maunakea Street lei stands — the living heart of Honolulu's Chinatown.",area:"Chinatown / Downtown",price:"Free",parking:"Paid parking in plaza garage",hours:"Varies by shop; most open 8am-5pm",bestTime:"Mornings for the freshest lei on Maunakea St; Chinese New Year for festivals",kidFriendly:true,talkStory:"This unassuming plaza houses traditional herbalists, acupuncturists, jewelry shops, and some of the best dim sum in the city. The courtyard comes alive during Chinese New Year and other festivals. Locals shop here for dried seafood, traditional Chinese medicine, and jade jewelry. The lei stands outside on Maunakea Street sell the most beautiful and affordable lei on the island — buy your lei here, not at the airport.",kamaaina:null},
  {name:"Dole Plantation",tier:"B",lat:21.5265,lng:-158.035,category:"cultural",subcategory:"attraction",tagline:"Touristy but fun — ride the Pineapple Express, get lost in the world's largest maze, and eat a Dole Whip at the source.",area:"Central Oahu (Wahiawa)",price:"$$",parking:"Free parking lot, large and usually available",hours:"Daily 9:30am–5pm",bestTime:"Arrive by 10am to beat tour bus crowds. Weekdays are significantly less packed than weekends",kidFriendly:true,talkStory:"Yes, it's a tourist trap — but it's a fun one, especially with kids. The Pineapple Express train ride (20 min, ~$14) gives a nice overview of the plantation and North Shore agriculture. The Pineapple Garden Maze is certified by Guinness as the world's largest — budget 30-45 min. The real move is to skip the gift shop markup and grab a Dole Whip (pineapple soft serve) from the stand out front. Great pit stop on the way to or from the North Shore. Locals rarely go, but visitors love it.",kamaaina:"Kamaaina discounts on train ride and maze with valid Hawaii ID"},
  {name:"Foster Botanical Garden",tier:"B",lat:21.317,lng:-157.858,category:"cultural",subcategory:"garden",tagline:"Honolulu's oldest botanical garden (1853) — ancient trees, rare orchids, and a peaceful escape in the heart of the city.",area:"Chinatown / Downtown",price:"$5",parking:"Free lot on Vineyard Blvd",hours:"Daily 9am-4pm",bestTime:"Weekday mornings for the most peaceful experience",kidFriendly:true,talkStory:"Established in 1853 by Queen Kalama, Foster is Honolulu's oldest botanical garden and a peaceful 14-acre oasis in the heart of the city. Ancient trees planted by early botanists tower overhead, the orchid collection is world-class, and the prehistoric glen features plants that date back to the age of dinosaurs. Most tourists rush to Diamond Head or Waikiki and completely miss this gem. The bo tree, grown from a cutting of the original tree under which Buddha attained enlightenment, is a highlight.",kamaaina:null},
  {name:"Hawaiian Mission Houses",tier:"C",lat:21.305,lng:-157.859,category:"cultural",subcategory:"museum",tagline:"The oldest surviving Western buildings in Hawaii (1821) — honest, nuanced storytelling about missionaries' complex legacy.",area:"Downtown",price:"$12",parking:"Metered street parking on King St",hours:"Tue-Sat 10am-4pm; check for special events",bestTime:"Guided tour times vary; Wednesday evening events are popular",kidFriendly:true,talkStory:"The oldest surviving Western-style buildings in Hawaii (dating to 1821) sit in the shadow of downtown Honolulu's skyscrapers. Guided tours reveal the complex story of the missionaries who arrived in Hawaii and their lasting impact on Hawaiian culture, for better and worse. The printing house where Hawaiian-language texts were first produced is particularly fascinating. Locals appreciate the nuanced, honest storytelling.",kamaaina:null},
  {name:"Honolulu Museum of Art",tier:"A",lat:21.3038,lng:-157.8485,category:"cultural",subcategory:"museum",tagline:"Hawaii's largest art museum — 50,000 works spanning 5,000 years, housed in a stunning 1927 building with open-air courtyards.",area:"Downtown Honolulu",price:"$$",parking:"Street parking on Beretania St or paid lots nearby. Limited museum lot",hours:"Wed–Mon 10am–6pm, Fri until 9pm. Closed Tuesdays",bestTime:"First Friday of the month — free admission, live music, food trucks, and a festive atmosphere. Weekday mornings are quietest",kidFriendly:true,talkStory:"Founded by Anna Rice Cooke in 1927, this museum is a hidden gem that most visitors skip. The building itself is gorgeous — a series of galleries connected by open-air courtyards with koi ponds and tropical gardens. The collection spans Asian, European, American, Pacific Island, and Hawaiian art. Highlights include a world-class collection of Japanese woodblock prints, a Monet, a Van Gogh, and rotating contemporary exhibitions. The museum cafe is excellent for lunch. Also operates Shangri La (Doris Duke's Islamic art estate) — book that separately.",kamaaina:"Free admission for Hawaii residents with valid ID. General admission $20"},
  {name:"Iolani Palace",tier:"S",lat:21.3065,lng:-157.859,category:"cultural",subcategory:"historical-site",tagline:"The only royal palace on American soil — home to Hawaii's last monarchs, with electricity before the White House.",area:"Downtown",price:"$27",parking:"Metered street parking; paid lots on King St",hours:"Tue-Sat 9am-4pm; tours at set times",bestTime:"Morning guided tours; Friday noon concerts by the Royal Hawaiian Band on the grounds (free)",kidFriendly:true,talkStory:"Home to Hawaii's last reigning monarchs — King Kalakaua and Queen Liliuokalani — Iolani Palace had electricity before the White House. Guided tours reveal the tragic story of Hawaii's overthrow, and the restored state rooms are magnificent. Locals view this as a deeply important cultural site, not just a museum. The grounds are beautiful and free to walk. Reserve guided tours in advance; Friday noon concerts by the Royal Hawaiian Band are a beloved tradition.",kamaaina:"Kamaaina rates available"},
  {name:"National Memorial Cemetery of the Pacific",tier:"A",lat:21.3122,lng:-157.8487,category:"cultural",subcategory:"historic",tagline:"A sacred resting place inside an extinct volcanic crater — free to visit, with sweeping views of Honolulu and a humbling sense of history.",area:"Punchbowl (Honolulu)",price:"Free",parking:"Free parking inside the crater. Drive up Puowaina Drive",hours:"Daily 8am–5:30pm (Oct–Feb); 8am–6:30pm (Mar–Sep)",bestTime:"Early morning for cooler temps and fewer visitors. Combine with a Tantalus Drive loop",kidFriendly:true,talkStory:"Known locally as Punchbowl, this cemetery sits inside the Puowaina crater — 'Puowaina' means 'Hill of Sacrifice' in Hawaiian. Over 53,000 veterans are interred here, including those from WWI, WWII, Korea, and Vietnam. The Courts of the Missing list 28,000+ names of service members whose remains were never recovered. The views of Honolulu from the crater rim are stunning. This is not a tourist attraction — it's a place of deep respect. Keep voices low, stay on paths, and be mindful. Free admission, no reservations needed.",kamaaina:null},
  {name:"Pearl Harbor National Memorial",tier:"S",lat:21.3647,lng:-157.95,category:"cultural",subcategory:"historic",tagline:"The USS Arizona Memorial, Battleship Missouri, and the site where December 7, 1941 changed the world — free admission, book ahead.",area:"Pearl Harbor",price:"Free",parking:"$7/day in visitor center lot — arrives early, fills fast. Do NOT leave valuables in your car (high-theft area)",hours:"Daily 7am–5pm. Last Arizona Memorial boat at 3:30pm. Closed Thanksgiving, Christmas, New Year's Day",bestTime:"Arrive by 7am for walk-up tickets or book online 8 weeks ahead on Recreation.gov ($1 service fee). Mornings are cooler and less crowded",kidFriendly:true,talkStory:"Four major sites, each takes a couple hours: the USS Arizona Memorial (free, 45-min program with documentary and boat ride to the memorial), USS Bowfin submarine, Battleship Missouri, and Pearl Harbor Aviation Museum (last two require bus to Ford Island, separate paid admission). NO BAGS ALLOWED — no purses, backpacks, camera bags, or diaper bags. Only wallets, cameras, phones, and water bottles. Bag storage available near entrance for $5-10. 1,300 free walk-up tickets released daily but go fast. The memorial straddles the sunken hull of the Arizona without touching it — you can still see oil leaking from the ship 80+ years later. Plan a full day if seeing all four sites.",kamaaina:null},
  {name:"Pu'u o Mahuka Heiau",tier:"A",lat:21.6402,lng:-158.0572,category:"cultural",subcategory:"historical-site",tagline:"Oahu's largest ancient Hawaiian temple — a sacred 17th-century site on a bluff overlooking Waimea Bay with breathtaking views.",area:"North Shore",price:"Free",parking:"Small gravel lot at the end of Pupukea Rd",hours:"Open daily, daylight hours",bestTime:"Sunrise or sunset for the most powerful atmosphere",kidFriendly:true,talkStory:"Oahu's largest ancient Hawaiian temple covers nearly two acres on a bluff overlooking Waimea Bay. Built in the 17th century, this National Historic Landmark was a place of human sacrifice and spiritual power. Today, locals still leave offerings of ti leaves wrapped around stones. The views of Waimea Valley and the ocean are breathtaking. Most tourists visit Waimea Bay below without knowing this sacred site exists just up the road. Treat the site with deep respect.",kamaaina:null},
  {name:"Shangri La",tier:"A",lat:21.257,lng:-157.793,category:"cultural",subcategory:"museum",tagline:"Doris Duke's oceanfront Islamic art mansion — a jaw-dropping private estate with 2,500 pieces of art from the Islamic world.",area:"Kahala / Diamond Head",price:"$30",parking:"Tours depart from Honolulu Museum of Art; shuttle provided",hours:"Wed-Sat; tours at set times (must pre-book)",bestTime:"Book well in advance; tours are small and sell out",kidFriendly:false,talkStory:"Tobacco heiress Doris Duke built this stunning oceanfront estate in the 1930s and filled it with over 2,500 pieces of Islamic art collected during her world travels. The house itself is a work of art — intricate tilework, carved wooden screens, and gardens inspired by Mughal and Moorish design. Tours are small (12 people) and depart from the Honolulu Museum of Art. One of the most unique cultural experiences in all of Hawaii.",kamaaina:"Kamaaina rates available"},
  {name:"CLIMB Works Keana Farms",tier:"B",lat:21.683,lng:-157.995,category:"experience",subcategory:"adventure",tagline:"Eight ziplines over a working North Shore farm with panoramic ocean and mountain views — Oahu's best zipline, period.",area:"Kahuku",price:"$$$",parking:"Free on-site parking. Check in 40 minutes before tour time",hours:"Mon–Sat 8am–6pm. Closed Sundays",bestTime:"Morning tours for cooler temps and best light on the Ko'olau mountains. Book at least 5 days ahead during busy season",kidFriendly:true,talkStory:"Three-hour tour with 8 dual ziplines (up to half a mile long), 2 rappels, sky bridges, and an ATV ridgetop ride over a 450-acre working farm that grows macadamia nuts, papaya, and taro. Kids as young as 5 can go (must be accompanied by adult); under 80 lbs can ride tandem with a guide. Weight limit 270 lbs (250 if under 5'10\"). Wear closed-toe shoes and clothes you don't mind getting dirty. Lockers provided for phones and valuables. Perfect 5.0 rating on Google with 8,500+ reviews — that's not a typo. The views of the North Shore coastline from the ridgeline are unreal.",kamaaina:"25% kamaaina discount with valid Hawaii ID — brings price from $169 to about $127"},
  {name:"First Friday Art Walk",tier:"A",lat:21.312,lng:-157.862,category:"experience",subcategory:"cultural-event",tagline:"Chinatown transforms into a block party every first Friday — galleries, street performers, food, and the creative pulse of Honolulu.",area:"Chinatown / Downtown",price:"Free",parking:"Street parking fills fast; take the bus or rideshare",hours:"First Friday of each month, 5-9pm",bestTime:"Start at Hotel Street around 5:30pm and wander; galleries close around 9pm",kidFriendly:true,talkStory:"On the first Friday of every month, Honolulu's Chinatown transforms into a block party centered on the arts. Galleries on Nu'uanu Avenue open their doors late, street performers and musicians set up on corners, restaurants and bars offer special menus, and the streets fill with a creative, diverse crowd. This is where locals go to see and be seen, discover new artists, and enjoy Chinatown's vibrant food and drink scene all in one evening.",kamaaina:null},
  {name:"Halona Blowhole Lookout",tier:"B",lat:21.2789,lng:-157.6779,category:"experience",subcategory:"scenic-viewpoint",tagline:"A natural lava tube that shoots ocean spray 30 feet in the air — quick roadside stop with views of the rugged east coast.",area:"Hawaii Kai / East Side",price:"Free",parking:"Free pullout lot on Kalanianaole Hwy. Small and fills fast midday",hours:"Open 24/7 (roadside pullout)",bestTime:"Best spray during high surf and high tide — winter swells produce the most dramatic blasts. Morning light is best for photos",kidFriendly:true,talkStory:"A quick but satisfying stop on the east side drive between Hanauma Bay and Makapu'u. The blowhole shoots water through a lava tube formed by volcanic activity — bigger swells mean bigger blasts, sometimes 30+ feet. The lookout also overlooks Halona Cove (aka 'From Here to Eternity Beach' from the 1953 film). DO NOT climb down the rocks to the blowhole — people have been killed by rogue waves and getting sucked into the tube. Stay behind the guardrail. Combine with Sandy Beach (next door), Hanauma Bay, and Makapu'u Lighthouse Trail for a full east side day.",kamaaina:null},
  {name:"Hawaii Nature Center",tier:"B",lat:21.319,lng:-157.826,category:"experience",subcategory:"nature-education",tagline:"Interactive nature education in Makiki Valley — guided rainforest walks, bug hunts, and Hawaiian ecology for curious kids and adults.",area:"Makiki",price:"$15",parking:"Limited lot on Makiki Heights Dr",hours:"Daily 8am-4pm; guided programs at set times",bestTime:"Morning guided programs; weekdays are less busy",kidFriendly:true,talkStory:"Nestled in Makiki Valley just minutes from downtown, the Hawaii Nature Center offers interactive nature education perfect for curious kids. Guided rainforest walks teach about native Hawaiian plants and animals, bug hunts let kids explore with magnifying glasses, and the interpretive center has hands-on exhibits about Hawaiian ecology. Local families love the weekend programs. A great rainy-day or hot-day alternative to the beach.",kamaaina:null},
  {name:"Hawaii State Art Museum",tier:"B",lat:21.308,lng:-157.8595,category:"experience",subcategory:"museum",tagline:"Free museum showcasing Hawaii's best contemporary art in a beautifully restored 1928 Spanish Colonial building downtown.",area:"Downtown",price:"Free",parking:"Metered street parking on Hotel St",hours:"Tue-Sat 10am-4pm",bestTime:"Weekday afternoons for the quietest experience; First Friday evenings",kidFriendly:true,talkStory:"Housed in a beautifully restored 1928 Spanish Colonial building (the former YMCA Armed Services building), HiSAM showcases Hawaii's best contemporary art across multiple galleries — all for free. The permanent collection features works by Hawaii's leading artists, and rotating exhibitions highlight emerging talent. The sculpture garden courtyard is a peaceful surprise. Most tourists walk right past without realizing this free gem exists.",kamaaina:null},
  {name:"Ko Hana Distillers",tier:"A",lat:21.452,lng:-158.037,category:"experience",subcategory:"distillery",tagline:"Oahu's only rum distillery — Hawaiian agricole rum made from 34 heritage sugarcane varieties grown on-site.",area:"Kunia / Central",price:"$$",parking:"Free lot on the farm",hours:"Tours and tastings daily; check schedule",bestTime:"Reserve ahead on weekends; weekday tastings are more intimate",kidFriendly:false,talkStory:"Oahu's only rum distillery produces Hawaiian agricole rum from 34 heritage varieties of Hawaiian sugarcane grown on-site. The tasting room tour explains how pre-contact Hawaiians cultivated ko (sugarcane) and how each heirloom variety produces a different flavor. The tasting flight includes single-varietal rums unlike anything you've had. Locals bring visitors here as a proudly Hawaiian alternative to wine tasting. The agricultural setting in Kunia is beautiful.",kamaaina:null},
  {name:"Ko'olau Distillery",tier:"B",lat:21.396,lng:-157.792,category:"experience",subcategory:"tasting",tagline:"A veteran-owned craft distillery in Kailua making whiskey, rum, and gin — tours, tastings, trivia nights, and food trucks.",area:"Kailua",price:"$$",parking:"Free parking in the Kapaa Quarry Pl industrial complex",hours:"Mon & Wed 12pm–7pm. Tue 12pm–8pm. Thu 12pm–9pm. Fri 12pm–10pm. Sat 12pm–9pm. Sun 8am–7pm",bestTime:"Thursday trivia nights or weekends for food trucks and live music. Afternoon tours at 1pm, 3pm, or 4pm",kidFriendly:false,talkStory:"Tucked in an industrial complex near the Kailua/Kaneohe border, this veteran-owned distillery has quietly become one of Oahu's best hangout spots. One-hour tours cover the full whiskey process from mashing to bottling, ending with a 5-spirit tasting. Their signature Old Pali Road Whiskey is the star. Beyond tours, they have a full bar with craft cocktails, local beers, and wine. Thursday trivia nights are packed, and weekends usually have food trucks and live music in the outdoor area. 21+ for tastings.",kamaaina:null},
  {name:"La'ie Point State Wayside",tier:"A",lat:21.6514,lng:-157.9169,category:"experience",subcategory:"scenic",tagline:"A dramatic windswept cliff with views of a natural sea arch and offshore bird sanctuary — free, quick, and totally uncrowded.",area:"Laie",price:"Free",parking:"Only about 10 spots at the end of Naupaka St — park further down and walk if full. Be respectful of residents",hours:"Daylight hours (roughly 7am–6:30pm)",bestTime:"Late afternoon for golden light on the cliffs. Morning for calmer seas and better visibility of Kukuihoolua Island",kidFriendly:true,talkStory:"A 5-minute walk from the parking area to a rocky coastal point with views of Kukuihoolua Island (the one with the natural arch punched through it) and a seabird sanctuary. Wear closed-toe shoes — the lava rock is sharp and uneven. Not a swimming spot (strong currents and dangerous rocks). No facilities or restrooms. It's a 15-minute stop that pairs perfectly with a North Shore day trip — between PCC and Kahuku shrimp trucks. One of the most photographed spots on the Windward Coast but rarely crowded because most tourists don't know about it.",kamaaina:null},
  {name:"Manoa Honey & Mead",tier:"B",lat:21.51,lng:-158.03,category:"experience",subcategory:"tasting",tagline:"Hawaii's only meadery — taste local honey wines, tour the apiary, and learn about beekeeping on a working honey farm.",area:"Wahiawa",price:"$$",parking:"Free on-site parking",hours:"Wed–Thu 10am–4pm. Fri–Sun 11am–6pm. Closed Mon–Tue",bestTime:"Saturday for Bees to Mead tours at 10am or 2pm (reservations required). Weekday afternoons for unhurried tastings",kidFriendly:false,talkStory:"Don't let the Wahiawa industrial location fool you — this tiny meadery is doing something nobody else in Hawaii is. They make mead (honey wine) from their own hives and offer tastings of 6 varieties Friday through Sunday (last seating 5pm). The Bees to Mead tour ($10 deposit) takes you through the apiary to see honey harvesting up close before tasting. You can share tasting flights if 6 glasses is too much. The showroom sells local honey products and bottles to take home. It's small, it's not fancy, and that's exactly why it's great. 21+ for mead tastings.",kamaaina:null},
  {name:"Nu'uanu Pali Lookout",tier:"A",lat:21.366,lng:-157.7935,category:"experience",subcategory:"scenic-viewpoint",tagline:"The most dramatic viewpoint on Oahu — sheer cliffs, howling winds, and the entire Windward Coast spread out below.",area:"Nu'uanu (Pali Highway)",price:"$",parking:"$7/vehicle. Small lot fills up midday",hours:"Daily 6am–6pm",bestTime:"Morning for clearest views. Afternoon clouds roll in. Trade winds blast through here — hold onto hats, phones, and small children",kidFriendly:true,talkStory:"This is where King Kamehameha I won the decisive 1795 Battle of Nu'uanu, driving hundreds of O'ahu warriors over the 1,000-foot cliffs to unify the Hawaiian Islands. The views are jaw-dropping — the entire Windward Coast from Kaneohe to Kailua laid out below the Ko'olau cliffs. The wind here is legendary — sustained 30-40 mph gusts are normal, and 60+ mph days happen. It's a quick stop (15-20 min) right off the Pali Highway between Honolulu and Kailua. Great combined with Old Pali Road hike nearby.",kamaaina:"$3 parking for Hawaii residents with valid ID"},
  {name:"Kailua Farmers' Market",tier:"A",lat:21.397,lng:-157.74,category:"farmers-market",subcategory:"evening",tagline:"Thursday evening market run by the same folks behind KCC — 20 years of Hawaii-grown-only produce, mochi, and street corn.",area:"Kailua",price:"Free",parking:"Free parking at Kailua Town Center",hours:"Thursdays 4pm–7pm sharp. Alarm sounds at 7pm and all sales stop immediately",bestTime:"Arrive before 5pm — popular items like Mochi Aulelei Hawaii taro mochi and Nozawa Farms street corn sell out early",kidFriendly:true,talkStory:"Run by the Hawaii Farm Bureau, the same organization behind the famous KCC Farmers Market. This one's been going for 20 years and strictly sells Hawaii-grown products — produce, flowers, beef, pork, seafood, and ready-to-eat foods. Look for the family-run German bakery and handmade salsas. Kids love the chalk and live music. The 7pm alarm is no joke — when it goes off, everything shuts down, so don't arrive at 6:45 expecting to browse. Located at 609 Kailua Rd in Kailua Town Center.",kamaaina:null},
  {name:"KailuaTown Farmers Market",tier:"B",lat:21.4,lng:-157.744,category:"farmers-market",subcategory:"sunday",tagline:"Sunday morning market with live music, local coffee, and a relaxed Kailua vibe — the Windward side's best weekend ritual.",area:"Kailua",price:"Free",parking:"Free parking near Adventist Health Castle Hospital area. Come early for closest spots",hours:"Sundays 8am–12pm, rain or shine",bestTime:"Arrive at 8am for best selection of fresh produce and baked goods before they sell out",kidFriendly:true,talkStory:"Run by FarmLovers Markets at 640 Ulukahiki St, east of Castle Hospital. Live music sets the mood while you browse local produce, fresh flowers, jams, honey, and prepared foods. The open-air cafe area with locally grown coffee and pastries is where Kailua locals hang on Sunday mornings. Dog-friendly. Most vendors take cards but bring cash for faster transactions. Pairs well with a morning at Kailua Beach or brunch at Moke's down the road.",kamaaina:null},
  {name:"KCC Farmers Market",tier:"S",lat:21.269,lng:-157.8,category:"farmers-market",subcategory:"weekend-market",tagline:"Hawaii's biggest and best farmers market — 80+ vendors, incredible prepared food stalls, and a Diamond Head backdrop.",area:"Kapahulu / Diamond Head",price:"$-$$",parking:"Free parking at KCC campus; fills up fast",hours:"Saturdays 7:30am-11am; Tuesdays 4-7pm (smaller)",bestTime:"Arrive at 7:30am Saturday opening; by 9:30am the best items sell out",kidFriendly:true,talkStory:"The biggest and best farmers market in Hawaii takes place every Saturday morning at Kapiolani Community College near Diamond Head. About 80 vendors sell everything from fresh-pressed sugarcane juice and macadamia nut ice cream to fried green tomatoes and local honey. The prepared food stalls are a destination unto themselves. Locals arrive right at 7:30am for the best selection. The Tuesday evening market is smaller but less crowded.",kamaaina:null},
  {name:"Pearlridge Farmers Market",tier:"B",lat:21.385,lng:-157.938,category:"farmers-market",subcategory:"weekend-market",tagline:"Saturday morning market in Aiea drawing local families — strong Filipino food stalls and the best prices on tropical fruit.",area:"Aiea / Pearl City",price:"$",parking:"Free parking at Pearlridge Center",hours:"Saturdays 8am-12pm",bestTime:"Arrive early for the best tropical fruit selection",kidFriendly:true,talkStory:"A Saturday morning market at Pearlridge Center that draws local families from Central and West Oahu. The selection of fresh tropical fruits, locally made pickles and preserves, and Filipino prepared foods is particularly strong. This market sees very few tourists and offers some of the best prices on the island for local produce. A great stop if you're in the Aiea/Pearl City area.",kamaaina:null},
  {name:"Waialua Farmers Market",tier:"B",lat:21.577,lng:-158.13,category:"farmers-market",subcategory:"weekend-market",tagline:"A small but excellent Saturday market inside the historic Waialua Sugar Mill — hyper-local produce and artisan goods.",area:"North Shore",price:"$",parking:"Free lot at the Sugar Mill",hours:"Saturdays 8:30am-12pm",bestTime:"Saturday mornings; combine with shopping at the Sugar Mill artisan shops",kidFriendly:true,talkStory:"Held Saturdays inside the historic Waialua Sugar Mill, this small but excellent market features hyper-local produce, homemade jams, fresh-baked goods, and coffee grown just up the road. The vendors are local farmers and artisans you can chat with about their products. Combined with the nearby shops in the Sugar Mill (including Waialua Coffee & Chocolate and Green Gypsy Thrift), it makes for a perfect North Shore morning.",kamaaina:null},
  {name:"Windward Mall Farmers Market",tier:"B",lat:21.417,lng:-157.811,category:"farmers-market",subcategory:"indoor-market",tagline:"Air-conditioned indoor market every Wednesday — exceptional prepared foods reflecting the true diversity of Windward Oahu.",area:"Windward",price:"$",parking:"Free mall parking",hours:"Wednesdays 2:30-7:30pm",bestTime:"Go hungry — the prepared food stalls (smoked fish, poke, mango sticky rice, ube pastry) are outstanding",kidFriendly:true,talkStory:"A completely air-conditioned indoor farmers market held every Wednesday inside Windward Mall. The selection of prepared foods — smoked fish, fresh poke, mango sticky rice, ube pastry, and taro chips — is exceptional. Locals on the Windward side treat this as their weekly grocery and dinner run. The mix of Asian, Pacific Island, and Hawaiian foods reflects the true diversity of the Kaneohe community.",kamaaina:null},
  {name:"Aiea Loop Trail",tier:"B",lat:21.3986,lng:-157.896,category:"hike",subcategory:"easy",tagline:"Lush forest loop above Pearl Harbor with WWII crash site remnants — underrated and uncrowded.",area:"Aiea",price:"Free",parking:"Free lot at Keaiwa Heiau State Park",hours:"Gates open 7am–7:45pm (Apr–Labor Day); 7am–6:45pm (Labor Day–Mar)",bestTime:"Early morning for cooler temps; avoid after heavy rain (very muddy)",kidFriendly:true,talkStory:"Look for the WWII C-47 cargo plane wreck about midway through the loop — easy to miss if you're not watching for it. Trail is about 4.8 miles with gentle elevation. Dogs OK on leash. Combine with a visit to the Keaiwa Heiau (ancient Hawaiian healing temple) at the trailhead.",kamaaina:null},
  {name:"Aihualama Trail",tier:"B",lat:21.334,lng:-157.8047,category:"hike",subcategory:"moderate",tagline:"The trail that starts where Manoa Falls ends — climb up into the bamboo forest most people skip.",area:"Manoa",price:"Free",parking:"Use the Manoa Falls parking lot ($7 non-resident, free for residents) at 3739 Manoa Road",hours:"Open daily 8am-6pm",bestTime:"Morning when the bamboo forest is misty and magical",kidFriendly:false,talkStory:"About 2.5 miles one-way from the Manoa Falls trailhead with 900 ft elevation gain. The trail branches off just before Manoa Falls and switchbacks steeply up through dense bamboo forest to connect with the Pauoa Flats Trail. It's a completely different vibe from the busy falls trail — quiet, shaded, and you'll probably have it to yourself. The bamboo groves are stunning when the wind blows through them. You can loop it with Pauoa Flats and Nu'uanu Trail for a longer adventure. Muddy and slippery — always.",kamaaina:"Free parking with Hawaii state ID"},
  {name:"Crouching Lion Trail",tier:"B",lat:21.5455,lng:-157.841,category:"hike",subcategory:"ridge",tagline:"Short but steep scramble to a dramatic rock formation with panoramic views of Kahana Bay and the Ko'olau range.",area:"Windward Coast (Ka'a'awa)",price:"Free",parking:"Small pullout on Kamehameha Hwy near mile marker 27. Limited to 5-6 cars",hours:"Daylight hours",bestTime:"Early morning for cooler temps and better light. Trail gets full sun with no shade",kidFriendly:false,talkStory:"A short (~1 mile) but intense hike with steep, muddy sections and some rock scrambling near the top. The payoff is incredible — 360-degree views of Kahana Bay, the Ko'olau mountains, and the Windward Coast. The 'Crouching Lion' is a rock formation at the summit that resembles a lion in repose. The trail is not officially maintained and can be slippery when wet — wear shoes with good grip, not slippers. Not recommended for young kids due to steep drop-offs near the top. Trailhead can be hard to find — look for the worn path on the mauka (mountain) side of the highway across from Kahana Bay.",kamaaina:null},
  {name:"Diamond Head Summit",tier:"S",lat:21.2613,lng:-157.8047,category:"hike",subcategory:"sunrise",tagline:"Oahu's most iconic crater climb — tunnels, stairs, and 360-degree views that justify the hype.",area:"Waikiki",price:"$",parking:"$10/vehicle inside the crater; $5/person entry (reservations required)",hours:"Gate opens 6am; last entry 4pm",bestTime:"Sunrise — book the 6am slot weeks in advance; it sells out",kidFriendly:true,talkStory:"Reservations required at gostateparks.hawaii.gov — walk-ups are turned away. Bring a flashlight for the dark tunnel sections. About 1.6 miles round trip with 560 ft elevation gain and steep stairs near the top. Bring water — no shade. The 6am sunrise slot is magical but the 6:30am is nearly as good with shorter lines.",kamaaina:"Hawaii residents free entry with valid state ID; $5 parking (vs $10 non-resident)"},
  {name:"Ehukai Pillbox (Sunset)",tier:"A",lat:21.6634,lng:-158.0501,category:"hike",subcategory:"pillbox",tagline:"Watch pros surf Pipeline from a WWII bunker on the ridge — short, steep, and spectacular.",area:"North Shore",price:"Free",parking:"Street parking on Ke Nui Rd near Sunset Elementary",hours:"Sunrise to sunset (no gates)",bestTime:"Golden hour / sunset for best light; winter mornings to watch Pipeline surf from above",kidFriendly:false,talkStory:"Short but steep — about 15-20 minutes up. Two pillboxes; the second one at the summit has the best panoramic view. In winter you can watch the Pipe Masters competition from up here — bring binoculars. The trailhead is behind Sunset Elementary School.",kamaaina:null},
  {name:"Hau'ula Loop Trail",tier:"B",lat:21.6067,lng:-157.9068,category:"hike",subcategory:"moderate",tagline:"A lush windward ridge loop that most tourists never find — all the Norfolk pines and ocean views without the crowds.",area:"Hau'ula",price:"Free",parking:"Free lot at Hau'ula Homestead Road trailhead — small lot, maybe 10 cars",hours:"Open sunrise to sunset daily",bestTime:"Morning for the clearest views — afternoon clouds move in fast on the windward side",kidFriendly:true,talkStory:"This 2.5-mile loop gains about 600 ft of elevation and takes most people about 90 minutes. Go counterclockwise for the best experience — you get the steeper climb out of the way first and finish with the gentle ridge walk. Great views of La'ie and the windward coast. The Norfolk pine groves are beautiful and provide solid shade. A perfect 'easy day' hike when you want nature without the commitment.",kamaaina:null},
  {name:"Hawaii Loa Ridge Trail",tier:"A",lat:21.3035,lng:-157.7365,category:"hike",subcategory:"ridge",tagline:"A steep Ko'olau ridge climb through native forest that delivers summit-caliber views in under 3 miles.",area:"Hawaii Kai",price:"Free",parking:"Free parking inside the Hawaii Loa Ridge subdivision gate — the guard may ask where you're going, just say the trailhead",hours:"Open sunrise to sunset daily; subdivision gate hours may vary",bestTime:"Early morning for clear summit views and cooler temps on the exposed upper ridge",kidFriendly:false,talkStory:"About 5.5 miles round trip with 2,200 ft of elevation gain — it's a grunt. The trail climbs steeply through one of the last stands of native lowland forest on the Ko'olau Range, with koa, 'ohi'a, and native ferns. The upper ridge is narrow and exposed with views into Waimanalo and the windward coast. You'll need to pass through the Hawaii Loa Ridge residential area to reach the trailhead. The trail can be very muddy and slippery in the upper section. One of the best ridge hikes close to town for experienced hikers.",kamaaina:null},
  {name:"Judd Trail (Jackass Ginger Pool)",tier:"C",lat:21.3394,lng:-157.8166,category:"hike",subcategory:"easy",tagline:"A quick shady loop through Nu'uanu Valley with a hidden swimming hole the locals call Jackass Ginger.",area:"Nu'uanu",price:"Free",parking:"Free roadside parking along Nu'uanu Pali Drive near the trailhead — limited spots",hours:"Open sunrise to sunset daily",bestTime:"Midday when you want a quick shady escape from the heat",kidFriendly:true,talkStory:"Just under a mile loop with barely 100 ft elevation change — this is about as easy as it gets. The trail loops through a eucalyptus and Norfolk pine forest along Nu'uanu Stream. Jackass Ginger Pool is a popular mud-sliding and rope-swing spot for local kids, but swim at your own risk (leptospirosis concern in all freshwater). Great for a quick nature break if you're in the area, but don't drive across the island for it.",kamaaina:null},
  {name:"Ka'au Crater Trail",tier:"A",lat:21.311,lng:-157.782,category:"hike",subcategory:"advanced",tagline:"One of Oahu's most rewarding secret hikes — past three waterfalls to a volcanic crater rim with jaw-dropping panoramic views.",area:"Palolo Valley",price:"Free",parking:"Street parking on Waiomao Rd; respect residents",hours:"Daylight hours",bestTime:"Early morning on dry days; extremely dangerous when wet",kidFriendly:false,talkStory:"One of Oahu's most rewarding secret hikes takes you deep into the rainforest past three waterfalls and up to the rim of a dormant volcanic crater. The trail is steep, muddy, and not for beginners — but locals consider it one of the island's finest adventures. The final view from the crater rim, looking across the Ko'olau Range to the Windward side, is unforgettable. Bring gloves for rope sections and allow 5-6 hours round trip.",kamaaina:null},
  {name:"Ka'ena Point Trail",tier:"S",lat:21.5728,lng:-158.2357,category:"hike",subcategory:"coastal",tagline:"Oahu's raw western tip — monk seals laze on rocks and albatross nest where the island ends.",area:"Waianae",price:"Free",parking:"Free lot at end of Farrington Hwy past Yokohama Bay",hours:"Sunrise to sunset daily (no gates on the Waianae side)",bestTime:"Early morning to beat the heat; Nov–Jun for albatross nesting season",kidFriendly:false,talkStory:"Bring at least 2 liters of water per person — there is absolutely zero shade for the entire 5-mile round trip. Wear a hat and sun protection. The fenced sanctuary at the point protects nesting Laysan albatross and Hawaiian monk seals — stay behind the fence. Dolphins sometimes visible from the point. Do NOT attempt to swim here — the currents are extremely dangerous.",kamaaina:null},
  {name:"Kaipapa'u Gulch Trail",tier:"C",lat:21.595,lng:-157.912,category:"hike",subcategory:"moderate",tagline:"A quiet windward gulch hike through guava and kukui forest — you'll likely have the whole trail to yourself.",area:"Hau'ula",price:"Free",parking:"Free roadside parking along Hau'ula Homestead Road near the trailhead — very limited",hours:"Open sunrise to sunset daily",bestTime:"Morning for the best light filtering through the forest canopy",kidFriendly:false,talkStory:"About 4 miles round trip with 600 ft elevation gain through a lush gulch in the windward Ko'olaus. The trail parallels a stream and passes through stands of kukui nut, guava, and hau trees. It's not a destination hike — no big waterfall or summit — but the solitude and forest ambiance are the whole point. Trail can be overgrown in sections, so long pants are a good call. Combine with nearby Hau'ula Loop for a longer day. Mosquitoes are aggressive — repellent is non-negotiable.",kamaaina:null},
  {name:"Kamananui (Moanalua) Valley to Dam",tier:"C",lat:21.371,lng:-157.8652,category:"hike",subcategory:"easy",tagline:"A flat, shady valley walk perfect for families who want nature without the workout.",area:"Moanalua",price:"Free",parking:"Free parking at the Moanalua Valley Park trailhead off Moanalua Valley Road",hours:"Open sunrise to sunset daily",bestTime:"Any time of day — the valley stays cool and shaded",kidFriendly:true,talkStory:"About 3 miles round trip to the small dam with almost zero elevation gain — it's basically a nature walk along the valley floor. You'll cross the stream a few times on stepping stones and walk through mango, monkeypod, and kukui nut trees. The dam makes a good turnaround point for families. This is actually the start of the much longer Moanalua Valley Trail to the Ko'olau summit, but the easy valley portion is its own mellow experience. Great spot for a peaceful morning walk with keiki.",kamaaina:null},
  {name:"Kawainui Marsh",tier:"C",lat:21.3922,lng:-157.7426,category:"hike",subcategory:"easy",tagline:"Hawaii's largest freshwater marsh — flat, stroller-friendly, and a birder's paradise.",area:"Kailua",price:"Free",parking:"Free lot at Kaha Park on Kailua Rd",hours:"Open daily, sunrise to sunset",bestTime:"Early morning for best birdwatching; cooler temps",kidFriendly:true,talkStory:"Completely flat paved path — perfect for strollers, wheelchairs, and bikes. Look for endangered Hawaiian stilts (ae'o), moorhens, and coots. The boardwalk section over the marsh is the highlight. Combine with a Kailua Beach day — it's a 5-minute drive.",kamaaina:null},
  {name:"Kealia Trail",tier:"A",lat:21.5253,lng:-158.1835,category:"hike",subcategory:"ridge",tagline:"The best-kept-secret ridge trail on the North Shore — wide open views from Dillingham to the Waianae Mountains.",area:"Mokuleia",price:"Free",parking:"Free dirt pulloff on Farrington Highway past Dillingham Airfield — look for the trail marker on the mauka side",hours:"Open sunrise to sunset daily",bestTime:"Early morning — zero shade on this trail so you'll bake by 10am",kidFriendly:false,talkStory:"About 6 miles round trip with 2,000 ft elevation gain along a fully exposed ridge — bring at least 2 liters of water per person. The trail follows an old access road that switchbacks up the Waianae Range with insane views of the North Shore and Dillingham Airfield (you'll see skydivers below you). It connects to the Kuaokala Trail at the top for a longer adventure. One of the best sunset-facing ridge hikes if you time it right. Windy at the top — always.",kamaaina:null},
  {name:"Koko Crater Railway",tier:"S",lat:21.2886,lng:-157.6975,category:"hike",subcategory:"challenging",tagline:"1,048 railway ties straight up a crater — the most brutal 1.6-mile workout on the island.",area:"Hawaii Kai",price:"Free",parking:"Free parking at Koko Head District Park",hours:"Open 24 hours (no gates; parking lot at Koko Head District Park always accessible)",bestTime:"Pre-dawn start (bring headlamp) — avoid midday heat at all costs",kidFriendly:false,talkStory:"Bring a headlamp if starting before dawn — many locals do this as a sunrise workout. The bridge section near the top has a bypass trail to the left if you're not comfortable crossing the gap. Very exposed with zero shade — bring plenty of water. There's a small botanical garden in the crater at the top.",kamaaina:null},
  {name:"Koloa Gulch",tier:"B",lat:21.5815,lng:-157.9205,category:"hike",subcategory:"waterfall",tagline:"A rugged stream-walking adventure to a hidden waterfall deep in the windward mountains.",area:"Hau'ula",price:"Free",parking:"Limited roadside parking on Kamehameha Highway near the trailhead — be respectful of residential areas",hours:"Open sunrise to sunset daily",bestTime:"Dry conditions are critical — never attempt after heavy rain due to flash flood risk",kidFriendly:false,talkStory:"About 5 miles round trip with 800 ft of gradual elevation gain, but the distance is deceptive — you're walking IN the stream for most of it. Expect at least 20 stream crossings, slippery boulders, and overgrown sections. The reward is a beautiful multi-tiered waterfall in a narrow gulch. This trail requires real preparation: water shoes or canyoneering boots, trekking poles, and always check weather before going. Flash floods are a genuine danger here. Verify current trail access before heading out — the trailhead area borders private land.",kamaaina:null},
  {name:"Kuaokala Ridge Trail",tier:"A",lat:21.5369,lng:-158.2293,category:"hike",subcategory:"ridge",tagline:"A remote Waianae ridge trail with views that rival anything on the island — and almost no one there.",area:"Waianae",price:"Free",parking:"Free parking at the Kuaokala Game Management Area access road off Farrington Highway — the gate is sometimes locked, check DLNR for access",hours:"Open sunrise to sunset; access gate may be locked weekdays — check Hawaii DLNR schedule",bestTime:"Weekend mornings when the access gate is reliably open",kidFriendly:false,talkStory:"About 5 miles round trip along the Waianae Range with 1,500 ft elevation gain. The trail runs along the spine of the ridge with jaw-dropping views of Makua Valley on one side and the ocean on the other. This area is part of an Army/DLNR managed zone, so access can be limited — call ahead or check the DLNR website. When it's open, it's one of the most stunning ridge walks on Oahu. The trail connects to Kealia Trail for a much longer through-hike. Bring wind protection — it's exposed and breezy at the top.",kamaaina:null},
  {name:"Kuliouou Ridge Trail",tier:"A",lat:21.3132,lng:-157.7227,category:"hike",subcategory:"ridge",tagline:"The best beginner-friendly ridge hike on the island — panoramic Ko'olau views without the death-grip scrambles.",area:"Hawaii Kai",price:"Free",parking:"Free street parking on Kalaau Place in the Kuliouou residential area — arrive early on weekends or you'll be circling",hours:"Open sunrise to sunset daily",bestTime:"Early morning for cool temps and clear summit views before clouds roll in",kidFriendly:false,talkStory:"About 5 miles round trip with 1,800 ft of elevation gain — it's a steady climb but nothing technical. The switchbacks through the pine forest keep it shaded until you hit the exposed ridge at the top. On a clear day you can see from Koko Head to Kaneohe Bay. Bring plenty of water — there's zero shade for the last quarter mile. The Norfolk pine grove halfway up is a perfect rest spot.",kamaaina:null},
  {name:"La'ie Falls Trail",tier:"B",lat:21.6325,lng:-157.9275,category:"hike",subcategory:"waterfall",tagline:"A muddy, jungly adventure to a secluded North Shore waterfall most visitors never hear about.",area:"La'ie",price:"Free",parking:"Limited parking near the trailhead off Poohaili Street in La'ie — respect the residential neighborhood",hours:"Open sunrise to sunset daily",bestTime:"After light rain for waterfall flow, but not during or right after heavy rain",kidFriendly:false,talkStory:"About 5 miles round trip with 800 ft elevation gain through thick tropical vegetation. The trail follows an old irrigation ditch route and crosses multiple streams. The falls at the end are about 25 feet and drop into a decent pool. This trail is perpetually muddy — no getting around it. Wear shoes you're okay with destroying and bring mosquito repellent. The trail can be hard to follow in spots, so pay attention to trail markers. Check current access status before going — the trailhead passes near private land and access has been restricted at times.",kamaaina:null},
  {name:"Lanikai Pillbox",tier:"S",lat:21.3901,lng:-157.719,category:"hike",subcategory:"pillbox",tagline:"Two WWII bunkers over the Mokulua Islands — the most photogenic sunrise hike on the windward side.",area:"Kailua",price:"Free",parking:"Street parking on Kaelepulu Dr — arrive before sunrise to find a spot",hours:"Sunrise to sunset (no gates; unofficial trail on public land)",bestTime:"Sunrise — start 30 min before for the climb; the light over the Mokes is unbeatable",kidFriendly:false,talkStory:"The trailhead is at the end of Kaelepulu Dr behind a chain-link fence — look for the worn path. About 20-25 min to the first pillbox. The second pillbox is 10 min further with even better views. Trail is steep and rocky in spots — wear proper shoes, not slippers. After the hike, walk down to Lanikai Beach for a swim.",kamaaina:null},
  {name:"Likeke Falls",tier:"B",lat:21.3563,lng:-157.801,category:"hike",subcategory:"waterfall",tagline:"A short jungle scramble to a waterfall that feels way more remote than it actually is.",area:"Ko'olau",price:"Free",parking:"Park at the Ko'olau Golf Club lot off Pali Highway — the trail starts behind the maintenance area",hours:"Open sunrise to sunset daily",bestTime:"After rain for the best water flow — morning for fewer people",kidFriendly:false,talkStory:"About 2 miles round trip with 400 ft elevation change. The trail is short but scrappy — expect muddy sections, root tangles, and a couple stream crossings. The 15-ft waterfall at the end drops into a small pool surrounded by mossy rocks and jungle. Not as dramatic as Manoa Falls but way more private. You can connect this to the Old Pali Road trail for a longer loop. Wear shoes with grip and long pants — the overgrowth brushes against you the whole way.",kamaaina:null},
  {name:"Lyon Arboretum",tier:"B",lat:21.333,lng:-157.802,category:"hike",subcategory:"easy",tagline:"A 194-acre rainforest research garden in upper Manoa Valley — quiet trails, rare tropical plants, and the feel of deep jungle.",area:"Manoa",price:"Free (donations welcome)",parking:"Limited lot; arrive early or carpool",hours:"Mon-Fri 8am-4pm, Sat 9am-3pm",bestTime:"Weekday mornings for solitude; expect afternoon showers",kidFriendly:true,talkStory:"Operated by the University of Hawaii, this 194-acre botanical garden in upper Manoa Valley feels like a secret rainforest just minutes from the city. The trails wind through rare tropical plant collections, native Hawaiian species, and groves of towering trees. Far less crowded than nearby Manoa Falls, it offers a more immersive jungle experience. Reservations required — book online in advance.",kamaaina:null},
  {name:"Ma'ili Pillbox (Pink Pillbox)",tier:"B",lat:21.4175,lng:-158.1715,category:"hike",subcategory:"pillbox",tagline:"The West Side's colorful pillbox hike with sunset views that absolutely crush the East Side versions.",area:"Waianae",price:"Free",parking:"Free parking at the base trailhead on Ma'ili Point — small gravel lot",hours:"Open sunrise to sunset daily",bestTime:"Late afternoon for the best sunset — West Side faces the ocean sunset directly",kidFriendly:false,talkStory:"About 1.5 miles round trip with 500 ft of quick elevation gain — short and steep but totally doable for most people. The two pillboxes at the top are covered in colorful graffiti art (hence 'Pink Pillbox') and offer 360-degree views of the Waianae Coast, Makaha Valley, and the open ocean. This is the best sunset pillbox hike on Oahu, hands down — the sun drops right into the Pacific in front of you. The trail is steep and loose in spots, so wear proper shoes. Leeward side means it's almost always dry and sunny.",kamaaina:null},
  {name:"Makapu'u Lighthouse Trail",tier:"S",lat:21.3097,lng:-157.6512,category:"hike",subcategory:"coastal",tagline:"Fully paved and stroller-friendly with whale sightings Nov–May and dramatic ocean cliffs.",area:"Makapu'u",price:"Free",parking:"Free lot off Kalanianaole Hwy (fills by 9am weekends)",hours:"Sunrise to sunset daily (parking lot gate opens at sunrise)",bestTime:"Jan–Mar for peak whale watching; early morning to avoid heat and crowds",kidFriendly:true,talkStory:"Bring binoculars — humpback whales breach offshore Jan through Mar and you can spot them from multiple viewpoints along the trail. Fully paved and wheelchair/stroller accessible. About 2 miles round trip. No shade, so bring water and sunscreen. The tidepools below the lighthouse are worth the extra scramble down if conditions are calm.",kamaaina:null},
  {name:"Makiki Valley Loop",tier:"B",lat:21.326,lng:-157.8247,category:"hike",subcategory:"moderate",tagline:"Three trails stitched into one perfect loop through the lush valley behind Honolulu — the local's Manoa alternative.",area:"Makiki",price:"Free",parking:"Free parking at the Hawaii Nature Center on Makiki Heights Drive — lot fills by 9am on weekends",hours:"Open sunrise to sunset daily",bestTime:"Early morning for birdsong and cool temps — the canopy keeps it shady all day though",kidFriendly:true,talkStory:"The full Maunalaha-Makiki Valley-Ualaka'a loop is about 3 miles with 800 ft elevation gain. You'll walk through a tropical forest planted by the CCC in the 1930s — Cook pines, eucalyptus, and guava everywhere. The Moleka trailhead connector adds more views if you want to extend it. Way fewer people than Manoa Falls with the same jungle vibes. Trail can be slippery after rain, but it's well-maintained with good signage. The Hawaii Nature Center at the start is great for kids.",kamaaina:null},
  {name:"Manoa Falls",tier:"S",lat:21.3317,lng:-157.8003,category:"hike",subcategory:"waterfall",tagline:"A 150-ft jungle waterfall 15 minutes from Waikiki — Jurassic Park vibes are not an accident.",area:"Manoa",price:"$",parking:"$7 parking at 3739 Manoa Rd (the only lot)",hours:"Open daily 8am–6pm (last entry by 4:30pm); closed during flash flood warnings",bestTime:"Early morning for fewer crowds; after light rain for a fuller waterfall (but trail gets muddier)",kidFriendly:true,talkStory:"Wear closed-toe shoes — the trail is a mud pit 90% of the time. Bug spray is essential (Manoa valley mosquitoes are relentless). About 1.6 miles round trip, mostly flat with a gentle incline. Do NOT swim in the pool — falling rocks and leptospirosis risk. The Lyon Arboretum next door is a hidden gem for plant lovers.",kamaaina:"Hawaii residents park free with valid state ID"},
  {name:"Maunawili Demonstration Trail",tier:"A",lat:21.3534,lng:-157.7698,category:"hike",subcategory:"moderate",tagline:"A 10-mile one-way traverse through windward paradise — the best single-track on Oahu if you can arrange a car shuttle.",area:"Maunawili",price:"Free",parking:"Free parking at the Pali Highway trailhead (Nu'uanu side) or the Waimanalo trailhead on Kumuhau Street",hours:"Open sunrise to sunset daily",bestTime:"Start in the morning going Pali-to-Waimanalo to keep the sun at your back",kidFriendly:false,talkStory:"About 10 miles one-way (or do shorter out-and-back sections) with rolling elevation gains totaling about 1,600 ft. The trail contours along the Ko'olau foothills with constant views of windward Oahu — Kailua, Olomana, and the ocean. It's a well-maintained single-track that mountain bikers share, so stay alert on blind corners. Best done as a shuttle hike with a car at each end. The middle section has a few muddy patches year-round. Pack snacks — this is a 4-5 hour commitment at hiking pace.",kamaaina:null},
  {name:"Maunawili Falls",tier:"A",lat:21.3535,lng:-157.77,category:"hike",subcategory:"waterfall",tagline:"A 20-ft jungle cascade with a swimming hole and cliff-jump rock — best legal swim-at-falls on the windward side.",area:"Kailua",price:"Free",parking:"Very limited street parking at end of Kelewina St — arrive before 8am",hours:"Sunrise to sunset (no gates)",bestTime:"Early morning before 8am to get parking and beat crowds",kidFriendly:false,talkStory:"The trail is muddy and has multiple stream crossings — wear shoes you don't mind getting wet. About 3 miles round trip. The swimming hole at the base is the reward; there's a rock ledge people jump from (check depth first). Bring a waterproof bag for your phone. Mosquito repellent is a must.",kamaaina:null},
  {name:"Moanalua Valley Trail",tier:"A",lat:21.3638,lng:-157.8727,category:"hike",subcategory:"moderate",tagline:"A wild 10-mile valley-to-summit trek through stream crossings and native forest to the Ko'olau ridge.",area:"Moanalua",price:"Free",parking:"Free parking at the end of Moanalua Valley Road — the neighborhood gate is open during daylight hours",hours:"Open sunrise to sunset daily",bestTime:"Start early — this is a long day hike and you want to summit before afternoon clouds",kidFriendly:false,talkStory:"About 10 miles round trip with 2,600 ft elevation gain to the Ko'olau summit. Expect stream crossings (at least 12), muddy conditions year-round, and rope sections near the top. The valley itself is stunning with native plants and old taro patches. The Ko'olau summit views of windward Oahu are breathtaking. This is a full-day commitment — bring lunch, 3+ liters of water, and start by 7am. Not for casual hikers, but the reward at the top is unreal.",kamaaina:null},
  {name:"Old Pali Road",tier:"B",lat:21.3571,lng:-157.8044,category:"hike",subcategory:"easy",tagline:"A paved historic road reclaimed by the jungle — the easiest walk to dramatic Ko'olau cliff views.",area:"Nu'uanu",price:"Free",parking:"Park at the Pali Lookout parking lot ($7 non-resident, free for Hawaii IDs; reservations may be required for non-residents via gostateparks.hawaii.gov)",hours:"Open sunrise to sunset daily",bestTime:"Late afternoon when the light hits the cliffs — but expect wind at the lookout any time of day",kidFriendly:true,talkStory:"This is a 2-mile round trip flat walk on an old abandoned highway — perfect for anyone who wants dramatic scenery without breaking a sweat. The road is mostly paved but crumbling in spots with jungle growing through the cracks, which honestly makes it cooler. You'll pass through bamboo groves and banyan trees with killer views of the windward coast. It's also a significant Hawaiian historical site — the Battle of Nu'uanu was fought here. Super windy at the top, bring a light jacket.",kamaaina:"Free parking with Hawaii state ID"},
  {name:"Olomana Three Peaks",tier:"A",lat:21.3545,lng:-157.7702,category:"hike",subcategory:"challenging",tagline:"Oahu's most thrilling ridge scramble — first peak is earned, second is gutsy, third is borderline reckless.",area:"Maunawili",price:"Free",parking:"Free parking at the loop on Royal Hawaiian Golf Club access road off Auloa Road in Kailua",hours:"Open sunrise to sunset daily",bestTime:"Start at sunrise to beat the heat — the exposed ridgeline gets brutally hot by midday",kidFriendly:false,talkStory:"About 4.5 miles round trip to all three peaks with 1,600 ft elevation gain. Most people turn around after the first peak (1,643 ft) and honestly that's the smart move — the views are already incredible. Peaks two and three involve serious scrambling with rope assists and knife-edge ridges. People have died on this trail, no joke. Wear grippy shoes, bring gloves, and never go when it's wet. Not a trail to wing it on.",kamaaina:null},
  {name:"Pauoa Flats Trail",tier:"B",lat:21.346,lng:-157.813,category:"hike",subcategory:"moderate",tagline:"A misty forest trail to a rare flat overlook above Nu'uanu Valley — the trailhead most people walk right past.",area:"Tantalus",price:"Free",parking:"Free roadside parking along Tantalus Drive (Round Top Drive) near the trailhead",hours:"Open sunrise to sunset daily",bestTime:"Early morning when the mist hangs in the valley — bring a rain layer",kidFriendly:true,talkStory:"About 2 miles round trip with 500 ft of moderate climbing through native forest to Pauoa Flats — a rare level clearing in the Ko'olaus with views into Nu'uanu Valley and out to the Pali. The trail connects to Aihualama and Nu'uanu Trail for longer loops through the Tantalus trail network. It's well-maintained and shaded the whole way. The upper section has some of the best native Hawaiian forest accessible from Honolulu — look for 'ohi'a lehua and koa trees. Almost always cooler and wetter than town.",kamaaina:null},
  {name:"Pu'u Ma'eli'eli Trail",tier:"B",lat:21.3922,lng:-157.7514,category:"hike",subcategory:"pillbox",tagline:"Kailua's lesser-known pillbox hike with the same views and a fraction of the crowds.",area:"Kailua",price:"Free",parking:"Free street parking on Kapa'a Quarry Road near the trailhead",hours:"Open sunrise to sunset daily",bestTime:"Sunrise for golden light over Kailua Bay and the Mokulua Islands",kidFriendly:true,talkStory:"About 2.5 miles round trip with 600 ft of elevation gain — short but steep in spots. You'll pass three WWII bunkers along the ridge with panoramic views of Kailua, Kaneohe Bay, and the Ko'olau Range. Way less crowded than the Lanikai Pillbox and honestly the views are just as good. The trail is well-maintained with some rocky sections. There's a bonus loop option that extends the hike along the ridge. Locals come here for quick after-work sunset sessions.",kamaaina:null},
  {name:"Pu'u Ualaka'a (Tantalus Sunset)",tier:"A",lat:21.3134,lng:-157.8228,category:"hike",subcategory:"sunset",tagline:"The best free sunset view over Honolulu — Waikiki, Diamond Head, and Pearl Harbor all at once.",area:"Tantalus",price:"Free",parking:"Free lot (about 45 spaces)",hours:"Open 7am–6:45pm (Apr–Labor Day until 7:45pm)",bestTime:"Sunset — arrive 30 min before for parking and a good spot",kidFriendly:true,talkStory:"Drive up Round Top Dr — the winding road through the rainforest is scenic itself. Bring a light jacket, it's always windier and cooler up here than in town. Don't leave valuables visible in your car. The lookout is a short walk from the parking lot, not a real hike. Combine with the Makiki Valley Loop trail nearby if you want actual hiking.",kamaaina:null},
  {name:"Pupukea-Paumalu Trail (Ted Makalena)",tier:"C",lat:21.6536,lng:-158.061,category:"hike",subcategory:"easy",tagline:"A mellow North Shore forest walk through ironwoods and native plants — a breather between surf sessions.",area:"Pupukea",price:"Free",parking:"Free parking at the trailhead on Pupukea Road across from the Boy Scout Camp",hours:"Open sunrise to sunset daily",bestTime:"Any time — it's shaded and low-key",kidFriendly:true,talkStory:"About 2 miles of interconnected loop trails with minimal elevation change through a mix of ironwood, Cook pine, and native Hawaiian plants. This is a community-maintained trail system that's great for a casual nature walk, trail running, or mountain biking. Don't expect epic views — this is more of a forest bathing experience. Perfect for North Shore visitors who want a break from the beach. The trails can be confusing without a map — download the trail guide from Na Ala Hele before you go.",kamaaina:null},
  {name:"Wa'ahila Ridge Trail",tier:"B",lat:21.314,lng:-157.7975,category:"hike",subcategory:"ridge",tagline:"A proper ridge hike that starts right behind the University of Hawaii — lunch break adventure material.",area:"St. Louis Heights",price:"Free",parking:"Free parking at Wa'ahila Ridge State Recreation Area off Ruth Place — small lot, comes with restrooms and picnic tables",hours:"Open 7am to 7:45pm (Apr-Sep) or 7am to 6:45pm (Oct-Mar)",bestTime:"Late afternoon for golden hour light on the ridge — but start early enough to finish before gate closes",kidFriendly:false,talkStory:"About 5 miles round trip with 1,000 ft of elevation gain along a narrow ridge with views into both Manoa and Palolo valleys. The first mile through the ironwood and Cook pine forest is gentle, then it gets real — narrow ridgeline with drop-offs on both sides. The views of Diamond Head, Waikiki, and the Ko'olau Range are incredible. Trail is well-maintained by the state but gets slippery when wet. One of the best easily-accessible ridge hikes from town — students at UH hit this between classes.",kamaaina:null},
  {name:"Wahiawa Botanical Garden",tier:"C",lat:21.496,lng:-157.954,category:"hike",subcategory:"easy",tagline:"A free 27-acre tropical jewel in Central Oahu — lush ravine walks through native ferns and palms that feel primordial.",area:"Wahiawa / Central",price:"Free",parking:"Free lot on California Ave",hours:"Daily 9am-4pm",bestTime:"Mornings for the coolest temperatures and best light",kidFriendly:true,talkStory:"A free 27-acre botanical garden in Central Oahu along a deep ravine, featuring native Hawaiian plants, tropical ferns, and a palm garden that feels primordial. Far from any tourist path, the cool, shaded ravine walk feels like entering a different world. Locals come here for quiet walks and photography. Free admission, open daily.",kamaaina:null},
  {name:"Waimano Ridge Trail",tier:"B",lat:21.4207,lng:-157.9147,category:"hike",subcategory:"ridge",tagline:"A long, rewarding ridge hike through native forest to the Ko'olau summit — for hikers who want to earn their views.",area:"Pearl City",price:"Free",parking:"Free parking at the trailhead at the top of Waimano Home Road in Pacific Palisades",hours:"Open sunrise to sunset daily",bestTime:"Very early morning start — you need a full day for the summit push",kidFriendly:false,talkStory:"The full trail to the Ko'olau summit is about 14 miles round trip with 2,500 ft elevation gain — it's a serious full-day commitment. Most people do the first 3 miles to the swimming hole (Waimano Pool) as a moderate out-and-back. The ridge section beyond the pool gets progressively more rugged with native 'ohi'a forest and insane valley views. The final push to the summit is muddy, steep, and exposed but the windward-side views are worth every step. Bring headlamp as backup — easy to misjudge time on this one.",kamaaina:null},
  {name:"Waimea Valley Falls",tier:"A",lat:21.6398,lng:-158.06,category:"hike",subcategory:"waterfall",tagline:"The only place on Oahu where you can legally swim beneath a waterfall — botanical garden walk to boot.",area:"North Shore",price:"$$",parking:"Free lot at 59-864 Kamehameha Hwy",hours:"Daily 9am–4pm (last entry 3:30pm)",bestTime:"Weekday mornings for fewest crowds; after rain for a fuller waterfall",kidFriendly:true,talkStory:"Admission is $26/adult, $14/child (4-12). The paved path to the falls is fully stroller-friendly — about 0.75 miles each way through a lush botanical garden. Life vests are provided free for swimming at the falls (required). Bring water shoes for the rocky pool bottom. The garden itself has over 5,000 species of tropical plants. Combine with Waimea Bay across the street for a full North Shore day.",kamaaina:"Kamaaina rate ~$16/adult with valid Hawaii ID (vs $26 regular)"},
  {name:"Wiliwilinui Ridge",tier:"A",lat:21.299,lng:-157.7628,category:"hike",subcategory:"moderate",tagline:"The Ko'olau's best-kept ridge secret — pass through a gated community into native forest with panoramic views.",area:"East Honolulu",price:"Free",parking:"Limited spots — check in with security at the Waialae Iki gate on Okoa St",hours:"Daylight hours only; security gate staffed roughly 7am–6pm",bestTime:"Early morning for clear summit views (clouds roll in by midday)",kidFriendly:false,talkStory:"Must check in with security at the Waialae Iki neighborhood gate on Okoa St. About 4.5 miles round trip with 1,500 ft elevation gain — moderate to challenging. The Ko'olau ridge summit views of both windward and leeward Oahu are among the best on the island. Trail can be muddy and slippery — wear proper hiking shoes. Bring layers for the windy, cooler summit.",kamaaina:null},
  {name:"Ala Moana Beach Park Playground",tier:"A",lat:21.2889,lng:-157.8476,category:"kids",subcategory:"playground",tagline:"Huge playground right next to the calmest beach in Honolulu — the ultimate combo for families.",area:"Ala Moana",price:"Free",parking:"Free parking lot in the park (fills fast on weekends — arrive before 10am)",hours:"Park open 4am–10pm daily; playground always accessible during park hours",bestTime:"Weekday mornings for parking and shade; late afternoon for cooler play",kidFriendly:true,talkStory:"Perfect for ages 1-10. The playground has structures for toddlers and bigger kids with shade coverings. The real win is the beach — Ala Moana's reef-protected water is ankle-to-knee deep for a long way out, perfect for little ones. Pack a picnic, grab a spot under the trees, and you can easily spend a full day. Restrooms and outdoor showers on-site. The park has a paved path great for bikes and scooters too.",kamaaina:null},
  {name:"Bishop Museum",tier:"S",lat:21.3326,lng:-157.87,category:"kids",subcategory:"museum",tagline:"Hawaii's biggest museum with a world-class planetarium and a hands-on science center that rivals the mainland.",area:"Kalihi",price:"$$",parking:"Free parking on-site in museum lot",hours:"Wed–Mon 9am–5pm. Closed Tuesdays",bestTime:"Arrive at opening on a weekday; planetarium shows sell out so grab tickets first",kidFriendly:true,talkStory:"Best for ages 4 and up. The Science Adventure Center is the highlight for kids — erupting volcano model, giant insect displays, and interactive exhibits about Hawaii's natural history. The planetarium show is a must. The Hawaiian Hall with its three-story Victorian architecture teaches kids about Hawaiian culture. Allow 3-4 hours. Keiki under 4 are free.",kamaaina:"Kamaaina rate with Hawaii ID; membership pays for itself in 2-3 visits"},
  {name:"Coral Crater Adventure Park",tier:"B",lat:21.3198,lng:-158.074,category:"kids",subcategory:"adventure",tagline:"Ziplines, an aerial adventure course, and ATV rides inside a volcanic crater — an adrenaline rush for older keiki.",area:"Kapolei",price:"$$$",parking:"Free parking on-site",hours:"Daily 8am–4pm; book activities online in advance",bestTime:"Morning for cooler temps; weekdays for shorter waits on courses",kidFriendly:true,talkStory:"Best for ages 7 and up. The aerial adventure course has different difficulty levels so you can match to your kid's comfort. The zipline is a thrill for tweens and teens. Younger kids (4+) can do the junior course. Closed-toe shoes required. Bring water and sunscreen — it's hot and dry out in Kapolei. Combo packages save money if you want to do multiple activities.",kamaaina:"Kamaaina rates with Hawaii ID — check website for current local pricing"},
  {name:"Gunstock Ranch",tier:"B",lat:21.5802,lng:-157.895,category:"kids",subcategory:"adventure",tagline:"Horseback rides through the Koolau foothills with mountain and ocean views — pony rides for the little ones.",area:"Laie",price:"$$",parking:"Free parking on-site at the ranch",hours:"Mon–Sat 9am–4pm. Closed Sundays. Rides by reservation only",bestTime:"Morning rides for cooler weather and better mountain views before clouds build",kidFriendly:true,talkStory:"Pony rides available for ages 2-6. Regular trail rides for ages 7 and up. The 1-hour scenic ride through pastures with views of the Windward coast is the sweet spot for families. Closed-toe shoes required. The guides are friendly and great with nervous first-timers. Book ahead — they keep groups small. Located near Laie, so pair with a trip to the Polynesian Cultural Center or Hukilau Beach.",kamaaina:"Kamaaina rates available — mention when booking"},
  {name:"Hawaii Children's Discovery Center",tier:"B",lat:21.2936,lng:-157.8619,category:"kids",subcategory:"indoor-play",tagline:"Three-story interactive museum in Kakaako — hands-on exhibits that make learning feel like play.",area:"Kakaako",price:"$",parking:"Free lot on-site",hours:"Tue–Fri 9am–1pm, Sat–Sun 10am–3pm. Closed Mon",bestTime:"Weekday mornings for smallest crowds; great rainy-day option",kidFriendly:true,talkStory:"Best for ages 2-8. Three floors of themed exhibits — the Your Town floor with mini grocery store and fire truck is the biggest hit. Allow 2-3 hours. The Kakaako waterfront park next door is a nice add-on for burning off remaining energy. Check their website for special event days.",kamaaina:"Kamaaina rate available with Hawaii ID; check website for current pricing"},
  {name:"Hawaii Plantation Village",tier:"C",lat:21.3925,lng:-158.0136,category:"kids",subcategory:"museum",tagline:"Walk through restored plantation-era homes and learn how Hawaii's multicultural identity was built.",area:"Waipahu",price:"$",parking:"Free parking on-site",hours:"Mon–Sat 10am–2pm. Closed Sundays. Guided tours at 10am, 11am, 12pm, 1pm",bestTime:"First tour at 10am is least crowded and cooler",kidFriendly:true,talkStory:"Best for ages 6 and up — younger kids may not engage with the history. The guided tour walks through homes representing eight different ethnic groups that worked the sugar plantations. Older kids interested in Hawaii history will find it fascinating. About 1-1.5 hours total. A good educational stop near the Waipahu area. The gift shop has unique local items. Pair with a drive through old Waipahu town for lunch.",kamaaina:"Kamaaina rate with Hawaii ID"},
  {name:"Honolulu Zoo Keiki Zoo",tier:"A",lat:21.2711,lng:-157.8214,category:"kids",subcategory:"farm",tagline:"Walk right into the goat pen — mini goats, baby sheep, pigs, ponies, and alpaca.",area:"Waikiki",price:"$",parking:"Street parking on Kapahulu Ave or metered lots nearby",hours:"Daily 9am–4:30pm (zoo gates close at 4pm)",bestTime:"Weekday mornings — animals are most active and crowds are thin",kidFriendly:true,talkStory:"The Keiki Zoo petting area is in the back left of the zoo — head there first before it gets crowded. The whole zoo is walkable in 2-3 hours. Combine with a picnic at Kapiolani Park right next door and a walk to Waikiki Beach. 151 Kapahulu Ave. Twilight Tours on select evenings are a unique experience.",kamaaina:"Kamaaina: $8/adult, $4/child (vs $19/$11 non-resident) with valid Hawaii ID"},
  {name:"Hoomaluhia Botanical Garden",tier:"A",lat:21.389,lng:-157.8023,category:"kids",subcategory:"nature",tagline:"400 acres of lush gardens backed by the Koolau cliffs — free admission and the most photogenic spot on Oahu.",area:"Kaneohe",price:"Free",parking:"Free parking at visitor center and multiple lots throughout the garden",hours:"Daily 9am–4pm. Closed Christmas & New Year's Day",bestTime:"Early morning for misty mountain views and cooler temps; weekdays to avoid weekend crowds",kidFriendly:true,talkStory:"Great for all ages. Drive through the garden and stop at various sections — kids love the lake area for catch-and-release fishing (free poles available on weekends). The wide paved paths are stroller-friendly. Bring mosquito repellent, snacks, and rain jackets — it's Windward side so expect passing showers. The iconic Koolau mountain backdrop from the entrance road is the most Instagrammed spot on Oahu.",kamaaina:null},
  {name:"Kahuku Farms",tier:"B",lat:21.6811,lng:-157.9503,category:"kids",subcategory:"farm",tagline:"A real working farm on the North Shore with tractor tours, fruit tastings, and the best acai bowl on the island.",area:"North Shore",price:"$",parking:"Free parking on-site along the farm road",hours:"Wed–Mon 10am–4pm. Closed Tuesdays",bestTime:"Late morning for farm tours; the cafe gets a long line at lunch so go early or late",kidFriendly:true,talkStory:"Good for ages 2 and up. The farm tour on a tractor-pulled wagon takes about 40 minutes — kids get to taste fresh fruit right off the trees (lilikoi, papaya, banana, whatever is in season). The cafe's smoothies, acai bowls, and grilled banana bread are legendary. Bring cash as backup. Short and sweet visit — about 1-2 hours total. Great stop on a North Shore loop day.",kamaaina:null},
  {name:"Kakaako Waterfront Park",tier:"B",lat:21.2912,lng:-157.8633,category:"kids",subcategory:"playground",tagline:"Grassy slopes for rolling, ocean views, and open space for running — a simple, free park locals love.",area:"Kakaako",price:"Free",parking:"Free parking lot on-site",hours:"Daily 7am–7:45pm (gates lock at closing)",bestTime:"Late afternoon for ocean breezes and sunset views; weekday mornings for fewer people",kidFriendly:true,talkStory:"Good for all ages. The grassy hill is the main attraction for kids — they'll roll down it for hours. Great kite-flying spot when trade winds are up. No playground equipment, but the open space is perfect for balls, frisbees, and picnics. Pair with a visit to the Children's Discovery Center right across the street. No swimming — the rocky shoreline is for looking only. Restrooms available.",kamaaina:null},
  {name:"Kaneohe Sandbar (Ahu o Laka)",tier:"A",lat:21.4622,lng:-157.806,category:"kids",subcategory:"nature",tagline:"A sandbar in the middle of Kaneohe Bay where you stand in knee-deep turquoise water with the Koolaus as backdrop.",area:"Kaneohe",price:"$$",parking:"Park at Heeia Kea Boat Harbor; various tour operators depart from here",hours:"Tour operators run morning and afternoon trips; sandbar accessible during low tide",bestTime:"Low tide for maximum sandbar exposure; morning trips for calmer water and better light",kidFriendly:true,talkStory:"Good for ages 2 and up. At low tide, the water is shin-deep on the sandbar — perfect for toddlers to splash around safely. Bring your own kayak or SUP to save money, or book a boat tour that includes gear. The views of Chinaman's Hat and the Koolau Mountains from the sandbar are unreal. Bring reef-safe sunscreen, snacks, and a pop-up shade if you have one. Check tide charts before you go — at high tide the sandbar disappears.",kamaaina:"Some tour operators offer kamaaina rates — ask when booking"},
  {name:"Kapiolani Park Playground",tier:"A",lat:21.2692,lng:-157.8152,category:"kids",subcategory:"playground",tagline:"Huge banyan-shaded playground steps from Waikiki — the go-to for hotel families who need a playground break.",area:"Waikiki",price:"Free",parking:"Free parking along Monsarrat Ave and park side streets; metered spots on Kalakaua",hours:"Open 24 hours (playground best during daylight)",bestTime:"Mornings or late afternoon for shade and cooler temps; weekdays for less crowds",kidFriendly:true,talkStory:"Great for ages 1-8. The playground sits under massive banyan trees that provide natural shade — huge win in Hawaii heat. Multiple play structures for different age groups. The surrounding park is perfect for bike riding, picnics, and kite flying. Saturday mornings have a farmers market at KCC nearby. Walk to the zoo, aquarium, or beach in minutes. Restrooms available in the park. Bring a blanket for lounging while keiki play.",kamaaina:null},
  {name:"Keiki and the Plow",tier:"A",lat:21.2934,lng:-157.7108,category:"kids",subcategory:"farm",tagline:"U-pick veggies, mud kitchens, goats, and a pirate ship — a rare working farm open to families.",area:"Hawaii Kai",price:"$",parking:"Small lot at 587 Pakala St, Hawaii Kai",hours:"Saturdays 9–11am only",bestTime:"Arrive right at 9am — it fills up fast and the 2-hour window goes quickly",kidFriendly:true,talkStory:"Only open Saturdays 9-11am so plan accordingly. Kids can pick vegetables, play in the mud kitchen, feed goats, and climb the pirate ship structure. Wear clothes you don't mind getting dirty — mud is part of the fun. Bring a change of clothes and towel for the car. A truly unique Oahu experience most tourists never find.",kamaaina:null},
  {name:"Kolowalu Park Playground",tier:"B",lat:21.2969,lng:-157.8619,category:"kids",subcategory:"playground",tagline:"Oahu's first inclusive playground — ramps, sensory panels, accessible swings for every kid.",area:"Kakaako",price:"Free",parking:"Free parking at Ward Village",hours:"Dawn to dusk",bestTime:"Late afternoon when it cools down; mornings on weekends before it gets busy",kidFriendly:true,talkStory:"Fully ADA-accessible with ramps, sensory panels, and adaptive swings — one of the only playgrounds on the island designed for kids of all abilities. Dog park right next door if you have a pup. Located in Ward Village, Kakaako — combine with lunch at one of the nearby restaurants. Rubber ground surface stays cooler than sand playgrounds.",kamaaina:null},
  {name:"Kualoa Ranch",tier:"S",lat:21.5213,lng:-157.8377,category:"kids",subcategory:"adventure",tagline:"Jurassic Valley ATV tours, horseback rides, and ziplines on a working cattle ranch — where they filmed Jurassic Park.",area:"Kualoa",price:"$$$",parking:"Free parking on-site",hours:"Daily 7:30am–5:30pm; tours run on set schedules — book online in advance",bestTime:"Morning tours have better light for Kualoa Valley photos and cooler temps",kidFriendly:true,talkStory:"Different activities for different ages: the Jurassic Valley bus tour is good for all ages including toddlers. Horseback riding starts at age 10, ATV at age 16 (or ride as passenger). The Secret Island beach is great for younger keiki — calm water and kayaks included. Book the combo packages for best value. Bring sunscreen and closed-toe shoes for most activities.",kamaaina:"Kamaaina rates available with valid Hawaii ID — significant discount on tour packages"},
  {name:"Makapuu Tide Pools",tier:"A",lat:21.3107,lng:-157.6512,category:"kids",subcategory:"nature",tagline:"Natural lava rock tide pools teeming with sea life — free outdoor aquarium for curious keiki.",area:"East Oahu",price:"Free",parking:"Park at Makapuu Lookout lot (free) or along Kalanianaole Hwy near the pools",hours:"Open 24 hours; best during daylight at low tide",bestTime:"Low tide is essential — check tide charts. Morning for calmer conditions and fewer people",kidFriendly:true,talkStory:"Best for ages 3 and up with close supervision. At low tide, the lava rock pools trap small fish, crabs, sea urchins, and anemones — kids can observe but remind them to look and not touch. Wear reef shoes — the rocks are sharp and slippery. The access path is rocky and uneven, not stroller-friendly. Bring a mesh bag for treasures to look at and return. Check surf conditions — stay away when waves are big. A quick, free nature experience on the east side.",kamaaina:null},
  {name:"Manoa Falls Trail",tier:"A",lat:21.333,lng:-157.8021,category:"kids",subcategory:"nature",tagline:"A short, shaded rainforest hike to a 150-foot waterfall — doable for most keiki and absolutely magical.",area:"Manoa",price:"Free",parking:"$7 paid parking lot at trailhead; fills up by 10am on weekends",hours:"Open sunrise to sunset daily; gate closes at 6pm",bestTime:"Early morning on weekdays; trail gets muddy after rain but the waterfall is more impressive",kidFriendly:true,talkStory:"Good for ages 4 and up (or carry younger ones). The trail is 1.6 miles round trip through a bamboo and banyan rainforest — feels like Jurassic Park. It's muddy, so wear shoes you don't mind getting dirty. Mosquito repellent is essential. Do not swim in the pool at the base — leptospirosis risk. Bring a light rain jacket. The Lyon Arboretum next door is a nice add-on if kids have energy left.",kamaaina:null},
  {name:"Pearl Harbor Aviation Museum",tier:"A",lat:21.3545,lng:-157.9726,category:"kids",subcategory:"museum",tagline:"Real WWII planes in original hangars on Ford Island — the flight simulators are a huge hit with older kids.",area:"Pearl Harbor",price:"$$",parking:"Park at Pearl Harbor Visitor Center; shuttle bus to Ford Island included with admission",hours:"Daily 9am–5pm (last entry 4pm). Closed Thanksgiving, Christmas, New Year's",bestTime:"Weekday mornings; pair with the free USS Arizona Memorial visit",kidFriendly:true,talkStory:"Best for ages 6 and up. Two original WWII hangars filled with restored planes you can get close to — the Japanese Zero and the B-25 bomber are jaw-droppers. The combat flight simulators ($) are the highlight for most kids. The museum tells the Pearl Harbor story in a way kids can grasp. Combine with the free USS Arizona Memorial and plan a full morning. No bags larger than a purse allowed at Pearl Harbor — leave them in the car.",kamaaina:"Kamaaina discount with Hawaii ID"},
  {name:"Polynesian Cultural Center",tier:"S",lat:21.6397,lng:-157.9227,category:"kids",subcategory:"museum",tagline:"Six island villages, canoe rides, fire-knife dancing, and a luau — the best cultural experience on Oahu for families.",area:"Laie",price:"$$$",parking:"Free parking on-site",hours:"Mon–Sat 12:30pm–9pm. Closed Sundays",bestTime:"Arrive at opening to see all six villages before the evening show; weekdays for smaller crowds",kidFriendly:true,talkStory:"Good for ages 4 and up. Kids get to throw spears, learn hula, paddle canoes, and try coconut husking across six Polynesian island villages. The evening luau and Ha: Breath of Life show with fire-knife dancing is the grand finale — kids are mesmerized. It's a full-day commitment (6+ hours) so plan accordingly. Bring comfortable walking shoes. The all-inclusive packages with dinner and show are the best value. Closed Sundays.",kamaaina:"Kamaaina annual pass and discounted packages available with Hawaii ID"},
  {name:"Sea Life Park Hawaii",tier:"B",lat:21.3129,lng:-157.6594,category:"kids",subcategory:"aquarium",tagline:"Dolphin shows, sea lion encounters, and a huge reef tank right at Makapuu — touristy but the keiki love it.",area:"Waimanalo",price:"$$$",parking:"Free parking lot on-site",hours:"Daily 10am–4pm; check website for seasonal hours",bestTime:"Arrive at opening to catch the first dolphin show with fewer crowds",kidFriendly:true,talkStory:"Best for ages 3-12. The dolphin and sea lion shows keep kids glued. The bird sanctuary walkthrough and the reef tank viewing area are included with admission. Swim-with-dolphin programs book out fast — reserve weeks ahead. Bring reef-safe sunscreen and hats, there's limited shade. Combine with a drive to Makapuu Lookout right next door.",kamaaina:"Kamaaina annual pass is a solid deal if you go more than twice a year"},
  {name:"Turtle Bay Resort Pool & Beach",tier:"B",lat:21.7079,lng:-157.9978,category:"kids",subcategory:"splash-pad",tagline:"Day passes let you use the resort pool with waterslide, plus walk to calm Kuilima Cove for baby turtles.",area:"North Shore",price:"$$",parking:"Free self-parking for day-pass guests",hours:"Pool open 8am–8pm daily; day passes available based on capacity",bestTime:"Weekday mornings for pool space; late afternoon for turtle sightings at the cove",kidFriendly:true,talkStory:"Great for all ages. The pool has a waterslide and shallow kids area. But the real gem is Kuilima Cove — a sheltered bay where green sea turtles hang out regularly and the water is calm enough for toddlers. Bring your own snorkel gear for the older kids. Day passes include pool, beach access, and beach equipment. Reserve ahead on weekends — they cap the number. Worth the drive up to the North Shore.",kamaaina:"Kamaaina day rates available — call ahead for current pricing and availability"},
  {name:"Wai Kai Splash Pad",tier:"B",lat:21.3117,lng:-158.0236,category:"kids",subcategory:"splash-pad",tagline:"West Oahu's waterfront splash zone with floating obstacle course — worth the drive for a full day.",area:"Ewa Beach",price:"$",parking:"Free lot at 91-1621 Keoneula Blvd",hours:"Mon–Thu 10am–8pm, Fri–Sat 10am–9pm, Sun 10am–7pm (seasonal; check website)",bestTime:"Weekday mornings for the least crowds; bring sunscreen for the outdoor areas",kidFriendly:true,talkStory:"The splash pad area is great for toddlers while older kids love the floating obstacle course on the lagoon. Multiple dining options on-site so you can make it a full day. Check their website for seasonal hours and pricing — activities are priced separately. About 30 min from Waikiki.",kamaaina:"Kamaaina rates available with valid Hawaii ID; check website for current pricing"},
  {name:"Waikiki Aquarium",tier:"A",lat:21.2658,lng:-157.8216,category:"kids",subcategory:"aquarium",tagline:"The third-oldest aquarium in the US, right on the Waikiki shoreline — small enough to not overwhelm little ones.",area:"Waikiki",price:"$",parking:"Limited street parking on Kalakaua Ave; paid lot at Kapiolani Park nearby",hours:"Daily 9am–5pm (last entry 4:30pm). Closed Thanksgiving & Christmas",bestTime:"Weekday mornings for fewest crowds; feeding times posted at entrance",kidFriendly:true,talkStory:"Perfect for ages 1-10. Small and manageable — you can do the whole thing in about an hour, which is ideal for short attention spans. The outdoor monk seal exhibit and the giant clam tank are the biggest kid magnets. The touch pool lets keiki handle sea cucumbers and hermit crabs. Combine with a walk along the adjacent shoreline trail to Sans Souci Beach.",kamaaina:"Kamaaina rate with Hawaii ID — significantly cheaper than regular admission"},
  {name:"Waimanalo Country Farms",tier:"B",lat:21.346,lng:-157.718,category:"kids",subcategory:"farm",tagline:"Seasonal pumpkin patch, corn maze, and farm activities on a real Waimanalo farm — fall is the best time.",area:"Waimanalo",price:"$",parking:"Free parking in the farm field lot",hours:"Seasonal — typically open Oct–Nov for pumpkin season, check website/social media for dates",bestTime:"Weekday mornings during pumpkin season for shortest lines; arrive at opening on weekends",kidFriendly:true,talkStory:"Best for ages 2-10. The fall pumpkin festival is the main draw — corn maze, hayrides, petting zoo, pumpkin picking, and local food vendors. It's a beloved Oahu fall tradition for local families. Lines get long on weekends so go early or on weekdays. Bring cash for food vendors. Wear closed-toe shoes — it's a working farm and gets muddy. They also do a smaller spring festival some years. Follow their Instagram for dates and hours.",kamaaina:null},
  {name:"Waimea Valley",tier:"A",lat:21.636,lng:-158.0508,category:"kids",subcategory:"nature",tagline:"A paved botanical walk through sacred Hawaiian valley ending at a swimmable waterfall — North Shore magic.",area:"North Shore",price:"$$",parking:"Free parking lot at entrance across from Waimea Bay",hours:"Daily 9am–4pm (last admission 3:30pm)",bestTime:"Morning on weekdays; the waterfall pool is calmest and least crowded before noon",kidFriendly:true,talkStory:"Great for ages 2 and up. The 0.75-mile paved path to the waterfall is fully stroller-friendly — rare for a nature walk in Hawaii. Life jackets provided free at the falls for swimming. The botanical gardens along the way have peacocks roaming freely that kids go wild for. Bring water shoes for the rocky pool bottom. Pack snacks — the on-site cafe is limited. Combine with a stop at Waimea Bay Beach across the street.",kamaaina:"Kamaaina rate with Hawaii ID; kids 4-12 discounted, under 4 free"},
  {name:"Wet 'n' Wild Hawaii",tier:"A",lat:21.3343,lng:-158.086,category:"kids",subcategory:"splash-pad",tagline:"26 rides including Keiki Kove splash zone — the full water park experience on the island.",area:"Kapolei",price:"$$",parking:"Free parking at 400 Farrington Hwy, Kapolei",hours:"Daily from 10:30am (closing time varies seasonally)",bestTime:"Weekdays for shorter lines; arrive at opening for the first hour with no waits",kidFriendly:true,talkStory:"~$50/adult, ~$38/kids — book online for 10% off. Keiki Kove is perfect for toddlers while older kids hit the big slides. Bring your own towels and sunscreen (rentals and shop are overpriced). Lockers available but bring a waterproof pouch for your phone. Food is pricey inside — eat a big breakfast before. Allow a full day, especially with kids.",kamaaina:"Kamaaina annual passes and discounted day rates with valid Hawaii ID"},
  {name:"Aloha Stadium Swap Meet",tier:"A",lat:21.3728,lng:-157.93,category:"market",subcategory:"flea-market",tagline:"Hawaii's iconic outdoor flea market with 400+ vendors — relocated to the upper Halawa lot while the new stadium is built.",area:"Aiea",price:"$",mustOrder:[],parking:"Park in the lower lot, enter through the Halawa gate. Parking is CASH ONLY",talkStory:"A local institution since the 1970s. The old stadium was demolished in 2025 for the New Aloha Stadium Entertainment District (opening 2029), but the swap meet relocated to the upper Halawa parking lot in October 2025 with improvements — repaved areas, centralized vendors, dedicated food truck section, big-top tent with live music, and modern restrooms. Over 400 vendors selling everything from aloha shirts and local crafts to fresh produce and plate lunches. Great for cheap souvenirs that aren't tourist-trap quality. The swap meet will stay at this location for 5-10 years during construction.",cashOnly:false,kamaaina:"Kamaaina/military admission $1 with valid ID (general admission $2). Kids 11 and under free"},
  {name:"H Mart Keeaumoku",tier:"A",lat:21.295,lng:-157.839,category:"market",subcategory:"korean-grocery",tagline:"Massive Korean grocery with an incredible hot food bar, live seafood counter, and Hawaii-exclusive frozen treats.",area:"Ala Moana",price:"$$",mustOrder:["Korean fried chicken","tteokbokki","poke"],parking:"Paid garage at Keeaumoku shopping area",talkStory:"The largest Korean grocery chain in America has a massive Honolulu location that locals treat as both grocery store and food court. The hot food bar has incredible Korean fried chicken, japchae, and tteokbokki. The banchan section is enormous, and the fresh seafood counter sells live crab and whole fish. Check the freezer section for Hawaiian-exclusive flavors of Korean ice cream bars. Weekday afternoons are best; weekends are packed.",cashOnly:false,kamaaina:null},
  {name:"Marukai Wholesale Mart",tier:"A",lat:21.335,lng:-157.862,category:"market",subcategory:"japanese-grocery",tagline:"Hawaii's first warehouse-style Japanese market — fresh bentos, sushi counters, and Japanese snacks you can't find anywhere else.",area:"Kalihi",price:"$",mustOrder:["daily bento box","poke","sushi rolls"],parking:"Free lot",talkStory:"Marukai is a Japanese discount warehouse that locals have relied on for decades. The daily bento selection is legendary — arrive before lunch for the widest variety of freshly made boxes. The poke and sushi counters rival dedicated restaurants at a fraction of the price. Stock up on Japanese snacks, kitchenware, and specialty ingredients you won't find at Safeway. Membership not required for food purchases.",cashOnly:false,kamaaina:null},
  {name:"Nijiya Market",tier:"B",lat:21.2885,lng:-157.842,category:"market",subcategory:"japanese-grocery",tagline:"Boutique Japanese grocery with impeccable quality sushi, onigiri, and hard-to-find Japanese ingredients.",area:"Ala Moana",price:"$$",mustOrder:["fresh onigiri","chirashi bowl","mochi"],parking:"Shared lot at Ala Moana area",talkStory:"Nijiya is a smaller, more curated Japanese grocery that locals love for its quality over quantity approach. The prepared foods section has restaurant-quality sushi, onigiri, and bento boxes. The produce is pristine and the Japanese snack aisle is a treasure hunt. Less overwhelming than Marukai but the quality is consistently higher. The freshly made onigiri are a perfect quick lunch.",cashOnly:false,kamaaina:null},
  {name:"Palama Supermarket",tier:"B",lat:21.321,lng:-157.861,category:"market",subcategory:"korean-grocery",tagline:"Hawaii's favorite Korean grocery — legendary banchan counter, fresh kimchi, and hot plate lunches that rival any restaurant.",area:"Kalihi",price:"$",mustOrder:["banchan assortment","fresh kimchi","plate lunch"],parking:"Free lot on N King St",talkStory:"Palama is where local Korean and mixed-plate families do their serious grocery shopping. The banchan counter is the star — fill a container with a dozen different Korean side dishes for just a few dollars. The in-house kimchi is made fresh and the hot plate lunches rival dedicated restaurants. The produce section has exceptional quality at prices that beat the big chains. Weekday mornings are best; weekends get packed.",cashOnly:false,kamaaina:null},
  {name:"Tamashiro Market",tier:"S",lat:21.3193,lng:-157.8638,category:"market",subcategory:"fish-market",tagline:"Honolulu's most trusted fish market for over 80 years — where local families buy poke and fresh seafood for parties.",area:"Kalihi",price:"$$",mustOrder:["shoyu ahi poke","spicy tako poke","poke plate"],parking:"Small lot in front; street parking on N King St",talkStory:"Open since the 1940s, Tamashiro Market is a Kalihi institution. The poke counter has a dozen varieties daily — shoyu ahi, spicy tako, limu, and seasonal specials. Come Saturday morning before 10am for the best selection; by noon, the popular cuts are gone. Locals grab a styrofoam plate and eat standing in the parking lot. The fish counter also sells whole fish, sashimi-grade blocks, and shellfish at prices well below supermarkets.",cashOnly:false,kamaaina:null},
  {name:"Anna O'Brien's",tier:"B",lat:21.29,lng:-157.82,category:"nightlife",subcategory:"live-music-venue",tagline:"Honolulu's quintessential dive bar since 1969 — live rock, reggae, and punk upstairs, sticky-floor charm downstairs.",area:"Mo'ili'ili",price:"$",mustOrder:["cheap beer"],parking:"Street parking on Beretania St",talkStory:"Open since 1969, this is Honolulu's quintessential dive bar — home to motorcycle clubs, rugby teams, musicians, and blue-collar workers. The upstairs stage hosts live music most nights (rock, reggae, punk) with modest or no cover charge. The downstairs bar is dark, sticky, and wonderful. Locals consider it an institution. Thursday-Saturday nights for live music; upstairs for the bands, downstairs for the dive bar atmosphere.",cashOnly:false,kamaaina:null},
  {name:"Bar Leather Apron",tier:"S",lat:21.309,lng:-157.86,category:"nightlife",subcategory:"cocktail-bar",tagline:"One of the world's best cocktail bars hidden on a downtown Honolulu mezzanine — 15 seats, Japanese technique, local ingredients.",area:"Downtown",price:"$$$",mustOrder:["bartender's choice cocktail","old fashioned with Hawaiian honey"],parking:"Street parking; paid lot nearby",talkStory:"Hidden on the mezzanine of the TOPA Financial Center, this tiny bar was named one of the best in the world. With only about 15 seats, it feels like a private club. Bartenders Justin Park and Tom Park create immaculate craft cocktails using house-made syrups, local ingredients, and Japanese technique. Reserve in advance online. Go early in the week for a more intimate experience. This is where Honolulu's cocktail cognoscenti drink.",cashOnly:false,kamaaina:null},
  {name:"Bevy",tier:"B",lat:21.295,lng:-157.856,category:"nightlife",subcategory:"cocktail-bar",tagline:"Artsy Kakaako cocktail bar doubling as a gallery — creative drinks, locally sourced small plates, and rotating local art.",area:"Kakaako",price:"$$",mustOrder:["signature cocktail","small plates"],parking:"Street parking in Kakaako",talkStory:"An artsy cocktail bar in Kakaako that doubles as an art gallery with rotating exhibitions from local artists. The cocktails are creative and the food menu, focused on small plates and locally sourced ingredients, is consistently good. Locals come for after-work drinks at happy hour (4-6pm) and the weekend brunch cocktail menu is a neighborhood ritual.",cashOnly:false,kamaaina:null},
  {name:"Hana Koa Brewing Co.",tier:"A",lat:21.296,lng:-157.856,category:"nightlife",subcategory:"brewery",tagline:"Oahu's best brewery in a converted Coca-Cola factory — tropical IPAs, spacious beer garden, and rotating food pop-ups.",area:"Kakaako",price:"$$",mustOrder:["Kolsch","tropical IPA","rotating seasonal"],parking:"Street parking in Kakaako; some lot spaces",talkStory:"Occupying a converted Coca-Cola syrup factory in Kakaako, Hana Koa is widely considered the best brewery on Oahu. The spacious industrial taproom serves excellent locally brewed beers — from tropical IPAs to dark stouts — along with a creative food menu. The Kolsch and the IPA are the standouts. Thursday-Saturday evenings are liveliest; check for food truck pop-ups. Local families come for the beer garden atmosphere.",cashOnly:false,kamaaina:null},
  {name:"La Mariana Sailing Club",tier:"S",lat:21.315,lng:-157.874,category:"nightlife",subcategory:"tiki-bar",tagline:"Hawaii's original tiki bar since 1957 — hidden in an industrial marina with museum-worthy tiki artifacts and strong mai tais.",area:"Sand Island",price:"$$",mustOrder:["mai tai","blue hawaii"],parking:"Free lot at the marina",talkStory:"Hawaii's original tiki bar since 1957, hidden in an industrial marina you'd never find unless you knew it was there. The interior is a living museum of tiki culture — puffer fish lamps from the original Trader Vic's, rattan chairs from Don the Beachcomber, and hand-carved tikis from the old Kon Tiki Room. The mai tais are strong and the live music on Friday evenings sets a wonderfully retro mood. Founder Annette La Mariana originally charged $2 membership and 50-cent boat slips.",cashOnly:false,kamaaina:null},
  {name:"Smith's Union Bar",tier:"A",lat:21.311,lng:-157.8615,category:"nightlife",subcategory:"dive-bar",tagline:"Honolulu's oldest bar (1935) — cheap beers, great jukebox, and the unpretentious soul of Chinatown nightlife.",area:"Chinatown / Downtown",price:"$",mustOrder:["cheap beer","whatever's on tap"],parking:"Street parking; walk from downtown",talkStory:"Established in 1935, Smith's is a no-frills dive where beers are cheap and the jukebox has a great selection. The crowd is a mix of old-timers, off-duty chefs, creatives, and locals who appreciate a bar that hasn't tried to be anything other than what it is for nearly 90 years. There is nothing fancy here and that is entirely the point. After 9pm is best; Chinatown First Friday nights are especially lively.",cashOnly:true,kamaaina:null},
  {name:"Tchin Tchin Bar",tier:"B",lat:21.3125,lng:-157.8618,category:"nightlife",subcategory:"wine-bar",tagline:"An intimate Chinatown wine and cocktail bar with dim lighting, curated playlist, and a sophisticated but unpretentious vibe.",area:"Chinatown / Downtown",price:"$$",mustOrder:["natural wine selection","craft cocktail"],parking:"Street parking; walk from downtown",talkStory:"A moody, intimate wine and cocktail bar on Hotel Street in Chinatown. The dim lighting, curated playlist, and minimalist decor create a vibe that feels more Brooklyn or Tokyo than Honolulu. The natural wine selection is excellent and the bartenders can guide you to something unexpected. Popular with Chinatown's creative crowd and after-work industry folks. First Friday is especially lively.",cashOnly:false,kamaaina:null},
  {name:"The Dragon Upstairs",tier:"A",lat:21.313,lng:-157.863,category:"nightlife",subcategory:"jazz-club",tagline:"A tiny Chinatown jazz club above a bar — 30-person room where you're practically sitting with the band.",area:"Chinatown / Downtown",price:"$$",mustOrder:["cocktail from the bar downstairs"],parking:"Street parking; walk from downtown",talkStory:"A tiny jazz club above a Chinatown bar that features some of Hawaii's best jazz musicians in an intimate setting. The room holds maybe 30 people, creating a close-knit atmosphere where you're almost sitting with the band. Locals who love live music consider this one of Honolulu's greatest treasures. No cover on some nights; check the schedule online. Arrive early for a good seat.",cashOnly:false,kamaaina:null},
  {name:"3660 On the Rise",tier:"A",lat:21.2845,lng:-157.8113,category:"restaurant",subcategory:"fine-dining",tagline:"Where locals celebrate anniversaries — Chef Russell Siu's ahi katsu has been a Honolulu icon since 1992.",area:"Kaimuki",price:"$$$",mustOrder:["ahi katsu — seared ahi in nori-panko crust, the dish that made this place famous","Chinese-style duck","save room for dessert — the pastry program is strong"],parking:"Small lot on Waialae Ave; street parking on side streets",talkStory:"Open since 1992 — over 30 years of Pacific Rim fine dining on Waialae Ave. Chef Russell Siu's ahi katsu is one of the signature dishes of Honolulu fine dining, widely imitated but never matched. This is the restaurant where local families go for birthdays, anniversaries, and graduations. The slightly lower Google rating (4.4) is a function of higher expectations at this price point, not inconsistency. Dinner nightly, reservations strongly recommended.",cashOnly:false,kamaaina:null},
  {name:"53 By The Sea",tier:"B",lat:21.293,lng:-157.862,category:"restaurant",subcategory:"fine-dining",tagline:"Glass-walled waterfront dining at Kewalo Basin — panoramic ocean views and spectacular sunsets for special occasions.",area:"Kakaako",price:"$$$$",mustOrder:["seafood tower","wagyu steak","sunset cocktail"],parking:"Validated valet parking available",talkStory:"The crescent-shaped glass dining room sits right on the waterfront at Kewalo Basin, offering panoramic ocean views and spectacular sunsets. The contemporary Continental menu emphasizes beautifully presented seafood and steaks. Locals come here for anniversaries and proposals — request a window table facing west for sunset. Arrive 30 minutes before sunset for the best light. Reservations essential, especially weekends.",cashOnly:false,kamaaina:null},
  {name:"AGU A Ramen Bistro",tier:"B",lat:21.2913,lng:-157.8383,category:"restaurant",subcategory:"ramen",tagline:"Solid Honolulu ramen chain with rich tonkotsu broth — reliable bowl every single time.",area:"McCully",price:"$$",mustOrder:["Kotteri ramen — thick, rich tonkotsu broth with chashu and soft egg","AGU shoyu ramen — soy-based broth, lighter but still flavorful","Gyoza — pan-fried crispy, good starter while you wait"],parking:"Strip mall parking lot. The McCully location usually has spots available.",talkStory:"AGU has expanded to multiple locations across Honolulu but the quality stays consistent, which is impressive. The tonkotsu broth is legit rich and porky. Not the absolute best ramen on the island (that's a heated debate), but it's reliably good and you rarely have to wait as long as some other spots. Multiple locations means there's usually one near you. Good rainy day option when you want something warm and filling.",cashOnly:false,kamaaina:null},
  {name:"Aiea Bowl Restaurant",tier:"B",lat:21.3863,lng:-157.9319,category:"restaurant",subcategory:"plate-lunch",tagline:"Bowling alley restaurant with surprisingly excellent local food — the oxtail soup draws people from all over.",area:"Aiea",price:"$",mustOrder:["Oxtail soup — clear broth, tender meat, served with mustard cabbage and rice","Fried noodles — local-style chow mein, crispy and savory","Hamburger steak with gravy — classic plate lunch comfort food"],parking:"Large parking lot for the bowling alley. Never an issue.",talkStory:"Yes, it's in a bowling alley, and yes, the food is legitimately great. Aiea Bowl has been serving plate lunches since the early days and the oxtail soup is famous across the island. Lots of Pearl City/Aiea locals have been coming here for decades. The prices are still old-school cheap. Great for families — eat, then bowl a few games. If you're staying in Waikiki this isn't worth the drive, but if you're in the Pearl Harbor/Aiea area it's a must-stop.",cashOnly:false,kamaaina:null},
  {name:"Alicia's Market",tier:"A",lat:21.3268,lng:-157.8658,category:"restaurant",subcategory:"poke",tagline:"30+ poke varieties in a Kalihi market — the OG that every other poke shop tries to imitate.",area:"Kalihi",price:"$",mustOrder:["Shoyu ahi poke — the classic that built this place's reputation","Spicy ahi poke — creamy and perfectly balanced heat","Hawaiian-style poke — simple limu and sea salt, old-school preparation"],parking:"Small lot in front of the store on Dillingham Blvd",talkStory:"Named after founder Alicia — one of Kalihi's most beloved poke counters with a huge selection. Ask staff what's freshest today. Best selection before noon. Combine with Bishop Museum (also in Kalihi).",cashOnly:true,kamaaina:null},
  {name:"Bar MAZE",tier:"A",lat:21.2992,lng:-157.8629,category:"restaurant",subcategory:"fine-dining",tagline:"James Beard-nominated omakase in Kakaako — intimate counter seating where every course is theater.",area:"Kakaako",price:"$$$",mustOrder:["seasonal tasting menu ($125)","cocktail pairing ($200 with pairing)"],parking:"Street parking on Auahi St and surrounding Kakaako blocks; metered spots free after 6pm",talkStory:"Created by Justin and Tom Park (the duo behind award-winning Bar Leather Apron) with head chef Ki Chung (2024/2025 James Beard nominee). Justin Park won the 2023 James Beard Award for bartending. Opened 2021. Reservations essential weeks in advance. Wed–Sun from 5pm. The cocktail or non-alcoholic pairings are designed to match each course — worth the upgrade.",cashOnly:false,kamaaina:null},
  {name:"bEASTside Kitchen",tier:"B",lat:21.2803,lng:-157.7421,category:"restaurant",subcategory:"hawaiian-fusion",tagline:"Covid pop-up turned Hawaii Kai neighborhood gem — live music nightly, garlic shrimp that rivals the North Shore trucks.",area:"Hawaii Kai",price:"$$",mustOrder:["umami garlic shrimp — the signature","loco moco — elevated but still local","BBQ bao buns — crowd favorite"],parking:"Lot on Kalanianaole Hwy; ample compared to town restaurants",talkStory:"Founded by James Kiko and Grandma Nette as a roadside pop-up tent in Waimanalo in September 2021. Grew into a brick-and-mortar on Kalanianaole Hwy in Hawaii Kai. Live music every night except Tuesdays, bingo nights on 2nd and 4th Mondays — this is as much a community gathering spot as a restaurant. The east side location means zero tourists. Happy hour until 6pm. Open late (midnight most nights).",cashOnly:false,kamaaina:null},
  {name:"Boots & Kimo's",tier:"A",lat:21.3943,lng:-157.7396,category:"restaurant",subcategory:"breakfast",tagline:"Banana macadamia nut pancakes with mac nut sauce — worth the hour wait if you get there by 7:30am.",area:"Kailua",price:"$$",mustOrder:["banana mac nut pancakes ($13–15) — do NOT add butter or syrup, the sauce is everything"],parking:"Enchanted Lake Shopping Center has shared parking lot",talkStory:"Founded by Jesse 'Boots' Maragos and Kimo McVay — Kimo was a legendary Hawaii entertainment manager who managed Don Ho. Loco moco and fried rice are legit secondary orders. The move: Tue/Wed right at 7:30am opening for walk-in seating.",cashOnly:false,kamaaina:null},
  {name:"Brick Fire Tavern",tier:"A",lat:21.2849,lng:-157.8226,category:"restaurant",subcategory:"pizza",tagline:"Neapolitan wood-fired pizza with Hawaiian twists — kalua pig pizza, craft cocktails, and a loyal Kaimuki following.",area:"Kaimuki",price:"$$",mustOrder:["kalua pig pizza — Hawaiian BBQ meets Neapolitan crust","margherita — the benchmark, beautifully charred","craft cocktails — the bar program is legit"],parking:"Street parking on Waialae Ave; side streets toward Wilhelmina Rise",talkStory:"Kaimuki's neighborhood pizzeria since ~2017, using a wood-fired oven and local ingredients in creative ways. The kalua pig pizza is the kind of thing that could only come from Hawaii. The cocktail program adds another dimension — this is as much a bar as a pizza spot. Well outside the tourist zone, the crowd is Kaimuki regulars and east Honolulu date-nighters. Opens 11am Tue–Sun. Reservations recommended for dinner.",cashOnly:false,kamaaina:null},
  {name:"Broke Da Mouth Grindz",tier:"B",lat:21.344,lng:-158.07,category:"restaurant",subcategory:"plate-lunch",tagline:"The name says it all — braised short ribs so tender they fall apart, and portions so generous Kapolei locals make this their weekly ritual.",area:"Kapolei",price:"$",mustOrder:["Braised beef short ribs plate — fall-off-the-bone tender, the signature dish","Garlic chicken — crispy skin with serious garlic punch","Loco moco — homestyle and massive portion"],parking:"Strip mall parking lot with plenty of stalls",talkStory:"Family-run plate lunch spot that earned a devoted West Side following by focusing on slow-cooked comfort food and generous portions at working-class prices. Limited hours — check ahead. The short ribs sell out, so go early. Worth every minute of the wait. Wednesday specials draw the biggest crowds.",cashOnly:false,kamaaina:null},
  {name:"Buzz's Lanikai",tier:"A",lat:21.3886,lng:-157.7142,category:"restaurant",subcategory:"seafood",tagline:"Old-school Kailua steakhouse steps from Lanikai Beach — the kiawe-grilled ahi steak is a local institution.",area:"Lanikai",price:"$$",mustOrder:["Kiawe-grilled ahi steak — seared over wood, served with garlic butter","Buzz's original steak — 10oz sirloin, simple and satisfying","Coconut shrimp — crispy and sweet, classic pupu"],parking:"Small parking lot in front, plus street parking on Kawailoa Rd. Beach traffic makes weekends tough — go weekday evenings.",talkStory:"Buzz's has been here since the '60s and it looks like it — wood-paneled walls, tiki vibes, zero pretension. It's the kind of place where sandy-footed families sit next to couples on date night. The kiawe-grilled fish is the star — they use real local kiawe wood. Perfect post-beach dinner after a Lanikai day. BYOB used to be the move but they have a full bar now. Reservations don't exist — just show up and wait.",cashOnly:false,kamaaina:null},
  {name:"Café Kaila",tier:"A",lat:21.2843,lng:-157.829,category:"restaurant",subcategory:"breakfast",tagline:"Four-time Honolulu Magazine gold medalist for Best Breakfast — the meatloaf loco moco is a hangover cure and a life choice all at once.",area:"Moiliili / Kapiolani",price:"$",mustOrder:["Meatloaf loco moco — housemade meatloaf with rich gravy, the signature dish","Macadamia nut pancakes — fluffy with local mac nuts and tropical fruit","Eggs Benedict — perfectly poached with hollandaise on point"],parking:"Upper level of Market City Shopping Center",talkStory:"Opened in 2008 by Chef Christi Kaila Sei in Market City Shopping Center, quickly winning Honolulu Magazine's Best Breakfast award four times and becoming a local institution. Weekday mornings are way less crowded than weekends. Get there by 7:30am on Saturdays or expect a 30+ minute wait. The daily specials board is always worth checking.",cashOnly:false,kamaaina:null},
  {name:"Chogajip Korean Restaurant",tier:"B",lat:21.2907,lng:-157.837,category:"restaurant",subcategory:"late-night",tagline:"Open until 4am every single day — the chive pancakes and kimchi stew are why Honolulu's night owls know exactly where to end up.",area:"Ala Moana / Kapiʻolani",price:"$$",mustOrder:["chive pancakes (buchujeon)","kimchi jjigae","galbi"],parking:"Small shared lot off Kapiolani Blvd; street parking on side streets",talkStory:"A long-running late-night Korean spot on Kapiolani Blvd, beloved by Honolulu's restaurant and bar industry workers for decades as the go-to post-shift meal destination. Daily 8am–4am. The 2am crowd is its own subculture — service industry workers, night owls, post-bar hunger.",cashOnly:false,kamaaina:null},
  {name:"Cinnamon's Restaurant",tier:"A",lat:21.3923,lng:-157.7453,category:"restaurant",subcategory:"breakfast",tagline:"Kailua brunch institution where the guava chiffon pancakes and red velvet pancakes have a cult following.",area:"Kailua",price:"$$",mustOrder:["Guava chiffon pancakes — fluffy, tangy-sweet, the signature dish","Red velvet pancakes — cream cheese frosting on pancakes, outrageously good","Eggs Benedict — local twist with kalua pork or crab cake"],parking:"Parking lot behind the restaurant off Kailua Rd. Can fill up on weekends — arrive before 8:30am or after 11am.",talkStory:"Cinnamon's moved from its tiny original location to a bigger spot on Kailua Rd, which helped the wait times but weekends are still packed. The guava chiffon pancakes are what everyone comes for and they live up to the hype. Good combo: brunch at Cinnamon's, then walk to Kailua Beach. They also do a solid lunch menu but breakfast is the reason to go. Gets hot inside — grab a table on the patio if you can.",cashOnly:false,kamaaina:null},
  {name:"Da Ono Hawaiian Food",tier:"A",lat:21.2765,lng:-157.8135,category:"restaurant",subcategory:"plate-lunch",tagline:"The original Ono Hawaiian Foods closed after 57 years, but Da Ono carries the torch at the same Kapahulu address — kalua pig still hits.",area:"Kapahulu",price:"$",mustOrder:["Kalua pig plate — smoky, tender, and authentic as it gets","Lomi salmon — fresh tomato and salmon, served cold the traditional way","Pipikaula short ribs — Hawaiian-style dried beef, salty and chewy"],parking:"Street parking on Kapahulu Ave, small lot behind building",talkStory:"The original Ono Hawaiian Foods was founded in 1962 and served traditional Hawaiian plates for 57 years before closing in 2019. Da Ono opened in the same Kapahulu location, carrying forward the legacy of one of Honolulu's most beloved Hawaiian food spots. Wed–Sun only. Get there before 2pm for best selection — popular items sell out. Order the combo plate to try multiple Hawaiian dishes. The poi is legit.",cashOnly:false,kamaaina:null},
  {name:"Diamond Head Market & Grill",tier:"A",lat:21.2687,lng:-157.8058,category:"restaurant",subcategory:"plate-lunch",tagline:"Monsarrat Ave institution since the '90s — the lemon crunch cake alone is worth the trip.",area:"Kapahulu / Diamond Head",price:"$",mustOrder:["lemon crunch cake — legendary, the signature","ginger wasabi salmon plate","poke bowls — fresh, well-priced"],parking:"Small lot behind the market; street parking on Monsarrat Ave",talkStory:"Open 25+ years on Monsarrat Ave, serving plate lunches, poke, and baked goods from a takeout window. The lemon crunch cake is genuinely iconic — people order full cakes for parties. Tourists found this place (it's on the Diamond Head hike route), but it's a legitimate institution, not a tourist trap. The insider move: go on a weekday and avoid the post-hike weekend rush. The market side has good grab-and-go snacks too. Daily 7:30am–8pm.",cashOnly:false,kamaaina:null},
  {name:"Don Quijote Honolulu (Deli / Poke Counter)",tier:"B",lat:21.2968,lng:-157.8434,category:"restaurant",subcategory:"late-night",tagline:"24 hours, legit poke, fresh bento, spam musubi — the Japanese-style superstore that locals hit at 2am without shame.",area:"Moiliili / Kaheka",price:"$",mustOrder:["Poke by the container — multiple varieties, always fresh and cheap","Spam musubi — perfectly proportioned rice-to-spam ratio","Bento boxes — Japanese-quality prepared meals at supermarket prices"],parking:"Large free parking structure attached to the store",talkStory:"Part of the Japanese Don Quijote discount chain (formerly Daiei), this Kaheka St location became a local institution for its 24-hour deli counter with surprisingly excellent poke and prepared foods. Open 24/7. The late-night poke and bento run is a Honolulu tradition. Poke counter gets restocked throughout the day. The takoyaki and tempura near the deli are sleeper hits.",cashOnly:false,kamaaina:null},
  {name:"Duc's Bistro",tier:"A",lat:21.314,lng:-157.864,category:"restaurant",subcategory:"fine-dining",tagline:"A swank French-Vietnamese oasis hiding in Chinatown — crispy spring rolls meet bouillabaisse with island fish.",area:"Chinatown / Downtown",price:"$$$",mustOrder:["bouillabaisse with island fish","crispy spring rolls","beef in betel leaf"],parking:"Street parking; paid lots on Maunakea St",talkStory:"Chef Duc Pham creates sophisticated dishes blending French technique with Vietnamese flavors in a white-tablecloth setting that feels unexpected in gritty Chinatown — which is part of the charm. The bouillabaisse uses fresh island fish, the spring rolls are impossibly crispy, and the beef wrapped in betel leaf is extraordinary. Locals consider it one of the most underrated restaurants in Honolulu. Reservations recommended on weekends.",cashOnly:false,kamaaina:null},
  {name:"Ethel's Grill",tier:"A",lat:21.3265,lng:-157.8678,category:"restaurant",subcategory:"plate-lunch",tagline:"Tiny Kalihi gem where the garlic ahi and oxtail soup are worth the early wake-up.",area:"Kalihi",price:"$",mustOrder:["Garlic ahi steak — seared rare with garlic butter, the signature dish","Oxtail soup — rich, fall-off-the-bone, with mustard cabbage","Shoyu pork — tender braised pork belly in sweet shoyu"],parking:"Small lot in front of the strip mall. Gets packed during lunch — arrive by 10:30am.",talkStory:"Ethel's has been in this unassuming Kalihi strip mall forever, run by the same family. Lunch is the move — they open at 6am for breakfast but the hot stuff starts rolling at 10. The garlic ahi is legitimately one of the best things you'll eat on this island for under $15. Portions are local-style generous. This is deep Kalihi — not a tourist in sight. Cash preferred but they do take cards now.",cashOnly:false,kamaaina:null},
  {name:"Fête",tier:"S",lat:21.3085,lng:-157.8617,category:"restaurant",subcategory:"fine-dining",tagline:"Hawaii's first James Beard Best Chef winner in 19 years — seasonal New American meets local soul food in a Chinatown bistro.",area:"Chinatown / Downtown",price:"$$$",mustOrder:["carbonara with Portuguese sausage","twice-fried chicken with grits and collard greens","duck fat fries"],parking:"Street parking on Smith/Bethel; paid lots on Maunakea St",talkStory:"Opened 2016 by Chef Robynne Maii — won the James Beard Award for Best Chef Northwest & Pacific in 2022, the first Hawaii-based chef to win the regional award since Alan Wong in 2003. The menu bridges Southern comfort, French technique, and Hawaiian ingredients. Mon–Sat 11am–10pm. Ask for a seat near the open kitchen. Great combined with a Chinatown walk — galleries, Maunakea Marketplace, Local Joe coffee all nearby.",cashOnly:false,kamaaina:null},
  {name:"Fook Yuen Seafood Restaurant",tier:"A",lat:21.2862,lng:-157.8233,category:"restaurant",subcategory:"dim-sum",tagline:"Legit dim sum with rolling carts — the har gow and char siu bao are Chinatown quality without the Chinatown parking.",area:"Moiliili",price:"$$",mustOrder:["Har gow — delicate shrimp dumplings with translucent wrappers","Char siu bao — fluffy BBQ pork buns, steamed to order","Siu mai — pork and shrimp dumplings, a dim sum staple"],parking:"Parking lot in the McCully Shopping Center. Usually can find a spot.",talkStory:"Fook Yuen is where the Chinese aunties and uncles go for dim sum on weekends, and if that doesn't tell you it's legit, nothing will. They still do the traditional cart service — flag down the cart ladies and point at what looks good. Weekend dim sum gets packed by 10am so go early, especially for a big group. Weekday dim sum is the local hack — same food, no wait. The dinner seafood menu is solid too but dim sum is the main event.",cashOnly:false,kamaaina:null},
  {name:"Fort Ruger Market",tier:"A",lat:21.2703,lng:-157.7995,category:"restaurant",subcategory:"plate-lunch",tagline:"Tiny neighborhood deli on a residential side street — Filipino plate lunches with the kind of portions only aunties serve.",area:"Diamond Head",price:"$",mustOrder:["adobo plate — pork or chicken, classic Filipino comfort","lumpia — crispy spring rolls","loco moco — their version is massive"],parking:"Street parking on Alohea Ave; residential neighborhood, usually available",talkStory:"Hidden on a residential street near Fort Ruger Park — started as a corner market and evolved into a beloved plate lunch counter. The Filipino food is cooked from family recipes: pork adobo, lumpia, pinakbet, dinuguan. The same aunties and uncles come every week. Zero tourist presence. Enormous portions for the price. This is the kind of place you only find if a local tells you about it. Mon–Sat, closes early afternoon when food runs out.",cashOnly:false,kamaaina:null},
  {name:"Fujiyama Texas",tier:"A",lat:21.2884,lng:-157.8353,category:"restaurant",subcategory:"izakaya",tagline:"The ultimate late-night salvation — kushi katsu (deep-fried skewers) until 3:30am, perfect for when the clubs close and you need real food.",area:"Moiliili / S. King St",price:"$$",mustOrder:["assorted kushi katsu skewers","ahi poke","mapo tofu"],parking:"Small lot behind restaurant off S. King St; street parking on side streets in Moiliili",talkStory:"A Moiliili institution since the 1980s, Fujiyama Texas fuses Japanese izakaya with Texas-sized portions. The name itself captures Hawaii's cultural mash-up spirit — Japanese craft meets American excess. Open until 3:30am (except Tue). Midnight Diner menu kicks in at 11pm.",cashOnly:false,kamaaina:null},
  {name:"Fumi's Kahuku Shrimp (Ala Moana)",tier:"B",lat:21.2908,lng:-157.8434,category:"restaurant",subcategory:"shrimp",tagline:"The legendary North Shore truck that moved to Ala Moana's Makai Food Court — same garlic butter shrimp recipe, now easier to reach from town.",area:"Ala Moana",price:"$",mustOrder:["Garlic butter shrimp — the signature dish, drenched in buttery garlic sauce","Hot and spicy shrimp — serious heat with great flavor underneath","Shrimp scampi — lighter preparation, still packed with garlic"],parking:"Ala Moana Center parking structure, free for first 4 hours",talkStory:"Fumi's started as one of the original Kahuku shrimp trucks on the North Shore, farming their own shrimp in nearby aquaculture ponds. The Ala Moana location in the Makai Food Court brings that North Shore flavor to town. Makai Food Court hours vary. Order both the garlic shrimp and scampi for comparison. Ask for extra rice — you'll need it to soak up the garlic butter sauce. Lunch rush hits around noon.",cashOnly:false,kamaaina:null},
  {name:"Giovanni's Shrimp Truck",tier:"A",lat:21.6797,lng:-157.953,category:"restaurant",subcategory:"food-truck",tagline:"The OG garlic shrimp truck since 1993 — scrawl your name on the side and join the legend.",area:"Kahuku",price:"$$",mustOrder:["scampi (garlic butter) — the dish that made them famous"],parking:"Gravel parking adjacent",talkStory:"Started 1993 by Giovanni and Donna Aragon — a white van on the roadside in Kahuku that launched the entire North Shore shrimp truck industry. Don't wear a nice shirt — garlic butter splatters are inevitable. Combine with Romy's (1 mile up road) for the ultimate shrimp comparison.",cashOnly:false,kamaaina:null},
  {name:"Goma Tei Ramen (Ward)",tier:"B",lat:21.2968,lng:-157.8581,category:"restaurant",subcategory:"ramen",tagline:"A local mini-chain that consistently beats out the trendy newcomers — the sesame-rich tonkotsu broth is what keeps Honolulu coming back.",area:"Kakaako / Ward",price:"$$",mustOrder:["Sesame ramen — rich ground sesame broth, the signature bowl that defines this place","Spicy miso ramen — complex broth with layered heat","Gyoza — crispy pan-fried dumplings, perfect starter"],parking:"Ward Centre parking structure, validated with purchase",talkStory:"Goma Tei originated in Japan and opened its first Hawaii location in 2005, building a loyal following with its signature sesame-based broth that you won't find at most ramen shops. Now has multiple locations across Oahu. The sesame ramen is the move — it's what sets them apart from every other ramen shop. Weekday lunch is less packed than dinner. You can customize spice level and noodle firmness.",cashOnly:false,kamaaina:null},
  {name:"Guava Smoked",tier:"A",lat:21.2756,lng:-157.8136,category:"restaurant",subcategory:"plate-lunch",tagline:"Texas-style BBQ smoked with Hawaiian guava wood — brisket and pulled pork that taste like nowhere else on earth.",area:"Kapahulu",price:"$",mustOrder:["smoked brisket plate","pulled pork — guava wood gives it a subtle sweetness","combo plate to try both"],parking:"Street parking on Kapahulu Ave",talkStory:"Started as pop-ups before landing a brick-and-mortar on Kapahulu. The concept — Texas low-and-slow technique with Hawaiian guava wood — is a genuinely local innovation you won't find on the mainland. The smoke flavor is distinct: a little sweeter, a little more floral than mesquite or hickory. Portions are solid for the price. Your map has no BBQ representation — this fills that gap. Closed Mondays.",cashOnly:false,kamaaina:null},
  {name:"Haili's Hawaiian Food",tier:"A",lat:21.2942,lng:-157.8413,category:"restaurant",subcategory:"hawaiian",tagline:"Family-recipe Hawaiian food since 1950 — laulau, kalua pig, and squid luau that rival Helena's without the hype.",area:"Palama / Kalihi",price:"$",mustOrder:["Laulau — tender pork wrapped in taro and ti leaves, steamed for hours","Kalua pig plate — smoky, salty, fall-apart pulled pork","Squid luau — squid simmered in creamy taro leaf","Haupia for dessert"],parking:"Small lot in front on North King St. Street parking available",talkStory:"Operating since 1950, Haili's is the less-hyped sibling to Helena's Hawaiian Food — but locals will argue it's just as good. The recipes come from Aunty Haili's family and haven't changed in decades. The laulau is excellent — tender pork with butterfish wrapped in taro leaves — and the kalua pig is properly smoky. It's a no-frills plate lunch spot in a part of town most tourists never visit. If Helena's line is too long or they're closed (they're only open limited days), Haili's is the backup the locals know about.",cashOnly:false,kamaaina:null},
  {name:"Haleiwa Joe's",tier:"B",lat:21.5793,lng:-158.1035,category:"restaurant",subcategory:"seafood",tagline:"North Shore's sit-down seafood spot with a chill surfer vibe and solid fresh fish plates.",area:"Haleiwa",price:"$$",mustOrder:["Fresh catch of the day — grilled or seared, always local fish","Coconut shrimp — crispy and sweet, a crowd favorite","Joe's salad — mixed greens with macadamia nuts and lilikoi dressing"],parking:"Parking lot at Haleiwa Town Center, right in front of the restaurant.",talkStory:"Haleiwa Joe's has been in Haleiwa forever and it's the default 'nice dinner' option on the North Shore. Nothing mind-blowing, but reliably good fish in a laid-back setting. Good for families or when you want something more substantial than a food truck after a beach day. There used to be a Kaneohe location too (Haiku Gardens) — that one closed. The North Shore location is the OG. Sunset time on their patio is a vibe.",cashOnly:false,kamaaina:null},
  {name:"Hank's Haute Dogs",tier:"B",lat:21.2969,lng:-157.8559,category:"restaurant",subcategory:"food-truck",tagline:"Gourmet hot dogs in Kakaako — the lobster dog and Chicago dog are a step above any street cart.",area:"Kakaako",price:"$",mustOrder:["Lobster dog — chunks of lobster on a buttery roll with lemon aioli","Chicago dog — proper Vienna beef, neon relish, sport peppers, the whole deal","Bacon-wrapped dog — crispy bacon-wrapped hot dog with jalapeños"],parking:"Street metered parking on Coral St. SALT at Our Kakaako garage nearby.",talkStory:"Hank's started as one of Honolulu's first real gourmet food concepts that proved you could do elevated street food in Hawaii. Chef Hank Adaniya is a classically trained chef from Chicago who brought legit hot dog culture to Kakaako. The lobster dog sounds bougie but it's actually a great deal for what you get. Quick lunch spot if you're exploring the Kakaako murals or SALT area. No frills, just really good dogs.",cashOnly:false,kamaaina:null},
  {name:"Helena's Hawaiian Food",tier:"S",lat:21.3282,lng:-157.8642,category:"restaurant",subcategory:"hawaiian",tagline:"James Beard Award winner in a Kalihi strip mall — the pipikaula short ribs will ruin you for all other beef.",area:"Kalihi",price:"$$",mustOrder:["Hawaiian plate (pipikaula short ribs, lomi salmon, poi, haupia)"],parking:"Strip mall parking lot on N. School St in Kalihi",talkStory:"Founded 1946 by Helen 'Helena' Chock. Won the James Beard America's Classics Award in 2000 — the only traditional Hawaiian food restaurant ever honored. Eat poi with two fingers, never a fork. Don't make a face at poi — it's sacred.",cashOnly:true,kamaaina:null},
  {name:"Highway Inn Kakaako",tier:"S",lat:21.2964,lng:-157.8568,category:"restaurant",subcategory:"hawaiian",tagline:"Traditional Hawaiian plate lunch since 1947 — the poi, laulau, and pipikaula are as real as it gets.",area:"Kakaako",price:"$$",mustOrder:["Laulau — pork and butterfish wrapped in taro and ti leaves, steamed tender","Pipikaula short ribs — Hawaiian-style dried beef, grilled smoky and chewy","Poi — fresh-pounded, the real deal, order it with your plate"],parking:"Parking lot at SALT at Our Kakaako. Some street parking on Coral St.",talkStory:"Highway Inn started in Waipahu in 1947, back when it was literally on the highway between the plantations. The Kakaako location in SALT is the newer, hipper spot but the food is still old-school Hawaiian. This is where locals go when they want real Hawaiian food in a nicer setting than a takeout window. The original Waipahu location is still open too if you want the OG experience. Lunch gets crowded — 11am or after 1:30pm is your sweet spot.",cashOnly:false,kamaaina:null},
  {name:"Hihimanu Sushi",tier:"B",lat:21.2862,lng:-157.8247,category:"restaurant",subcategory:"japanese",tagline:"High-end omakase sushi on Waialae — named for the Hawaiian eagle ray, blending island identity with Japanese craft.",area:"Kaimuki",price:"$$$",mustOrder:["omakase — trust the chef's selection","seasonal sashimi — whatever's freshest","the full counter experience"],parking:"Street parking on Waialae Ave",talkStory:"The name 'hihimanu' is Hawaiian for eagle ray or manta ray — a nice touch that blends Hawaiian identity with serious sushi craft. $100+ omakase in a local Kaimuki neighborhood setting, not Waikiki. The crowd is local sushi aficionados willing to pay for quality. Reserve ahead. Dinner only, opens at 2pm Tue–Sun.",cashOnly:false,kamaaina:null},
  {name:"HUMU Sandwich & Smoothies",tier:"A",lat:21.3068,lng:-157.8625,category:"restaurant",subcategory:"deli",tagline:"Downtown sandwich shop with a 4.9 Google rating — the Reuben is the best on the island and locals want to keep it secret.",area:"Chinatown / Downtown",price:"$",mustOrder:["Reuben sandwich — consistently called the best on Oahu","bulgogi sub — Korean-meets-deli crossover","smoothies — surprisingly good for a sandwich shop"],parking:"Merchant St metered parking; downtown parking garages",talkStory:"A small deli on Merchant Street in the financial district with a 4.9 Google rating at nearly 200 reviews — one of the highest-rated food spots on Oahu. The Reuben is the draw: proper corned beef, sauerkraut, Russian dressing, rye bread. One reviewer said they 'wanted to keep it a hidden gem.' Primarily a lunch spot for downtown office workers. Quick service, reasonable prices. Weekday hours only.",cashOnly:false,kamaaina:null},
  {name:"Izakaya Nonbei",tier:"A",lat:21.2753,lng:-157.8121,category:"restaurant",subcategory:"japanese",tagline:"Intimate Tokyo-style izakaya tucked on a side street — the bartender knows your name by the second visit.",area:"Kapahulu",price:"$$",mustOrder:["yakitori — grilled over charcoal, proper izakaya style","sashimi platter — whatever's fresh","agedashi tofu — crispy and silky"],parking:"Street parking on Olu St and Kapahulu side streets",talkStory:"If Tokkuri Tei is the boisterous, social izakaya, Nonbei is its quieter, more refined counterpart. Small counter-bar setting that genuinely feels like a side-street izakaya in Tokyo. The chef/owner is Japanese and the food reflects that heritage without compromise. The crowd is local Japanese-American regulars and expats. Tucked on Olu Street off Kapahulu — you have to know it's there. Dinner only, 5pm–late. Reservations recommended.",cashOnly:false,kamaaina:null},
  {name:"J. Dolan's",tier:"B",lat:21.2835,lng:-157.8168,category:"restaurant",subcategory:"pizza",tagline:"New York-style pizza and craft beer in Kaimuki — often cited as the best slice on the island.",area:"Kaimuki",price:"$$",mustOrder:["pepperoni pizza — classic NY style, perfectly charred","craft beer selection — rotating taps worth exploring","garlic knots — if available"],parking:"Street parking on Waialae Ave; Kahala Mall lot nearby",talkStory:"Kaimuki's neighborhood pizza and beer joint since ~2014. Hand-tossed New York-style pies, good craft beer selection, and a laid-back vibe that draws UH students, young professionals, and Kaimuki regulars. If Brick Fire Tavern is the wood-fired artisan option, Dolan's is the casual, grab-a-slice-and-a-beer counterpart. Also has a second location (Irish pub) on Bethel St downtown. Late night friendly.",cashOnly:false,kamaaina:null},
  {name:"Kahuku Superette",tier:"A",lat:21.68,lng:-157.9501,category:"restaurant",subcategory:"poke",tagline:"A five-generation family recipe in a tiny convenience store on the North Shore — the shoyu poke here will ruin you for all others.",area:"Kahuku / North Shore",price:"$",mustOrder:["Shoyu ahi poke bowl — five-generation family recipe, the reason this place exists","Spicy ahi poke — creamy-spicy with fresh ahi","Plate lunch specials — surprisingly solid comfort food from a convenience store"],parking:"Small gravel lot right in front of the store",talkStory:"A family-owned country store in Kahuku town that has been serving the community for generations. Their poke recipe has been passed down through five generations, making it one of the oldest continuously family-made poke preparations on Oahu. Go early — the poke is made fresh daily and sells out fast, especially on weekends when the North Shore surf crowd rolls through. Grab it before noon for best selection. Combine with a Kahuku shrimp truck stop.",cashOnly:false,kamaaina:null},
  {name:"Kahumana Farm Cafe",tier:"A",lat:21.447,lng:-158.146,category:"restaurant",subcategory:"farm-to-table",tagline:"A farm-to-table cafe hidden deep in the Waianae Valley, serving food harvested from the surrounding organic gardens.",area:"Waianae",price:"$$",mustOrder:["farm salad","grain bowl","fresh-baked pastry"],parking:"Free lot on the farm property",talkStory:"Hidden in the back valley of Waianae on an organic farm that doubles as a transitional housing community. The food is made with ingredients harvested that morning — fresh salads, hearty grain bowls, and baked goods. The setting, surrounded by mountains and farmland, feels a world away from Honolulu. Open Wed-Sat for lunch; call ahead to confirm hours. Locals treasure this place for its mission as much as its food.",cashOnly:false,kamaaina:null},
  {name:"Kaimuki Shokudo",tier:"B",lat:21.2846,lng:-157.8148,category:"restaurant",subcategory:"late-night",tagline:"Izakaya menu that actually runs late — Kaimuki residents' answer to where to eat at 11pm on a Saturday.",area:"Kaimuki",price:"$$",mustOrder:["Garlic fried chicken — crispy, juicy, and perfect with a beer","Pork belly bao buns — rich and savory late-night fuel","Shoyu ramen — solid bowl to close out the night"],parking:"Street parking on Waialae Ave, side streets have more options",talkStory:"Part of the Kaimuki dining revival, Shokudo brought a modern izakaya concept to Waialae Ave with late-night hours that the neighborhood desperately needed — filling the gap for quality food after 10pm. Sun–Thu until midnight, Fri–Sat until 1am. The late-night happy hour deals are the move. Sit at the bar for faster service. The small plates are meant for sharing — order several and split with the table.",cashOnly:false,kamaaina:null},
  {name:"Kalapawai Cafe",tier:"A",lat:21.3924,lng:-157.7349,category:"restaurant",subcategory:"cafe",tagline:"Kailua's neighborhood anchor since 1932 — sunrise coffee to dinner wine, go every day and never get bored.",area:"Kailua",price:"$$",mustOrder:["Kailua Club","Hot Pastrami","Bacon Wrapped Figs","Fish Tacos"],parking:"Small lot behind cafe on Kailua Rd; additional street parking on surrounding blocks",talkStory:"An iconic Kailua brand since 1932, paying homage to plantation-era corner-store heritage. Locally sourced ingredients, wine program focused on small family-owned wineries and breweries. Multiple locations — the Kailua Town cafe at 750 Kailua Rd is the flagship.",cashOnly:false,kamaaina:null},
  {name:"Kapa Hale",tier:"A",lat:21.275,lng:-157.8051,category:"restaurant",subcategory:"fine-dining",tagline:"James Beard semifinalist in Kaimuki — hyper-seasonal Hawaiian ingredients in a cozy neighborhood room.",area:"Kaimuki",price:"$$$",mustOrder:["seasonal tasting menu"],parking:"Street parking on Waialae Ave and Kaimuki side streets (9th-12th Ave)",talkStory:"James Beard semifinalist for Best Chef Northwest & Pacific. Modern take on Hawaii Regional Cuisine — local products combined with ethnic influences showcasing flavors unique to today's Hawaii. Ask for a seat near the open kitchen if available. Reservations recommended.",cashOnly:false,kamaaina:null},
  {name:"Ken's Fresh Fish",tier:"A",lat:21.6452,lng:-157.9236,category:"restaurant",subcategory:"seafood",tagline:"Takeout-only, tiny, and almost impossible to find — the ahi katsu here is possibly the single best dish on the entire North Shore.",area:"Laie / North Shore",price:"$",mustOrder:["Ahi katsu — panko-crusted seared ahi, rare inside, possibly the best thing on the North Shore","Fresh poke — made daily from locally caught fish","Marlin tacos — unique preparation you won't find anywhere else"],parking:"Small gravel lot next to the shop",talkStory:"Run by fisherman Ken, who catches much of what he serves. This tiny takeout window in Laie started as a way to sell his daily catch directly to the community, and word spread through the North Shore surf network. Tue/Wed/Fri 11am–4pm, Sat 11am–5pm. No seating — takeout only. Call ahead to check if they're open and what's fresh. The menu changes based on the catch. Go early — once it's gone, it's gone.",cashOnly:false,kamaaina:null},
  {name:"Khan Skewer Restaurant",tier:"A",lat:21.2918,lng:-157.8362,category:"restaurant",subcategory:"chinese",tagline:"Xinjiang-style lamb skewers heavy on cumin and charcoal — the only spot on Oahu doing this regional Chinese BBQ right.",area:"McCully / Mōʻiliʻili",price:"$$",mustOrder:["lamb skewers — cumin-crusted, charcoal-grilled, the signature","hand-pulled noodles","cold dishes — cucumber salad, wood ear mushroom"],parking:"Street parking on Isenberg St; side streets toward University",talkStory:"One of the most genuinely local spots on this map. Isenberg Street near UH has zero tourist foot traffic — the clientele is overwhelmingly local Asian community who know exactly what Xinjiang BBQ should taste like. The lamb skewers are cumin-heavy and charcoal-grilled in the authentic Northwest Chinese style. Nobody else on Oahu fills this niche. Open for dinner, closed Tuesdays.",cashOnly:false,kamaaina:null},
  {name:"Koa Pancake House",tier:"B",lat:21.3942,lng:-157.8001,category:"restaurant",subcategory:"breakfast",tagline:"Old-school Kaneohe breakfast spot where retirees, surfers, and families all converge over macadamia nut pancakes.",area:"Kaneohe",price:"$",mustOrder:["Macadamia nut pancakes — fluffy stacks topped with mac nut syrup","Portuguese sausage, eggs, and rice — the local breakfast standard","Dutch baby pancake — puffy oven-baked pancake with powdered sugar and lemon"],parking:"Windward Mall parking lot. Plenty of spaces.",talkStory:"Koa Pancake House is inside the Windward Mall food court area in Kaneohe — don't let the mall location fool you, it's a legit breakfast institution on the Windward side. Mostly older local crowd in the morning which is always a good sign. Pancakes are big, cheap, and satisfying. Open early and closes mid-afternoon. Not worth a special trip from town, but if you're heading to Kaneohe or the Windward side, it's the breakfast move.",cashOnly:false,kamaaina:null},
  {name:"Koko Head Cafe",tier:"A",lat:21.2814,lng:-157.7996,category:"restaurant",subcategory:"breakfast",tagline:"Lee Anne Wong's brunch spot — Cornflake French Toast and kimchi fried rice are mandatory.",area:"Kaimuki",price:"$$",mustOrder:["Cornflake French Toast ($16–18, battered in cornflake cereal — cult following)","breakfast bibimbap ($17–19)"],parking:"Park on Kaimuki side streets (12th Ave, Harding Ave)",talkStory:"Opened 2014 by Chef Lee Anne Wong — Top Chef Season 1 alum, James Beard nominee. She also opened Papa Kurt's (smash burgers) nearby. Rotating scones and pastries at the counter — don't skip. No reservations for brunch — walk-in waitlist only. The move: weekday mornings right at 7am opening for zero wait. Walk Waialae Ave after for Kaimuki's boutiques.",cashOnly:false,kamaaina:null},
  {name:"Kona Brewing Co. Hawaii Kai",tier:"B",lat:21.2891,lng:-157.7075,category:"restaurant",subcategory:"seafood",tagline:"Hawaii Kai's waterfront brewpub — solid food, great beer, and sunset views over the marina.",area:"Hawaii Kai",price:"$$",mustOrder:["Longboard Lager or Big Wave on tap — always better on draft at the source","Kona Brewing pizza — wood-fired, crispy, better than expected","Poke nachos — ahi poke on won ton chips, great pupu"],parking:"Koko Marina Center parking lot. Plenty of spaces.",talkStory:"Yes, Kona Brewing is a big brand now, but the Hawaii Kai brewpub is their original Oahu location and it's actually a great spot. The marina-side patio is perfect for sunset beers after a Hanauma Bay or Hawaii Kai day. Food is solid pub fare — not life-changing but reliably good. The beer is always fresher here than anywhere else. Good family spot too. Skip the indoor seating and grab a patio table.",cashOnly:false,kamaaina:null},
  {name:"Lee's Bakery",tier:"A",lat:21.3122,lng:-157.8649,category:"restaurant",subcategory:"bakery",tagline:"Chinatown's Vietnamese bakery with the best banh mi on the island and fresh-baked French bread daily.",area:"Chinatown",price:"$",mustOrder:["Banh mi — classic Vietnamese sandwich on crispy French bread with pate and pickled veg","Pork hash — steamed dim sum-style dumpling, a local favorite","Coconut pandan cake — soft, fragrant, and not too sweet"],parking:"Street metered parking on River St. Chinatown garage nearby. Come early — they sell out.",talkStory:"Lee's has been anchoring this corner of Chinatown forever. The banh mi is under $5 and it's better than most $15 sandwiches anywhere else. They bake the French bread fresh daily — you can smell it from the street. Get there before noon because popular items sell out. It's a takeout counter, not a sit-down spot — grab your banh mi and eat it at one of the Chinatown benches or take it to go. Cash is king here.",cashOnly:true,kamaaina:null},
  {name:"Leonard's Bakery",tier:"S",lat:21.2854,lng:-157.8185,category:"restaurant",subcategory:"hawaiian",tagline:"Malasada institution since 1952 — get the custard-filled haupia and eat them in the parking lot.",area:"Kapahulu",price:"$",mustOrder:["haupia (coconut) malasada puff (the insider's pick over custard)","original plain"],parking:"Dedicated parking lot (~15–20 spots)",talkStory:"Founded 1952 by Leonard Rego, Portuguese descent — malasadas were traditionally made for Shrove Tuesday by Portuguese plantation immigrants from Madeira and the Azores. Never refrigerate. Bringing a box of Leonard's to a party or office is a power move.",cashOnly:false,kamaaina:null},
  {name:"Leonard's Malasada Mobile",tier:"B",lat:21.3132,lng:-157.8636,category:"restaurant",subcategory:"bakery",tagline:"Can't make it to Kapahulu? The Malasada Mobile brings the magic to you — same recipe, same dangerous habit-forming quality.",area:"Roaming / Metro Honolulu",price:"$",mustOrder:["original malasadas","custard-filled malasadas"],parking:"Varies by location — usually parks near shopping centers or event venues with adjacent parking",talkStory:"An extension of the Leonard's Bakery legacy (est. 1952), the Malasada Mobile brings the same Portuguese doughnuts to events, festivals, and neighborhoods across Oahu. Rotating locations — check Instagram. Freshest when hot.",cashOnly:true,kamaaina:null},
  {name:"Like Like Drive Inn",tier:"B",lat:21.2966,lng:-157.8363,category:"restaurant",subcategory:"local-grinds",tagline:"A 24-hour diner serving old-school Hawaiian comfort food since 1953 — oxtail soup, pancakes, and loco moco at 3am.",area:"Kalihi",price:"$",mustOrder:["oxtail soup","pancakes","loco moco"],parking:"Free lot",talkStory:"Pronounced 'lee-keh lee-keh' (named after the Likelike Highway nearby), this 24-hour diner has been feeding Honolulu's late-night crowd since 1953. The oxtail soup, pancake stack, and loco moco are comfort food classics done right. After-bar crowds, night-shift workers, and early-morning fishermen all converge here. The vinyl booths and Formica tables haven't changed in decades, and that's exactly the point.",cashOnly:false,kamaaina:null},
  {name:"Liliha Bakery",tier:"S",lat:21.3247,lng:-157.8519,category:"restaurant",subcategory:"hawaiian",tagline:"Coco puffs since 1950 — the green chiffon cake and butter rolls are the real insider order.",area:"Liliha",price:"$",mustOrder:["coco puffs (non-negotiable)","butter rolls ($1)"],parking:"Dedicated lot at the original Kuakini St location; Nimitz Hwy location has larger lot",talkStory:"Founded 1950 by Takeo and Sumie Takakuwa. The Coco Puff — choux pastry filled with chocolate pudding, topped with Chantilly frosting — is arguably Hawaii's most iconic pastry. Locals call it 'the puff' — say 'I brought puffs' and everyone on Oahu knows. Buy a box of 6 or 12 — it's the standard 'omiyage' (gift) when visiting a local's house. Go before 7am weekdays for fresh batches, zero line.",cashOnly:false,kamaaina:null},
  {name:"Maria Bonita Restaurant",tier:"A",lat:21.3097,lng:-157.8614,category:"restaurant",subcategory:"mexican",tagline:"28-year Chinatown Mexican institution — BYOB, no AC, just fans and the Mexican flag on the walls. The wet chile verde burrito is legendary.",area:"Chinatown / Downtown",price:"$",mustOrder:["wet chile verde burrito — smothered in green sauce, the signature","ahi burrito — Hawaiian-Mexican fusion done right","combo plate — try multiple things"],parking:"Street parking on Hotel St; paid lots on Maunakea St",talkStory:"Owner Diego started with a lunch wagon in Kailua/Waimanalo in 1998, named after his mother. Moved to this Chinatown spot and never left. No air conditioning, just fans. BYOB — bring your own beer or wine. The portions are crazy generous. The no-frills environment self-selects for people who care about food, not ambiance. Nearly three decades of authentic Mexican food in a hole-in-the-wall — the definition of a local gem. Lunch and dinner, closed Sun–Mon.",cashOnly:false,kamaaina:null},
  {name:"Marugame Udon",tier:"A",lat:21.2793,lng:-157.8282,category:"restaurant",subcategory:"noodles",tagline:"Locals genuinely love it despite the Waikiki address — watch them pull fresh noodles through the glass.",area:"Waikiki",price:"$",mustOrder:["kamaage udon ($5–7, the purist's choice — plain dipping noodles, taste the quality)","nikutama ($8–10, beef + egg)"],parking:"Don't drive — no parking in Waikiki",talkStory:"Toridoll Holdings franchise from Kobe, Japan — modeled after Kagawa Prefecture self-serve udon shops. Cafeteria-style: tray, order base udon, pick tempura, pay at register. Total bill can be under $10 — best value in Waikiki. Go at 10am opening or 2–4pm for shortest lines.",cashOnly:false,kamaaina:null},
  {name:"Max & Lucy's",tier:"A",lat:21.2989,lng:-157.8567,category:"restaurant",subcategory:"plate-lunch",tagline:"The chef is also your server — weekday-only, sells out daily, and the lemon bars are famous.",area:"Kakaako",price:"$",mustOrder:["kalbi ribs — the go-to plate","prime rib — when available, don't hesitate","lemon bars — famous for a reason, grab one before they're gone"],parking:"Street parking on Halekauwila St; Kakaako side streets",talkStory:"The kind of place that only exists in Honolulu — the chef cooks your food and then walks it to your table himself. Weekday only (Mon–Fri, 5am–2pm), closed weekends. Items sell out daily — the popular plates go fast by noon. Home-style comfort food: kalbi, teriyaki salmon, fried chicken, lasagna. The lemon bars are an institution. This is a working person's lunch spot in Kakaako, zero tourist presence.",cashOnly:false,kamaaina:null},
  {name:"Mitch's Fish Market & Sushi Bar",tier:"B",lat:21.2862,lng:-157.8672,category:"restaurant",subcategory:"seafood",tagline:"Fresh-off-the-boat seafood right next to the fishing pier — sashimi doesn't get more local than this.",area:"Honolulu Fish Auction",price:"$$",mustOrder:["Sashimi platter — whatever's freshest that day, caught that morning","Garlic shrimp — simple and garlicky, local style","Poke bowl — fresh ahi, rice, and furikake"],parking:"Parking lot at Pier 38. Easy to find, usually has spots.",talkStory:"Mitch's is literally next to the Honolulu Fish Auction at Pier 38 — the fish here was swimming yesterday. It's not fancy — plastic chairs and fluorescent lights — but the sashimi is as fresh as it gets without catching it yourself. Great for a no-frills seafood lunch. The fish auction tours happen early morning next door if you're into that. Lunch is the main event; they close in the afternoon.",cashOnly:false,kamaaina:null},
  {name:"Mud Hen Water",tier:"A",lat:21.2826,lng:-157.8128,category:"restaurant",subcategory:"hawaiian",tagline:"Modern Hawaiian cuisine in Kaimuki that showcases native ingredients — Ed Kenney's love letter to the land.",area:"Kaimuki",price:"$$",mustOrder:["Poi sourdough bread — tangy, purple-tinged, baked fresh daily","Kalo (taro) nachos — local twist on nachos with taro chips and kalua pork","Seasonal fish — always fresh, prepared with native Hawaiian flavors"],parking:"Street parking on Waialae Ave or side streets. Kaimuki parking can be tough on weekends — go early.",talkStory:"Chef Ed Kenney (also behind Town and Mud Hen Water) is deeply committed to local sourcing — the menu changes based on what Hawaiian farms have available. The name 'Mud Hen Water' is the literal English translation of Waikiki. The food is Hawaiian in spirit but modern in execution. The poi sourdough alone is worth the visit. Great Kaimuki date night option. Pair it with a walk up Waialae Ave to check out the other Kaimuki shops.",cashOnly:false,kamaaina:null},
  {name:"MW Restaurant",tier:"A",lat:21.2925,lng:-157.8515,category:"restaurant",subcategory:"fine-dining",tagline:"Chef Wade Ueoka's elevated take on local comfort food — the ahi cake and foie gras loco moco are iconic Honolulu dishes.",area:"Kakaako",price:"$$$",mustOrder:["ahi cake","foie gras loco moco","fried kalo"],parking:"Validated parking in building garage",talkStory:"Chef Wade Ueoka (formerly of Alan Wong's) takes classic local dishes and elevates them with fine-dining technique. The ahi cake stacks layers of seared ahi, avocado, and won ton crisps; the foie gras loco moco is a decadent riff on the plate-lunch staple. The dining room is upscale but welcoming. Lunch is a better value than dinner. Reservations recommended.",cashOnly:false,kamaaina:null},
  {name:"No Name Sandwich",tier:"B",lat:21.2836,lng:-157.8196,category:"restaurant",subcategory:"vietnamese",tagline:"Word-of-mouth banh mi shop on Waialae — the name tells you everything about the vibe.",area:"Kaimuki",price:"$",mustOrder:["classic banh mi — proper baguette, pickled veg, cilantro, jalapeño","grilled pork banh mi","try whatever daily special is on the board"],parking:"Street parking on Waialae Ave",talkStory:"A banh mi shop literally called No Name Sandwich — the kind of place you hear about from a friend, not a guidebook. Fresh baguettes, proper Vietnamese fillings, very low prices. Complements Lee's Bakery in Chinatown — two different neighborhoods, same genre, both beloved by locals. Waialae Ave location keeps it firmly in the Kaimuki local orbit. Closed Tuesdays. Opens 10am Wed–Mon.",cashOnly:false,kamaaina:null},
  {name:"O'Kims",tier:"A",lat:21.3118,lng:-157.8601,category:"restaurant",subcategory:"korean",tagline:"Korean fusion with French and Japanese technique — Yelp's #58 US restaurant in 2024. Truffle mandoo that'll rewire your brain.",area:"Chinatown / Downtown",price:"$$",mustOrder:["truffle mandoo — Korean dumplings elevated with truffle","kalbi short ribs — the classic, perfectly executed","black sesame cake — don't skip dessert"],parking:"Street parking on Nuuanu Ave; paid lots on Smith/Maunakea St",talkStory:"Chef Hyun Kim applies French, Italian, and Japanese techniques to Korean and local ingredients — the result is something genuinely new. Family-run on Nuuanu Ave in Chinatown, not a tourist magnet. Named Yelp's #58 of the Top 100 US Restaurants in 2024 — earned through real quality, not tourist review volume. Extensive vegan options including vegan kimchi. The small patio out back is a nice touch. Lunch and dinner, closed Mondays.",cashOnly:false,kamaaina:null},
  {name:"Olive Tree Cafe",tier:"A",lat:21.2757,lng:-157.7954,category:"restaurant",subcategory:"mediterranean",tagline:"The only legit Greek food on Oahu — cash only, BYOB, counter service, and a 20-year local cult following.",area:"Kahala",price:"$",mustOrder:["souvlaki plate — chicken or lamb, both excellent","falafel — crispy outside, fluffy inside","fresh fish special — ask what's available"],parking:"Small lot on Kilauea Ave; street parking on side streets",talkStory:"Open 20+ years and still the only Greek restaurant on Oahu worth visiting. Counter service, no frills, cash only, and BYOB — bring a bottle of wine and make an evening of it. The food quality is well above what the casual format suggests. Locals have been coming weekly for decades. Located next to Kapa Hale on Kilauea Ave. Dinner only, 5pm–9pm. Expect a wait on weekends — no reservations.",cashOnly:true,kamaaina:null},
  {name:"Omakase By Aung",tier:"A",lat:21.2756,lng:-157.8135,category:"restaurant",subcategory:"fine-dining",tagline:"Burmese-Japanese chef, 8 seats, no menu — just trust and exceptional fish.",area:"Kapahulu",price:"$$$",mustOrder:["omakase — there is no menu, the chef decides based on what's fresh"],parking:"Street parking on Kapahulu Ave; side streets off Winam Ave",talkStory:"Chef Aung brings a Burmese-Japanese perspective to edomae-style sushi in an intimate counter setting. About 8–10 seats, direct interaction with the chef throughout the meal. More personal and more 'insider' than Sushi Ginza Onodera (which is a global chain). Reserve ahead — seatings fill up. The experience runs $100–200+ depending on the day's catch. Kapahulu location keeps it off the tourist radar. If you want world-class omakase without Waikiki prices and crowds, this is the move.",cashOnly:false,kamaaina:null},
  {name:"Ono Seafood",tier:"S",lat:21.2811,lng:-157.8139,category:"restaurant",subcategory:"poke",tagline:"Made-to-order poke that locals will wait 30 minutes for — the shoyu ahi is non-negotiable.",area:"Kapahulu",price:"$",mustOrder:["shoyu ahi ($14–16)","spicy ahi"],parking:"Only 5–6 parking spots behind shop; park on side streets off Kapahulu",talkStory:"Founded by the Ono family — 'ono' means 'delicious' in Hawaiian. They cut fish to order, never pre-mixed. Tiny shop, no seating — take your bowl to Kapiolani Park (5 min walk) and eat with a Diamond Head view. Go Tue–Fri at 9am opening — sells out by early afternoon. Know your order before you reach the counter — line moves fast and staff expect efficiency.",cashOnly:false,kamaaina:null},
  {name:"Over Easy",tier:"B",lat:21.3976,lng:-157.7432,category:"restaurant",subcategory:"breakfast",tagline:"Kailua locals' go-to morning spot — no-fuss, no-gimmick breakfast done exceptionally well with a relaxed neighborhood vibe.",area:"Kailua Town",price:"$",mustOrder:["Brunch Bowl — rice, eggs, protein, and veggies all in one perfect bowl","Loco moco — classic Hawaii comfort breakfast done right","Seasonal specials — always worth asking about, changes frequently"],parking:"Street parking on Kailua Rd and side streets, small lot nearby",talkStory:"A homegrown Kailua breakfast spot that quickly became the Windward side's favorite morning ritual, known for using local ingredients and keeping the menu simple but executed perfectly. Tue–Sun, closed Monday. Weekday mornings are chill but weekends get packed by 8:30am. Call ahead to get on the waitlist if going on Saturday. The outdoor seating is the move on a nice Kailua morning.",cashOnly:false,kamaaina:null},
  {name:"Pai Honolulu",tier:"C",lat:21.3059,lng:-157.8632,category:"restaurant",subcategory:"fine-dining",tagline:"Hidden courtyard fine dining near Aloha Tower — chef-owned, locally sourced, and genuinely hard to find unless someone tells you.",area:"Chinatown / Downtown",price:"$$$",mustOrder:["seasonal tasting menu — changes regularly based on local sourcing","a la carte dishes — everything is made in-house","ask chef Kevin Lee what's best that night"],parking:"Harbor Court parking; street parking on Merchant St",talkStory:"Chef-owned by Kevin Lee since 2017, tucked in a courtyard at Harbor Court near Aloha Tower. The hidden location is part of the charm — you have to seek it out. Offers both a la carte and seasonal tasting menus, everything locally sourced and made in-house. The courtyard setting is quiet and elegant. A place for people who care about craft. Dinner only, Thu–Sat.",cashOnly:false,kamaaina:null},
  {name:"Palace Saimin",tier:"S",lat:21.3283,lng:-157.8542,category:"restaurant",subcategory:"hawaiian",tagline:"Hand-wrapped won tons since 1946 — if this place closes, Honolulu loses its soul.",area:"Kalihi",price:"$",mustOrder:["won ton min ($9–12, hand-wrapped won tons in pork-shrimp broth)","teriyaki beef sticks ($2–4 each — NON-NEGOTIABLE side order)"],parking:"Small lot next to the building on King Street",talkStory:"Family-run since 1946. Saimin is Hawaii's own noodle soup — evolved on sugar plantations where Japanese, Chinese, Filipino, and Portuguese workers shared ingredients. Combine with Helena's (also in Kalihi) for a full local food pilgrimage.",cashOnly:true,kamaaina:null},
  {name:"Pioneer Saloon",tier:"A",lat:21.2667,lng:-157.8135,category:"restaurant",subcategory:"plate-lunch",tagline:"Japanese-Hawaiian fusion plate lunches on Monsarrat Ave — the garlic ahi and curry are legendary neighborhood favorites.",area:"Kapahulu / Diamond Head",price:"$$",mustOrder:["garlic ahi steak","Japanese curry","SPAM musubi"],parking:"Street parking on Monsarrat Ave; arrive early",talkStory:"This tiny Monsarrat Avenue joint near Diamond Head serves Japanese-Hawaiian fusion plate lunches that punch way above their weight. The garlic ahi steak plate is the signature — seared rare with a rich garlic butter sauce over rice. The Japanese curry is thick, fragrant, and homestyle. A perfect post-Diamond Head hike meal. The line moves fast but seating is limited; many locals take it to nearby Kapiolani Park.",cashOnly:false,kamaaina:null},
  {name:"Podmore",tier:"B",lat:21.3077,lng:-157.8619,category:"restaurant",subcategory:"gastropub",tagline:"Sophisticated British gastropub by the Senia team — emerald booths, $30 cocktails, and everything made from scratch.",area:"Chinatown / Downtown",price:"$$$",mustOrder:["fish and chips — elevated but still recognizable","pot pie — rich and from-scratch","craft cocktails — the real draw"],parking:"Street parking on Merchant St; downtown parking garages",talkStory:"By the same team behind Senia (Chef Anthony Rush and Katherine Nomura). Styled like an elegant London lounge — emerald green booths, brass accents. British-inspired food (fish and chips, bangers and mash, pot pie) all made in-house with local ingredients. The cocktails (~$30) are serious. Small and intimate. A unique concept for Honolulu — nobody else is doing this. Dinner only, Tue–Sat.",cashOnly:false,kamaaina:null},
  {name:"Poke by the Pound",tier:"A",lat:21.3318,lng:-157.8712,category:"restaurant",subcategory:"poke",tagline:"Industrial-park address, zero ambiance, insane poke — Kalihi's best-kept secret that locals don't want you to know about.",area:"Kalihi",price:"$",mustOrder:["Shoyu ahi — classic and perfectly seasoned, sold by the pound","Spicy salmon — creamy spicy sauce with fresh salmon","Hawaiian-style ahi — traditional preparation with limu and Hawaiian salt"],parking:"Industrial park lot with plenty of free stalls",talkStory:"Tucked in a Kalihi industrial area, this no-frills poke counter built its reputation on fresh fish, fair prices, and word-of-mouth from construction workers and warehouse crews in the neighborhood. The name is literal — they sell poke by the pound and it's significantly cheaper than buying by the bowl. Buy a pound, grab rice separately, and you've got meals for two. The industrial park location keeps tourist traffic low.",cashOnly:false,kamaaina:null},
  {name:"Pupukea Grill",tier:"B",lat:21.6438,lng:-158.0562,category:"restaurant",subcategory:"poke",tagline:"Parked across from Banzai Pipeline since 2008 — the surfers lining up here aren't wrong, this is the North Shore's best poke bowl.",area:"Pupukea / North Shore",price:"$",mustOrder:["spicy tuna poke bowl","fish plate lunch"],parking:"Between Pupukea Beach Park and Sharks Cove",talkStory:"Started as a food truck parked across from Pipeline around 2008, built a loyal following among North Shore surfers and locals for fresh, no-frills poke bowls at beach prices. Tue–Sun 11am–5pm, closed Mon.",cashOnly:false,kamaaina:null},
  {name:"Purvé Donut Stop",tier:"A",lat:21.2832,lng:-157.8167,category:"restaurant",subcategory:"bakery",tagline:"Small-batch Hawaiian-flavored donuts that sell out by mid-morning — ube, lilikoi, haupia, and rotating seasonal specials.",area:"Kaimuki",price:"$",mustOrder:["ube donut — purple yam glaze, iconic","lilikoi donut — tart and sweet passionfruit","haupia donut — coconut cream filling"],parking:"Street parking on Waialae Ave; Kahala Mall parking nearby",talkStory:"Tiny Kaimuki donut shop on Waialae Ave with a 4.9 Google rating — one of the highest-rated food spots on Oahu. Everything is small-batch and made fresh daily with Hawaiian flavors. They sell out early, especially weekends — arrive by 7am to get the full selection. Leonard's has malasadas covered; Purvé is the donut move. Opens at 6am.",cashOnly:false,kamaaina:null},
  {name:"Rainbow Drive-In",tier:"S",lat:21.2753,lng:-157.8142,category:"restaurant",subcategory:"plate-lunch",tagline:"The plate lunch cathedral since 1961 — mixed plate with gravy is the move.",area:"Kapahulu",price:"$",mustOrder:["mixed plate with gravy ($12–14) — teriyaki beef + mahimahi + fried chicken, 2 scoops rice, mac salad"],parking:"Small lot in front, fills up fast at lunch — street parking on Kanaina Ave",talkStory:"Founded by Seiju Ifuku, a WWII 442nd Regiment veteran (the most decorated unit in US military history — all Japanese-Americans from Hawaii). 'Plate lunch' evolved from plantation-era bento boxes — Rainbow helped codify the modern format. Order at the window, grab your number. Take your plate to Kapiolani Park (one block) and eat under a tree with Diamond Head view — the local move.",cashOnly:false,kamaaina:null},
  {name:"Raised by the Waves",tier:"B",lat:21.6802,lng:-157.9521,category:"restaurant",subcategory:"vegan",tagline:"Kahuku Sugar Mill's plant-based gem — when North Shore surf culture goes vegan and does it exactly right, this is what you get.",area:"Kahuku / North Shore",price:"$",mustOrder:["acai bowls","smoothies","veggie sandwiches"],parking:"Located at Kahuku Sugar Mill",talkStory:"Born from North Shore surf culture, set up inside the historic Kahuku Sugar Mill complex alongside other small local vendors — proof that plant-based food belongs in Hawaii's food scene. Hours vary — check Instagram before going.",cashOnly:false,kamaaina:null},
  {name:"Romy's Kahuku Prawns",tier:"A",lat:21.6912,lng:-157.9728,category:"restaurant",subcategory:"food-truck",tagline:"Farm-raised shrimp from their own ponds — the butter garlic are plumper than Giovanni's, fight me.",area:"Kahuku",price:"$$",mustOrder:["steamed garlic prawns (steaming preserves the sweetness better than frying)"],parking:"Dirt lot next to the shrimp ponds",talkStory:"Filipino-owned family operation raising prawns in their own aquaculture ponds since the early 2000s — one of the few Kahuku shrimp spots where the shrimp literally come from right there on site. This is the spot locals recommend when they say 'skip Giovanni's.' Be patient — small family operation, not a fast-food line. Don't wander into the ponds.",cashOnly:true,kamaaina:null},
  {name:"Saigon's Restaurant",tier:"B",lat:21.2835,lng:-157.8108,category:"restaurant",subcategory:"vietnamese",tagline:"Honest Southern Vietnamese cooking on Waialae — the yellow curry wins people over and the pho is among the better bowls on the island.",area:"Kaimuki",price:"$",mustOrder:["pho — rich broth, generous noodles","yellow curry — the sleeper hit","vermicelli bowl — a solid everyday lunch"],parking:"Street parking on Waialae Ave",talkStory:"A neighborhood Vietnamese restaurant that's been on Waialae Ave for years, serving the Kaimuki/Kahala local crowd. Southern Vietnamese style — pho, banh mi, vermicelli, rice plates. Not fancy, not trendy, just well-executed Vietnamese food at reasonable prices. The Pig and The Lady covers Vietnamese-fusion; Saigon's is the traditional, affordable everyday counterpart. Lunch and dinner, closed Mondays.",cashOnly:false,kamaaina:null},
  {name:"Senia",tier:"S",lat:21.3107,lng:-157.8622,category:"restaurant",subcategory:"fine-dining",tagline:"Three-Michelin-star trained chef running two experiences under one roof — casual a la carte downstairs, elite 8-seat Chef's Counter upstairs.",area:"Chinatown / Downtown",price:"$$$",mustOrder:["Chef's Counter tasting menu (Fri/Sat only, reserve weeks ahead)","seared foie gras with haupia","any dessert — pastry chef Michelle Karr-Ueoka trained at Per Se and French Laundry"],parking:"Street parking on King/Nuuanu; paid lots on Smith St",talkStory:"Opened 2016 by Chef Anthony Rush and pastry chef Michelle Karr-Ueoka, both with decades under Alan Wong. Anthony trained in multiple three-Michelin-starred kitchens. The a la carte dining room is approachable and buzzy — come here on a weeknight for a great meal without the ceremony. The real move is the 8-seat Chef's Counter (Fri–Sat only) — a multi-course tasting menu that's one of the best dining experiences in Hawaii. Book weeks in advance. Won Hale 'Aina Gold for Best Tasting Menu. Tue–Sat dinner only.",cashOnly:false,kamaaina:null},
  {name:"Seven Brothers Burgers",tier:"A",lat:21.6435,lng:-157.9231,category:"restaurant",subcategory:"food-truck",tagline:"Samoan-Hawaiian family joint in Laie — the banana bread alone is worth the stop, the burgers are a bonus.",area:"Laie",price:"$",mustOrder:["Shez's Paniolo burger (thick patties, homemade onion rings, grilled pineapple, bacon, BBQ sauce)","Mom's Banana Bread"],parking:"Lot in front of the restaurant on Kamehameha Hwy",talkStory:"Founded 2009 by Art and Peggy Hannemann (bought the former Kahuku Grill). Opened Laie location specifically to serve locals and BYU-Hawaii students. The banana bread sells out early — get there before noon if that's your priority. Great stop on a North Shore loop. The seven brothers are literally seven brothers from the Hannemann family.",cashOnly:false,kamaaina:null},
  {name:"Shige's Saimin Stand",tier:"A",lat:21.5028,lng:-158.0211,category:"restaurant",subcategory:"saimin",tagline:"Townies willingly make the 30-minute drive to Wahiawa because nobody else makes saimin noodles in-house like Shige's does.",area:"Wahiawa / Central Oahu",price:"$",mustOrder:["saimin","teri cheeseburger"],parking:"Strip mall parking lot",talkStory:"Open since 1990, Shige's is one of the last places on Oahu making saimin noodles from scratch in-house — the handmade noodle texture is noticeably different from anywhere else. Tue–Sat 10am–9pm.",cashOnly:false,kamaaina:null},
  {name:"Side Street Inn",tier:"S",lat:21.2946,lng:-157.8472,category:"restaurant",subcategory:"plate-lunch",tagline:"Where Honolulu chefs eat on their day off — the fried rice feeds four and costs sixteen bucks.",area:"Ala Moana",price:"$$",mustOrder:["pan-fried pork chops ($16–20, THE signature dish)","signature fried rice ($14–16, enormous portions)"],parking:"Street parking",talkStory:"Founded by Colin Nishida, James Beard semifinalist and one of Hawaii's most respected chefs. After Honolulu's best chefs close their own restaurants at 10–11pm, they come here for Colin's pork chops and cold beer. Order family-style — 3–4 dishes for 2 people, split everything. Go late night (after 10pm) for the authentic chef crowd.",cashOnly:false,kamaaina:null},
  {name:"Side Street Inn (Kapahulu)",tier:"A",lat:21.276,lng:-157.8139,category:"restaurant",subcategory:"plate-lunch",tagline:"Where Honolulu's best chefs eat on their nights off — the pan-fried pork chops and signature fried rice are legendary for a reason.",area:"Kapahulu",price:"$$",mustOrder:["pan-fried pork chops","boneless kalbi","signature fried rice"],parking:"Small lot behind building, street parking on side streets",talkStory:"Second location of Colin Nishida's legendary Side Street Inn, opened on Kapahulu Ave to be closer to the Kaimuki/Kapahulu dining crowd. Same massive portions and chef-industry following as the original. Mon–Fri from 4pm, dine-in. Weekends get busy.",cashOnly:false,kamaaina:null},
  {name:"Southern Love",tier:"A",lat:21.3017,lng:-157.8577,category:"restaurant",subcategory:"southern",tagline:"The only serious soul food on Oahu — shrimp and grits that locals call the best in Hawaii, cooked to order in Kakaako.",area:"Kakaako",price:"$$",mustOrder:["shrimp and grits — widely called the best in Hawaii","cajun salmon — perfectly seasoned","catfish po'boy — Southern classic done right"],parking:"Street parking on Queen St; paid lots in Kakaako",talkStory:"Chef Corey Love and partner Elizabeth Martinez brought authentic Southern soul food to an island that desperately needed it. Everything is cooked to order — fried chicken, BBQ ribs, biscuits and gravy, catfish. Featured on Hawaii News Now. Short hours, closed Sun–Mon, limited parking — all the signs of a real local joint, not a tourist operation. Opened 2023 and already has a devoted following with a 4.8 Google rating. The only place on Oahu filling this niche.",cashOnly:false,kamaaina:null},
  {name:"St. Louis Drive Inn",tier:"B",lat:21.2854,lng:-157.8233,category:"restaurant",subcategory:"plate-lunch",tagline:"Old-guard plate lunch drive-inn near Chaminade — formica tables, walk-up counter, and food that tastes like someone's tutu made it.",area:"Kaimuki / St. Louis Heights",price:"$",mustOrder:["fried chicken plate — crispy and generous","beef stew — local-style comfort food","loco moco — classic drive-inn execution"],parking:"Small lot on Waialae Ave; street parking available",talkStory:"One of the old-guard drive-inns that defined the plate lunch genre in Honolulu. Decades old, no-frills, two scoops rice, mac salad, protein — the formula that built Hawaii's lunch culture. The crowd is Chaminade students, Kaimuki workers, and families who've been coming for generations. Rainbow Drive-In gets the fame; St. Louis Drive Inn is the quieter neighborhood equivalent. Opens early, closes mid-afternoon.",cashOnly:false,kamaaina:null},
  {name:"Sunrise Restaurant Hawaii",tier:"A",lat:21.2762,lng:-157.8155,category:"restaurant",subcategory:"japanese",tagline:"Okinawan-style home cooking on Kapahulu — a cuisine you can't find outside Hawaii or Okinawa itself.",area:"Kapahulu",price:"$",mustOrder:["Okinawan soba — different from mainland Japanese soba, thicker and heartier","goya champuru — bitter melon stir-fry, the classic Okinawan dish","andagi — Okinawan-style doughnut"],parking:"Street parking on Kapahulu Ave; small lot nearby",talkStory:"Hawaii has the largest Okinawan population outside Japan, and places like Sunrise keep that culinary heritage alive. This is home-style Okinawan cooking — not fancy, not trendy, just the food that local Okinawan families grew up eating. The crowd is primarily older local Japanese and Okinawan families. A deeply cultural pick that tells a story about Hawaii's immigrant history. Lunch and dinner, closed Mondays.",cashOnly:false,kamaaina:null},
  {name:"Surf N Salsa",tier:"B",lat:21.5955,lng:-158.1034,category:"restaurant",subcategory:"mexican",tagline:"Handmade corn tortillas and house-made salsa in a food truck on Kamehameha Highway — the fish tacos here make you question why you ever ate elsewhere.",area:"Haleiwa / North Shore",price:"$",mustOrder:["Fish tacos — fresh catch in handmade corn tortillas with house salsa","Carnitas tacos — slow-cooked pork, tender and well-seasoned","Housemade salsa — get the hot if you can handle it"],parking:"Dirt pulloff lot right next to the truck",talkStory:"A roadside food truck on Kamehameha Highway near Haleiwa that built a cult following among North Shore surfers and locals by making real-deal Mexican food with handmade tortillas and fresh-caught fish. Closed Sundays. The fish changes based on what's fresh — ask what they're using today. Lines build up around lunchtime so going slightly off-peak pays off. The green salsa is the sleeper hit.",cashOnly:false,kamaaina:null},
  {name:"Sushi Ginza Onodera",tier:"A",lat:21.2836,lng:-157.8303,category:"restaurant",subcategory:"fine-dining",tagline:"Tokyo-level omakase in Waikiki — the fish is flown in from Tsukiji and the craft is impeccable.",area:"Waikiki",price:"$$$",mustOrder:["Omakase — the full chef's counter experience, ~20 pieces of seasonal nigiri","Otoro — fatty tuna belly, melt-in-your-mouth perfection","Uni — seasonal sea urchin, often from Hokkaido"],parking:"Valet at the hotel or public parking at Waikiki Trade Center garage on Kuhio Ave.",talkStory:"This is a splurge — omakase runs $200-300+ per person — but it's genuinely world-class sushi without flying to Tokyo. The Honolulu outpost is part of a global chain with locations in Ginza, NY, and LA. Fish is sourced from Japan's top markets. Sit at the counter for the full experience. Make reservations well in advance, especially weekends. If you're celebrating something special and love sushi, this is the one.",cashOnly:false,kamaaina:null},
  {name:"Taco Kahuku",tier:"B",lat:21.6803,lng:-157.9557,category:"restaurant",subcategory:"food-truck",tagline:"North Shore taco truck with fresh fish tacos that rival the shrimp trucks without the crazy lines.",area:"North Shore (Kahuku)",price:"$",mustOrder:["Fresh fish taco — grilled catch of the day with slaw and crema","Garlic shrimp taco — North Shore shrimp truck flavors in taco form","Burrito bowl — rice, beans, fresh fish, and all the fixings"],parking:"Roadside pull-off area on Kamehameha Hwy near the other Kahuku food trucks.",talkStory:"While everyone lines up at the famous shrimp trucks, Taco Kahuku quietly serves some of the best fish tacos on the North Shore. The fish is fresh and local, the portions are generous, and the wait is usually way shorter than Giovanni's or Romy's next door. It's a great alternative if someone in your group doesn't want shrimp. Located in the same Kahuku food truck strip so you can mix and match.",cashOnly:false,kamaaina:null},
  {name:"Tamura's Fine Wine & Liquors",tier:"A",lat:21.4234,lng:-157.7486,category:"restaurant",subcategory:"poke",tagline:"Walk into a wine shop, walk out with the best poke in Kailua — trust the process.",area:"Kailua",price:"$",mustOrder:["spicy ahi (top seller)","garlic shrimp poke (hard to find elsewhere)","furikake salmon poke"],parking:"Ample parking at Aikahi Park Shopping Center",talkStory:"The Tamura family started as a legit wine/liquor store, then added a poke counter that became equally famous. You can taste before buying. The move: grab a pound of poke + a bottle of wine, drive to Kailua Beach or Lanikai for sunset. Best selection before 1pm.",cashOnly:false,kamaaina:null},
  {name:"Tamura's Fine Wine & Liquors (Waialae)",tier:"A",lat:21.2794,lng:-157.7901,category:"restaurant",subcategory:"poke",tagline:"The Kahala-area location of Oahu's best poke-inside-a-liquor-store situation — grab a bottle and a pound of spicy ahi, you've cracked the code.",area:"Kaimuki / Kahala",price:"$",mustOrder:["spicy ahi poke","furikake salmon"],parking:"Strip mall lot on Waialae Ave",talkStory:"The Waialae branch of Tamura's brings the same killer poke counter and curated wine selection to the Kaimuki/Kahala side of town — same family, same quality, closer to town. Mon–Sun 9:30am–8pm. Best selection before 1pm.",cashOnly:false,kamaaina:null},
  {name:"Tanioka's Seafoods",tier:"A",lat:21.3841,lng:-158.0011,category:"restaurant",subcategory:"poke",tagline:"West-side pilgrimage spot — the smoked meat counter alone is worth the drive from town.",area:"Waipahu",price:"$",mustOrder:["limu ahi poke","ahi patties ($3–4 each, crispy outside, tender inside — tourists overlook these)","the smoked marlin"],parking:"Strip mall lot, decent parking",talkStory:"Multi-generational family business rooted in Waipahu's plantation community — 'Grandma Tanioka's' recipes are the foundation. You can taste before buying a pound. Bring a cooler for the drive home. Great party platters for local gatherings. Best selection before 1pm.",cashOnly:false,kamaaina:null},
  {name:"Ted's Bakery",tier:"A",lat:21.6485,lng:-158.0595,category:"restaurant",subcategory:"bakery",tagline:"North Shore legend famous for haupia chocolate cream pie — the plate lunches fuel surfers year-round.",area:"North Shore (Sunset Beach)",price:"$",mustOrder:["Haupia chocolate cream pie — the iconic pie, chocolate and coconut pudding layers","Garlic shrimp plate — North Shore style, served with rice","Kalua pork plate lunch — smoky, tender, with mac salad and rice"],parking:"Small parking lot right in front on Kamehameha Hwy. Usually can find a spot except peak surf season weekends.",talkStory:"Ted's has been a North Shore institution since 1987. The haupia pie is so famous they ship it to the mainland. Every surfer, every local, every North Shore visitor ends up here at some point. The plate lunches are big, cheap, and perfect after a morning at Pipeline or Sunset. Get the pie to go for the beach — haupia pie on the sand watching the sunset is peak North Shore living. They open early so it's a solid breakfast stop too.",cashOnly:false,kamaaina:null},
  {name:"Teishoku Restaurant",tier:"A",lat:21.3297,lng:-157.8614,category:"restaurant",subcategory:"japanese",tagline:"Japanese set meals in a Kalihi shopping center — miso butterfish, miso soup, rice, pickles, all for one price. Tourists will never find this.",area:"Kalihi",price:"$$",mustOrder:["miso butterfish teishoku — the signature set meal","chicken katsu set — crispy and satisfying","any daily special — the rotating items are where the kitchen shines"],parking:"Kamehameha Shopping Center lot on N School St",talkStory:"Teishoku means 'set meal' in Japanese — a complete meal with miso soup, salad, pickled vegetables, rice, and your choice of protein, all on one tray. This is how locals eat lunch in Kalihi. N School Street is deep-neighborhood territory — no tourist has ever wandered here. Featured in Honolulu Magazine as a hidden gem. Fast service, very reasonable prices. Lunch and dinner, closed Mondays.",cashOnly:false,kamaaina:null},
  {name:"The Hibachi (Kailua)",tier:"B",lat:21.3978,lng:-157.7449,category:"restaurant",subcategory:"poke",tagline:"Windward side's hidden poke gem — assembled fresh to order right in front of you, with variety that puts the tourist spots to shame.",area:"Kailua",price:"$",mustOrder:["Fresh poke bowl — built to order with your choice of fish and toppings","Spicy ahi poke — creamy and flavorful, always a solid pick","Daily specials — ask what's new, they rotate preparations regularly"],parking:"Shopping center lot with ample parking",talkStory:"A neighborhood poke and grill counter in Kailua that earned a loyal Windward side following by keeping prices fair, fish fresh, and preparations simple — the kind of spot regulars visit multiple times a week. Check hours as they can vary. Lunch rush is the busiest — going mid-afternoon is the sweet spot. Watch them build your bowl and ask for recommendations on what fish came in fresh that day.",cashOnly:false,kamaaina:null},
  {name:"The Nighthawk",tier:"A",lat:21.3076,lng:-157.8618,category:"restaurant",subcategory:"american",tagline:"Chicago-style comfort food in a historic Chinatown building — Italian beef sandwiches, Maxwell Street Polish, and late-night Kung Fu Ham.",area:"Chinatown / Downtown",price:"$",mustOrder:["Italian beef sandwich — Chicago-style, juicy and proper","Chicago-style hot dog — no ketchup, ever","Kung Fu Ham — deep-fried pork belly with Thai chili garlic"],parking:"Street parking on S King St; paid lots on Smith/Maunakea",talkStory:"A Midwest transplant concept that somehow feels perfectly at home in Chinatown. Exposed brick walls, late-night hours, and a menu of Chicago comfort food you can't get anywhere else on the island. The Italian beef sandwich is authentic. The Kung Fu Ham (deep-fried pork belly with Thai chili garlic) is a house original that bridges Chicago and Honolulu. Downtown workers for lunch, Chinatown bar crowd for late night. Open until midnight.",cashOnly:false,kamaaina:null},
  {name:"The Pig and the Lady",tier:"A",lat:21.3118,lng:-157.8628,category:"restaurant",subcategory:"fine-dining",tagline:"Vietnamese-Hawaiian fusion that put Chinatown dining on the map — Chef Andrew Le's pho French dip is genius.",area:"Chinatown",price:"$$$",mustOrder:["Pho French dip — prime rib dipped in pho broth, absolute game changer","Crispy crepe banh xeo — stuffed with shrimp, pork, and herbs","Smoked meat pho — rich bone broth with brisket and all the fixings"],parking:"Street parking on Smith or Hotel St. Chinatown garage at 1130 N Nimitz Hwy is cheapest. Meter parking free after 6pm.",talkStory:"Chef Andrew Le started at the KCC Farmers Market and blew up from there. The dinner menu is creative Vietnamese-meets-local, and the Saturday farmers market booth still has lines. Dinner reservations recommended — walk-ins can try the bar. The Chinatown location has serious energy on Friday and Saturday nights. If you want the more casual lunch vibe, they do a killer weekday lunch too.",cashOnly:false,kamaaina:null},
  {name:"Tokkuri Tei",tier:"S",lat:21.275,lng:-157.8156,category:"restaurant",subcategory:"izakaya",tagline:"Honolulu's original izakaya — the garlic ahi belly and tofu steak are why reservations fill a week out.",area:"Kapahulu",price:"$$",mustOrder:["ika yaki (squid pancake, $12–14 — THE signature dish)","maguro tataki ($14–16)","garlic edamame","nasu dengaku (miso eggplant)","black sesame ice cream"],parking:"Street parking on side streets mauka of Kapahulu",talkStory:"Opened early 1990s by chef/owner Hide Yoshimoto (Hide-san) — one of the first authentic izakayas in Hawaii, helped spark the island's izakaya boom. Order multiple small plates to share — izakaya style means rounds of dishes throughout the evening, not one entree per person. Sake pairing is the proper move — ask staff to guide you. Go Tue/Wed for walk-in seating. Say 'kampai' before your first drink.",cashOnly:false,kamaaina:null},
  {name:"Tonkatsu Tamafuji",tier:"A",lat:21.2799,lng:-157.785,category:"restaurant",subcategory:"japanese",tagline:"Kaimuki's tonkatsu master — perfectly fried heritage pork cutlets with house-ground cabbage and secret dipping sauce.",area:"Kaimuki",price:"$$",mustOrder:["rosu katsu set","hire katsu set","menchi katsu"],parking:"Street parking on Waialae Ave; small lot behind",talkStory:"This Kaimuki gem serves what many locals consider the best tonkatsu on the island. The pork cutlets are made with premium heritage pork, breaded in ultra-fine panko, and fried to an impossibly crispy golden exterior while staying juicy inside. The house-ground cabbage is fluffy and fresh, and the dipping sauce has a secret recipe. Lunch lines form early — arrive by 11:30am or expect a 30-minute wait.",cashOnly:false,kamaaina:null},
  {name:"Totoya Kaimuki",tier:"A",lat:21.2844,lng:-157.8145,category:"restaurant",subcategory:"japanese",tagline:"Sixteen-seat kaisendon counter where the sashimi is piled so thick you can barely see the rice — get there early or join the wait.",area:"Kaimuki",price:"$$",mustOrder:["kaisen don — the signature sashimi rice bowl with daily fish selection","negitori don — torched salmon belly over rice","miso soup — yuzu or ginger-infused, not an afterthought"],parking:"Street parking on 12th Ave and side streets; competitive during lunch rush",talkStory:"Opened late 2024 on 12th Ave in Kaimuki and immediately became one of the hardest lunch seats on the island. Only 16 counter seats with an open kitchen — you watch your bowl being built. The fish quality is exceptional, sourced daily. Lines form before opening. The move is to come at an off-peak time (weekday, 1:30pm or late dinner). 4.8 Google stars with 200+ reviews — one of the highest-rated new restaurants on Oahu. Daily 11am–2:30pm and 5pm–8:30pm.",cashOnly:false,kamaaina:null},
  {name:"Uncle Bo's",tier:"A",lat:21.2828,lng:-157.8136,category:"restaurant",subcategory:"izakaya",tagline:"Kaimuki pupu bar with creative local-Asian fusion — the garlic truffle fries and dynamite are legendary.",area:"Kaimuki",price:"$$",mustOrder:["Garlic truffle fries — crispy, truffled, and addictive","Dynamite — baked seafood with spicy mayo, a local izakaya classic","Bo's fried rice — loaded with whatever's good, different every time"],parking:"Street parking on Waialae Ave and side streets. Kaimuki is tight — circle once or twice.",talkStory:"Uncle Bo's is the Kaimuki spot for late-night grinds and drinks with friends. Chef Bo Pathammavong brings Lao and local flavors together in creative pupu that are perfect for sharing. The vibe is loud, fun, and always packed on weekends. Great for groups — order a bunch of small plates and share everything. They're open late by Honolulu standards which makes it a go-to after other restaurants close. Reservations recommended on weekends.",cashOnly:false,kamaaina:null},
  {name:"Utage Restaurant & Lounge",tier:"A",lat:21.3243,lng:-157.8564,category:"restaurant",subcategory:"japanese",tagline:"Family-run Okinawan restaurant in Kalihi that literally calls regulars when specials are coming — 25 years of that kind of aloha.",area:"Kalihi",price:"$$",mustOrder:["ahi nori tempura — the signature","konbu maki — only made twice a year, ask when the next one is","daily specials — whatever the kitchen is excited about"],parking:"City Square Shopping Center lot on Kalani St",talkStory:"Run by the Kishimoto family since 2001 — daughter Edna handles front of house, son Ivan runs the kitchen. They keep a handwritten call list of regulars and phone them when favorite specials are available. That detail alone tells you everything about this place. Okinawan and Japanese cuisine in Kalihi's City Square Shopping Center, far from any tourist path. The Okinawan dishes connect to Hawaii's deep cultural ties with Okinawa. Lunch and dinner, closed Mondays.",cashOnly:false,kamaaina:null},
  {name:"Waiahole Poi Factory",tier:"A",lat:21.4832,lng:-157.8514,category:"restaurant",subcategory:"hawaiian",tagline:"One of the last real poi factories on Oahu — fresh poi, laulau, and squid luau in a Windward valley setting.",area:"Waiahole",price:"$",mustOrder:["Fresh poi — hand-pounded, creamy, the real deal","Laulau — pork and fish wrapped in taro leaves, steamed until melt-tender","Squid luau — squid simmered in coconut milk and taro leaves"],parking:"Small gravel lot right off Kamehameha Hwy. Easy to spot.",talkStory:"Waiahole Poi Factory is a cultural treasure. They've been making poi here in the valley for generations — this is one of the last places on Oahu where you can get fresh poi made the traditional way. The setting is beautiful — lush Windward valley with the Koolau mountains right there. Open limited hours (usually weekends and some weekdays), so check before you go. This is real Hawaiian food in a real Hawaiian place, not a tourist luau. Combine with a scenic drive up Kamehameha Hwy.",cashOnly:true,kamaaina:null},
  {name:"Yakitori Ando",tier:"A",lat:21.28,lng:-157.783,category:"restaurant",subcategory:"japanese",tagline:"Tiny Kaimuki izakaya serving omakase-only yakitori over binchotan charcoal — Oahu's best-kept dining secret.",area:"Kaimuki",price:"$$$",mustOrder:["omakase yakitori course","tsukune with egg yolk","chicken hearts"],parking:"Street parking on Center St and Waialae Ave",talkStory:"With only a handful of counter seats, Chef Ando grills each skewer over binchotan charcoal with Tokyo-level precision — chicken hearts, tsukune with runny egg yolk, and seasonal specials. The omakase-only format means you sit back and trust the chef. Book 3-4 weeks in advance; locals consider this the best-kept dining secret on Oahu. The intimate counter experience takes about 90 minutes and is unforgettable.",cashOnly:false,kamaaina:null},
  {name:"Yama's Fish Market",tier:"A",lat:21.2877,lng:-157.8229,category:"restaurant",subcategory:"plate-lunch",tagline:"The local plate lunch and poke counter that office workers plan their whole week around.",area:"Moiliili",price:"$",mustOrder:["Ahi poke — classic shoyu or spicy, always fresh-cut","Kalua pig plate — smoky pulled pork with cabbage, rice, and mac salad","Laulau plate — steamed pork and taro leaf with two scoops rice"],parking:"Small lot that fills up fast at lunch. Try street parking on Young St or Isenberg.",talkStory:"Yama's has been the Moiliili lunch spot for decades. The poke counter is legit — locals argue whether Yama's or Ono Seafood has the better ahi poke (answer: both are great, different style). The plate lunches are huge and cheap. Lunch rush is 11:30-1pm and the line goes out the door. Go at 11 or after 1:30. They also sell poke by the pound to take home — great move for a beach day.",cashOnly:false,kamaaina:null},
  {name:"Young's Fish Market",tier:"A",lat:21.3152,lng:-157.858,category:"restaurant",subcategory:"hawaiian",tagline:"Old-school Hawaiian plate lunch counter in Kalihi — massive portions, family recipes, and some of the best poke on the island.",area:"Kalihi",price:"$",mustOrder:["Hawaiian plate — laulau, kalua pig, lomi salmon, poi or rice","Poke by the pound — ahi, tako, or shoyu varieties","Pipikaula (dried beef)","Squid luau"],parking:"Small lot on Liliha St. Street parking on side streets",talkStory:"Young's has been serving Hawaiian food in Kalihi since 1951 and it's where local families go for plate lunch, poke, and luau supplies. The portions are enormous and the prices are fair. Their poke counter is one of the best on the island — fresh ahi, tako, and various preparations sold by the pound. The Hawaiian plate is a complete meal: laulau, kalua pig, lomi salmon, and your choice of poi or rice. Not a fancy sit-down spot — order at the counter, grab a seat at the plastic tables, and eat. This is real local food, not the sanitized tourist version.",cashOnly:false,kamaaina:null},
  {name:"Zippy's Restaurant",tier:"S",lat:21.2854,lng:-157.8365,category:"restaurant",subcategory:"plate-lunch",tagline:"Hawaii's diner chain that every local grew up on — chili and zip packs are a way of life.",area:"King Street",price:"$",mustOrder:["Zippy's Chili — the iconic thick, beefy chili that's been the same since 1966","Zip Pack — fried chicken, chili, rice, and mac salad in one legendary combo","Napoleon Bakery cream puffs — the grab-and-go bakery case is dangerously good"],parking:"Most locations have their own lot. King Street location has a parking lot behind the building.",talkStory:"Started in 1966 by Francis Higa and Charles Toguchi. There are over 20 locations across Oahu, but the King Street one near McCully is the classic. Zippy's chili recipe is a legit state secret — they've never revealed it. Every local kid grew up eating here after practice, after prom, at 2am. The Napoleon Bakery inside sells cakes for every birthday party on the island. It's not fancy, but it's home.",cashOnly:false,kamaaina:null},
  {name:"Aoki's Shave Ice",tier:"A",lat:21.5908,lng:-158.1022,category:"shave-ice",subcategory:"classic",tagline:"Directly across from Matsumoto with a fraction of the line — locals' quiet favorite since 1981.",area:"Haleiwa",price:"$",mustOrder:["lychee","lilikoi","tiger's blood","green tea","azuki beans + condensed milk combo"],parking:"Street spots fill fast — same parking situation as Matsumoto",talkStory:"The Aoki family are Haleiwa OGs — while tourists mob Matsumoto, locals quietly slip into Aoki's. Open since 1981. If you want to compare the two (and you should), get a small at each. The azuki beans + condensed milk combo is the local move.",cashOnly:false,kamaaina:null},
  {name:"Island Snow",tier:"S",lat:21.3946,lng:-157.7384,category:"shave-ice",subcategory:"classic",tagline:"Obama's Kailua go-to — every presidential visit = a stop here. Also a legit surf shop.",area:"Kailua",price:"$",mustOrder:["any flavor with vanilla ice cream on the bottom (the Island Snow signature)","li hing mui powder on top","passion orange guava (POG)"],parking:"Parking in the Kailua Shopping Center lot next door",talkStory:"A Kailua institution way before the Obama fame, doubling as a surf/skate shop since the '90s. The shop sponsors local surf groms and is deeply embedded in the Kailua community. Combine with a Kailua Beach day — it's a 5-minute walk. Every order comes with a scoop of vanilla ice cream buried at the bottom of the cone — that's the Island Snow signature. Add li hing mui powder on top for the local move.",cashOnly:false,kamaaina:null},
  {name:"Island Vintage Shave Ice",tier:"B",lat:21.2841,lng:-157.8306,category:"shave-ice",subcategory:"gourmet",tagline:"Organic syrups and fresh fruit toppings in the heart of Waikiki — gourmet done right.",area:"Waikiki",price:"$$",mustOrder:["Aloha — organic guava, passion fruit, and coconut cream","North Shore — pineapple with fresh mango chunks on top","add mochi balls and condensed milk drizzle"],parking:"Royal Hawaiian Center parking garage — validate at the shop",talkStory:"Yeah it's in Waikiki and yeah it's pricier, but Island Vintage actually uses organic Hawaiian-grown fruit syrups and the quality is legit. The shave ice is topped with real fruit pieces, not just syrup. It's connected to their acai bowl operation so everything is fresh. Best spot if you're already in Waikiki and don't want to drive 45 minutes for shave ice. The line moves fast even when it looks long.",cashOnly:false,kamaaina:null},
  {name:"Kaimana Shave Ice",tier:"A",lat:21.5791,lng:-158.1026,category:"shave-ice",subcategory:"gourmet",tagline:"All-natural fruit syrups with half the sugar and scratch-made ice cream — Haleiwa's gourmet contender to Matsumoto.",area:"Haleiwa",price:"$",mustOrder:["Any flavor with homemade mac nut ice cream — the signature combo","Liliko'i or mandarin — the tropical fruit syrups shine","Coffee flavor — unique and surprisingly good"],parking:"Street parking along Kamehameha Hwy in Haleiwa town",talkStory:"Opened in 2018 in a barn-red building on Haleiwa's main road, Kaimana quickly became the locals' alternative to the Matsumoto tourist line. All syrups are made from real fruit with about half the sugar of conventional shave ice. The ice cream is made from scratch daily — vanilla, mac nut, banana, and a vegan option that's surprisingly rich. One size, one or two flavors, done right. Mon–Sat noon–4:30pm, closed Sundays. Small-batch means flavors rotate, so ask what's fresh.",cashOnly:false,kamaaina:null},
  {name:"Matsumoto Shave Ice",tier:"S",lat:21.5911,lng:-158.1028,category:"shave-ice",subcategory:"classic",tagline:"The North Shore icon since 1951 — the rainbow combo is non-negotiable.",area:"Haleiwa",price:"$",mustOrder:["rainbow combo (strawberry-lemon-pineapple)","lilikoi","li hing mui","coconut","azuki beans + ice cream on the bottom"],parking:"Street parking — fills fast on weekends",talkStory:"The original wooden building and vintage sign are historic landmarks. Open since 1951. The T-shirt they sell ($15–20) is a legit souvenir. If the line is insane, walk 50 feet to Aoki's instead. ALWAYS add azuki beans + ice cream on the bottom ($1–2 extra) — that's the real order. Lines can hit 30+ min on weekends so go early or late.",cashOnly:false,kamaaina:null},
  {name:"Monsarrat Shave Ice",tier:"A",lat:21.2709,lng:-157.8164,category:"shave-ice",subcategory:"gourmet",tagline:"Real fruit compotes layered into silky ice — the gourmet shave ice that Diamond Head locals swear by.",area:"Diamond Head",price:"$",mustOrder:["Any flavor with ice cream and mochi balls — the full experience","Coconut cream or matcha — the house signatures","Mango or mixed berry — pure real fruit, no artificial syrup"],parking:"Street parking on Monsarrat Ave — limited but usually findable on weekdays",talkStory:"This little window next to Pioneer Saloon uses real organic fruit jams and compotes instead of artificial syrups — you can taste the difference immediately. Each cup is carefully layered by hand. Open daily 11am–5:30pm, closed on rainy days (they're serious about that). Add the Meadow Gold ice cream and shiratama mochi balls for the full experience. One of the best kept secrets on Monsarrat Ave's food row.",cashOnly:false,kamaaina:null},
  {name:"Shimazu Shave Ice",tier:"B",lat:21.3207,lng:-157.8696,category:"shave-ice",subcategory:"classic",tagline:"Old-school Kalihi corner shop — shave ice the way your tutu remembers it.",area:"Kalihi",price:"$",mustOrder:["rainbow with ice cream on the bottom","li hing mui — perfectly sour-sweet","vanilla with azuki beans"],parking:"Street parking on Kalihi St — not hard to find a spot",talkStory:"Shimazu has been around for decades in Kalihi, a neighborhood tourists never see. The shave ice is classic-style with fine ice and local-brand syrups. The aunties who work here know every kid in the neighborhood by name. It's cash-friendly and no-frills — just a counter window and a bench outside. This is the kind of place that makes Kalihi feel like old Hawaii.",cashOnly:true,kamaaina:null},
  {name:"Uncle Clay's House of Pure Aloha",tier:"S",lat:21.2857,lng:-157.8011,category:"shave-ice",subcategory:"gourmet",tagline:"All-natural syrups and real fruit — this is shave ice elevated to an art form.",area:"Aina Haina",price:"$",mustOrder:["lilikoi cream — tangy and rich, their signature","strawberry lemonade with li hing mui powder on top","haupia with azuki beans on the bottom"],parking:"Small lot in Aina Haina Shopping Center — easy parking",talkStory:"Uncle Clay's is the real deal — all syrups are made in-house from real fruit, no artificial colors or flavors. They've won every shave ice award the islands have. The shop is in a humble strip mall in Aina Haina, which keeps it mostly locals. Ask for the 'Pure Aloha' combo if you can't decide — they'll set you up right. Clayton and his family run the place with genuine aloha spirit.",cashOnly:false,kamaaina:null},
  {name:"Waiola Shave Ice",tier:"S",lat:21.2919,lng:-157.8358,category:"shave-ice",subcategory:"classic",tagline:"Honolulu institution since 1979 — cloud-soft ice that soaks up syrup better than anywhere.",area:"Moiliili",price:"$",mustOrder:["any flavor — the ice texture is the star here","azuki beans","li hing mui"],parking:"Street parking on Waiola St or in the small lot behind the shop",talkStory:"This is where UH Manoa students and Moiliili families have come for decades — no tourists, just neighborhood people. The owner is there most days. Won Hawaii's Best Shave Ice multiple years running. It's in a residential area so don't blast music or take up the whole sidewalk. Known for having the softest, finest-shaved ice on the island — it's almost powdery, which means the syrup absorbs completely instead of pooling at the bottom.",cashOnly:false,kamaaina:null},
  {name:"Green Gypsy Thrift Shop",tier:"B",lat:21.577,lng:-158.1295,category:"shopping",subcategory:"thrift-store",tagline:"A curated thrift store in the old Waialua Sugar Mill — vintage aloha shirts, surfwear, and bohemian North Shore finds.",area:"North Shore",price:"$",parking:"Free lot at the Sugar Mill",hours:"Daily 10am-5pm (hours may vary)",bestTime:"Saturday when combined with the Waialua Farmers Market",kidFriendly:true,talkStory:"A hidden gem thrift store inside the old Waialua Sugar Mill compound on the North Shore. The curated selection includes vintage aloha shirts, jewelry, hats, shoes, swimsuits, and wetsuits at excellent prices. The vibe is bohemian and laid-back, fitting perfectly with the North Shore lifestyle. Locals who surf the North Shore regularly shop here for gear and vintage finds. Combine with the Waialua Farmers Market on Saturday mornings.",kamaaina:null},
  {name:"Mori by Art + Flea",tier:"B",lat:21.31,lng:-157.863,category:"shopping",subcategory:"local-design",tagline:"Local fashion, home goods, and art from up-and-coming Hawaii-based artists and designers — each visit feels fresh.",area:"Chinatown / Downtown",price:"$$",parking:"Street parking; walk from downtown",hours:"Tue-Sat 11am-6pm; later on First Fridays",bestTime:"First Friday evenings when Chinatown's art walk is happening",kidFriendly:true,talkStory:"The brick-and-mortar location of Art + Flea (Hawaii's first urban street market) curates local fashion, home goods, stationery, and art from up-and-coming Hawaii-based artists and designers. The selection changes regularly, so each visit feels fresh. This is where creative Honolulu shops for locally designed T-shirts, prints, ceramics, and accessories you can't find anywhere else.",kamaaina:null},
  {name:"Na Mea Hawaii",tier:"A",lat:21.291,lng:-157.854,category:"shopping",subcategory:"hawaiian-goods",tagline:"The best shop on Oahu for genuinely Hawaiian-made gifts — koa wood bowls, lauhala weaving, and books by Native Hawaiian authors.",area:"Kakaako",price:"$$-$$$",parking:"Free parking at Ward Village",hours:"Mon-Sat 10am-6pm, Sun 10am-4pm",bestTime:"Weekday afternoons; check for cultural workshops and author events",kidFriendly:true,talkStory:"The single best shop on Oahu for gifts and goods that are genuinely Hawaiian-made. From hand-carved koa wood bowls to books by Native Hawaiian authors, lauhala weaving, and Hawaiian music, everything here supports Hawaiian artisans and cultural practitioners. The staff is knowledgeable and passionate. Locals come here for meaningful gifts, not the cheap made-in-China souvenirs you find in Waikiki. Regular cultural workshops and events.",kamaaina:null},
  {name:"Surf n Sea",tier:"S",lat:21.594,lng:-158.107,category:"shopping",subcategory:"surf-shop",tagline:"The oldest surf shop in Hawaii (1965) — real surfers sell and rent gear in a colorful Haleiwa waterfront landmark.",area:"North Shore",price:"$$",parking:"Small lot; street parking on Kamehameha Hwy",hours:"Daily 9am-7pm",bestTime:"Morning for the best advice on where to surf that day; check the used board section in back",kidFriendly:true,talkStory:"The oldest surf shop in Hawaii (since 1965), located right on the Haleiwa waterfront in a colorful wooden building. This is not a tourist trap — it's a working surf shop where North Shore locals buy and rent gear. The staff are real surfers who can tell you where the best waves are breaking that day. The used board section in the back has great deals. The building itself is a North Shore landmark worth photographing.",kamaaina:null},
  {name:"Ala Moana Beach Park (Magic Island Reef)",tier:"B",lat:21.287,lng:-157.848,category:"snorkel",subcategory:"reef",tagline:"An urban reef snorkel that Honolulu locals hit on their lunch break.",area:"Honolulu",price:"Free",parking:"Large free lot at Ala Moana Beach Park; metered spots along the peninsula",hours:"Park open 4am–10pm; gates lock at night",bestTime:"Morning before trade winds chop up the surface; summer months for clearest water",kidFriendly:true,talkStory:"Most people come to Ala Moana to sunbathe but the reef along the Magic Island side has surprisingly good snorkeling. Swim out past the sandy bottom and you hit coral with parrotfish, wrasse, and the occasional turtle. The lagoon side is super calm and great for kids just getting comfortable with a mask. The park has showers, restrooms, and is right next to Ala Moana Center if you need food or gear. One of the most convenient snorkel spots on the island.",kamaaina:null},
  {name:"China Walls (Portlock)",tier:"C",lat:21.2616,lng:-157.7068,category:"snorkel",subcategory:"shore-dive",tagline:"A rugged cliff entry for experienced snorkelers rewarded with crystal-clear Portlock water.",area:"Hawaii Kai",price:"Free",parking:"Limited street parking on Hanapepe Loop in Portlock neighborhood; be respectful of residents",hours:"Open 24 hours (daylight recommended)",bestTime:"Summer mornings when south swell is minimal; flat days only — even moderate surf makes entry dangerous",kidFriendly:false,talkStory:"This is NOT for beginners — entry is off a lava rock ledge and there is no beach. On calm days the water clarity is unreal, 60+ feet visibility with green sea turtles, reef sharks, and dense coral. You need to time your entry between sets and be comfortable climbing back up on wet rock. Locals come here to cliff jump too, so keep your head on a swivel. If there is any swell running, skip it.",kamaaina:null},
  {name:"Cockroach Cove (Halona Cove)",tier:"B",lat:21.272,lng:-157.693,category:"snorkel",subcategory:"cove",tagline:"The tiny hidden cove below the Halona Blowhole that most tourists photograph but never swim.",area:"Hawaii Kai",price:"Free",parking:"Free lot at Halona Blowhole Lookout; short steep scramble down to the cove",hours:"Open 24 hours; no lifeguard",bestTime:"Summer (May–Sep) when south shore is calm; ONLY on flat days — waves funnel into this cove dangerously",kidFriendly:false,talkStory:"This tiny cove is the one from the movie From Here to Eternity. The snorkeling is surprisingly good in the protected pocket — clear water, reef fish, and sea urchins tucked into the lava rock. The catch is safety: waves wrap around both sides and can slam you into the rocks with zero warning. Only go on dead-calm days and keep one eye on the ocean at all times. The scramble down is steep and sketchy in slippers — wear proper shoes. If the Blowhole is actively spraying, the cove is too rough to enter.",kamaaina:null},
  {name:"Electric Beach",tier:"A",lat:21.3574,lng:-158.1303,category:"snorkel",subcategory:"turtle",tagline:"A power plant warm-water outflow creates a fish and turtle magnet unlike anything else on Oahu.",area:"Kapolei",price:"Free",parking:"Roadside parking along Farrington Hwy past Ko Olina",hours:"Open 24 hours (no gates or facilities)",bestTime:"Morning for best visibility and calmer current",kidFriendly:false,talkStory:"Not for beginners — strong current near the warm-water outflow pipe. Enter from the sandy area to the right, not over the rocks. Dolphins frequently spotted in the deeper water offshore. Bring your own gear (no rentals nearby). The warm water from the power plant attracts an unusually dense concentration of fish and turtles year-round.",kamaaina:null},
  {name:"Ko Olina Lagoon 3",tier:"A",lat:21.3355,lng:-158.1258,category:"snorkel",subcategory:"beginner",tagline:"Year-round protected snorkeling with turtles — the safest, most accessible snorkel on Oahu.",area:"Ko Olina",price:"Free",parking:"Free public lot for Lagoon 3 (fills by 9am weekends)",hours:"Open 24 hours (public beach access)",bestTime:"Arrive by 8am weekends for parking; weekdays are easy. Morning has best visibility",kidFriendly:true,talkStory:"Bring your own snorkel gear — no rentals nearby and it saves money. Turtles frequent all four lagoons but Lagoon 3 tends to have the most. The man-made rock barriers keep the water calm 365 days a year, making this the safest snorkel for beginners and kids on the entire island. All lagoons are legally public beaches despite the resort setting.",kamaaina:null},
  {name:"Kuilima Cove (Turtle Bay)",tier:"A",lat:21.7015,lng:-157.9908,category:"snorkel",subcategory:"turtle",tagline:"A natural rock barrier makes this a lake — 3-5 turtles virtually guaranteed per session.",area:"North Shore",price:"Free",parking:"Turtle Bay Resort parking — free for beach access (tell the gate you're visiting the public beach)",hours:"Open 24 hours (public beach access through Turtle Bay Resort)",bestTime:"Morning for calmest water and best turtle sightings",kidFriendly:true,talkStory:"The beach is public even though it's at Turtle Bay Resort — don't be intimidated by the resort entrance. The natural rock shelf creates a protected pool that's calm even when the open ocean is rough. Bring your own gear; resort rentals are overpriced. About 1 hr 15 min from Waikiki — combine with a North Shore food truck tour.",kamaaina:null},
  {name:"Laniakea (Turtle Beach)",tier:"B",lat:21.619,lng:-158.0854,category:"snorkel",subcategory:"turtle",tagline:"The most famous turtle viewing spot on the island — green sea turtles haul out right on the sand, daily. Better for watching than snorkeling.",area:"North Shore",price:"Free",parking:"Roadside parking only (~50 spots) — dangerous crossing, use caution",hours:"Open 24 hours (roadside beach, no facilities)",bestTime:"Noon–3pm when turtles are most active hauling out onto the sand",kidFriendly:true,talkStory:"No touching the turtles — it's a federal offense with hefty fines. Volunteers often rope off resting turtles. Best for viewing turtles on the beach, not snorkeling (better snorkel spots elsewhere). The roadside parking requires crossing Kamehameha Hwy — be very careful with kids. A quick 15-min stop on a North Shore loop, not a full-day destination.",kamaaina:null},
  {name:"Maili Point",tier:"C",lat:21.4185,lng:-158.172,category:"snorkel",subcategory:"reef",tagline:"A low-key Waianae reef that delivers when you want to avoid the tourist trail entirely.",area:"Waianae",price:"Free",parking:"Street parking along Farrington Hwy near Maili Beach Park",hours:"Open 24 hours",bestTime:"Summer mornings; only snorkel when the ocean is calm — exposed reef with no protection",kidFriendly:false,talkStory:"Maili Point is a rocky outcrop with a reef that gets overlooked because tourists rarely venture this far down the Waianae Coast. On calm summer days the water along the point is clear with decent coral coverage and reef fish. Entry is rocky so wear reef shoes and pick your spot carefully. This is a local beach — respect the community, do not blast music, and clean up after yourself. Not worth the drive as a standalone trip but solid if you are already in the area.",kamaaina:null},
  {name:"Makua Beach (Pray for Sex Beach)",tier:"C",lat:21.527,lng:-158.237,category:"snorkel",subcategory:"shore-dive",tagline:"The end of the road on the Waianae Coast — remote, raw, and full of spinner dolphins.",area:"Waianae",price:"Free",parking:"Dirt pulloff along Farrington Hwy; limited space",hours:"Open during daylight; road may close for military exercises (check Makua Beach access schedule)",bestTime:"Summer (May–Sep) for calm water; early morning for spinner dolphin pods in the bay",kidFriendly:false,talkStory:"Makua is one of the most remote beaches you can drive to on Oahu. The snorkeling is best along the rocky edges of the bay where you will find healthy coral and less boat traffic. Spinner dolphins frequently come into the bay in the mornings — stay 50 yards back as federal law protects them. The beach is sometimes closed for live-fire military training at Makua Valley so check access before driving all the way out. No facilities, no lifeguard, no shade — bring everything you need.",kamaaina:null},
  {name:"Pupukea Tide Pools",tier:"A",lat:21.654,lng:-158.0635,category:"snorkel",subcategory:"reef",tagline:"Sheltered tide pools perfect for a mellow snorkel right next to Shark's Cove.",area:"North Shore",price:"Free",parking:"Free lot across from Pupukea Beach Park (shared with Shark's Cove); fills by 9am in summer",hours:"Open 24 hours (Pupukea Beach Park)",bestTime:"Summer only (May–Sep); low tide reveals the best pools; mornings are calmest",kidFriendly:true,talkStory:"These tide pools sit just south of Shark's Cove and are way more approachable for families and beginners. The shallow pools trap fish, sea cucumbers, and small eels when the tide drops. Wear reef shoes — the lava rock is sharp and slippery. In summer the outer pools connect to the open ocean and you can snorkel a wider area. Winter waves completely wash over this area so it is strictly a summer activity.",kamaaina:null},
  {name:"Sans Souci Beach (Queen's Beach)",tier:"B",lat:21.2588,lng:-157.8225,category:"snorkel",subcategory:"reef",tagline:"Waikiki's secret reef — locals snorkel here while tourists stay on the sand a mile west.",area:"Waikiki",price:"Free",parking:"Free street parking on Kalakaua Ave or paid lot at Kapiolani Park; metered spots fill early",hours:"Open 24 hours",bestTime:"Early morning for calmest water and best visibility; year-round spot but summer is ideal",kidFriendly:true,talkStory:"This is the beach at the foot of the Natatorium — where Waikiki locals actually swim. The reef starts about 30 yards out and runs parallel to shore with solid coral and plenty of reef fish. Entry is sandy and gradual, making it one of the easiest snorkel entries in town. The sea wall of the old Natatorium creates a calm channel on the right side. Watch for sea urchins in the shallower reef sections.",kamaaina:null},
  {name:"Three Tables",tier:"S",lat:21.6468,lng:-158.0621,category:"snorkel",subcategory:"beginner",tagline:"The easiest reef entry on the North Shore — walk right in from sand and float over a turtle-dotted reef.",area:"North Shore",price:"Free",parking:"Shares free lot with Shark's Cove across the street",hours:"Open 24 hours (no gates; Pupukea Beach Park)",bestTime:"Summer (May–Sep) for calm conditions; morning for best visibility",kidFriendly:true,talkStory:"Named for three flat reef sections that poke above the water like tables. Much easier entry than Shark's Cove next door — sandy bottom instead of rocks. A better choice for less experienced snorkelers. Turtles are common over the reef. Summer only (dangerous in winter). Bring your own gear or rent in Haleiwa.",kamaaina:null},
  {name:"Yokohama Bay (Keawaula Beach)",tier:"B",lat:21.553,lng:-158.247,category:"snorkel",subcategory:"shore-dive",tagline:"The very last beach before the road ends — pristine water and almost nobody around.",area:"Waianae",price:"Free",parking:"Free lot at Kaena Point State Park (Keawaula section); lot closes at 7pm",hours:"Gate opens at sunrise, closes at 7pm",bestTime:"Summer only (May–Sep); early morning for flat conditions and spinner dolphins",kidFriendly:false,talkStory:"Yokohama is the last sandy beach before the road ends at Kaena Point. In summer the water is crystal clear with healthy reef on the north end of the bay. This is a real wilderness beach — no food, no shops, no lifeguard. Spinner dolphins come into the bay in the mornings and monk seals occasionally haul out on the sand (stay 50 feet back, it is federal law). Strong currents can develop so stay close to shore. Combine with a hike to Kaena Point to see nesting albatross. Winter surf here is massive and deadly — summer only.",kamaaina:null},
];
